function addPatchItem() {
    const list = document.getElementById('pnItemsList');
    if (!list) return;
    const row = document.createElement('div');
    row.className = 'pn-item-row';
    row.innerHTML = `
        <div class="pn-item-row-top">
            <select class="form-input-lg pn-item-category">
                <option value="">— Select a category —</option>
                <option value="New Features">✨ New Features</option>
                <option value="Improvements">🚀 Improvements</option>
                <option value="Bug Fixes">🔧 Bug Fixes</option>
            </select>
            <button class="pn-remove-btn" onclick="removePatchItem(this)" title="Remove">✖</button>
        </div>
        <textarea class="form-input-lg pn-textarea pn-item-summary" placeholder="Describe what changed... (start lines with - for bullet points)"></textarea>`;
    list.appendChild(row);
}

function removePatchItem(btn) {
    const list = document.getElementById('pnItemsList');
    if (list && list.querySelectorAll('.pn-item-row').length > 1) btn.closest('.pn-item-row').remove();
}

async function savePatchEntry() {
    const title   = document.getElementById('pnEntryTitle').value.trim();
    const dateRaw = document.getElementById('pnEntryDate').value;
    const status  = document.getElementById('pnEntrySaveStatus');
    const btn     = document.getElementById('pnSaveEntryBtn');

    if (!title || !dateRaw) { status.textContent = 'Version title and date are required.'; status.className = 'pn-save-status pn-save-error'; return; }

    const rows = document.querySelectorAll('.pn-item-row');
    const items = [];
    let allValid = true;
    rows.forEach(row => {
        const category = row.querySelector('.pn-item-category').value;
        const summary  = row.querySelector('.pn-item-summary').value.trim();
        if (!category || !summary) { allValid = false; return; }
        items.push({ category, summary });
    });

    if (!allValid || !items.length) { status.textContent = 'Each item needs a category and summary.'; status.className = 'pn-save-status pn-save-error'; return; }

    const [y, m, d] = dateRaw.split('-');
    const date = `${m}/${d}/${y}`;

    btn.disabled = true;
    status.textContent = 'Saving...';
    status.className = 'pn-save-status';

    try {
        await postWrite(PATCH_NOTES_URL, { action: 'addEntries', title, date, items });
        status.textContent = `${items.length} item${items.length !== 1 ? 's' : ''} saved!`;
        status.className = 'pn-save-status pn-save-ok';
        document.getElementById('pnEntryTitle').value = '';
        document.getElementById('pnEntryDate').value  = '';
        document.getElementById('pnItemsList').innerHTML = '';
        addPatchItem();
    } catch (e) {
        status.textContent = 'Save failed.';
        status.className = 'pn-save-status pn-save-error';
    }
    btn.disabled = false;
    setTimeout(() => { status.textContent = ''; }, 4000);
}

// --- PATCH NOTES EDITOR ---
async function loadPatchNotesEditor() {
    const list = document.getElementById('pnEditList');
    if (!list) return;
    list.innerHTML = '<div class="pn-loading">Loading...</div>';
    try {
        const response = await fetch(`${PATCH_NOTES_URL}?v=${Date.now()}`);
        const data = await response.json();
        renderPatchNotesEditor(data);
    } catch (e) {
        list.innerHTML = '<div class="pn-loading">Failed to load.</div>';
    }
}

function renderPatchNotesEditor(data) {
    const list = document.getElementById('pnEditList');
    if (!list) return;
    const { entries } = data;
    if (!entries || !entries.length) { list.innerHTML = '<div class="pn-loading">No patch notes to edit.</div>'; return; }

    const sorted = buildPatchGroups(entries);
    const catBadge = { 'New Features': 'pn-badge-new', 'Improvements': 'pn-badge-improved', 'Bug Fixes': 'pn-badge-fixed' };

    list.innerHTML = sorted.map((group, gi) => {
        const vLabel = group.title;
        const safeTitle = group.title.replace(/"/g, '&quot;');
        return `
            <div class="pne-group" id="pne-group-${gi}" data-title="${safeTitle}" data-date="${group.date}">
                <div class="pne-group-header">
                    <div class="pne-group-view">
                        <span class="pne-group-title">${vLabel}</span>
                        <span class="pne-group-date">${formatPatchDate(group.date)}</span>
                        <button class="pne-btn pne-group-edit-btn" onclick="startEditPatchGroup(${gi})">Edit Version</button>
                    </div>
                </div>
                ${group.items.map(item => `
                    <div class="pne-item" id="pne-item-${item.id}"
                         data-id="${item.id}"
                         data-category="${item.category}"
                         data-summary="${item.summary.replace(/"/g, '&quot;').replace(/\n/g, '&#10;')}"
                         data-title="${group.title}"
                         data-date="${group.date}">
                        <div class="pne-item-view">
                            <span class="pn-badge ${catBadge[item.category] || ''}">${item.category}</span>
                            <span class="pne-item-summary">${item.summary.replace(/\n/g, ' ')}</span>
                            <div class="pne-item-actions">
                                <button class="pne-btn" onclick="startEditPatchItem('${item.id}')">Edit</button>
                                <button class="pne-btn pne-btn-delete" onclick="promptDeletePatchItem('${item.id}')">Delete</button>
                            </div>
                        </div>
                    </div>`).join('')}
            </div>`;
    }).join('');
}

// --- Edit a whole version's title + date (applies to all its items) ---
function startEditPatchGroup(gi) {
    const el = document.getElementById(`pne-group-${gi}`);
    if (!el) return;
    const title = el.dataset.title || '';
    const date  = el.dataset.date  || '';
    const header = el.querySelector('.pne-group-header');
    const view   = el.querySelector('.pne-group-view');
    if (view) view.style.display = 'none';

    const editDiv = document.createElement('div');
    editDiv.className = 'pne-group-edit';
    editDiv.innerHTML = `
        <input type="text" class="form-input-lg pne-edit-gtitle" value="${title.replace(/"/g, '&quot;')}" placeholder="Version title">
        <input type="date" class="form-input-lg pne-edit-gdate" value="${date}">
        <div class="pne-edit-actions">
            <button class="btn-primary" onclick="saveEditPatchGroup(${gi})">Save</button>
            <button class="pne-btn" onclick="cancelEditPatchGroup(${gi})">Cancel</button>
        </div>`;
    if (header) header.appendChild(editDiv);
}

function cancelEditPatchGroup(gi) {
    const el = document.getElementById(`pne-group-${gi}`);
    if (!el) return;
    const view    = el.querySelector('.pne-group-view');
    const editDiv = el.querySelector('.pne-group-edit');
    if (view) view.style.display = '';
    if (editDiv) editDiv.remove();
}

async function saveEditPatchGroup(gi) {
    const el = document.getElementById(`pne-group-${gi}`);
    if (!el) return;
    const oldTitle = el.dataset.title;
    const oldDate  = el.dataset.date;
    const title    = el.querySelector('.pne-edit-gtitle').value.trim();
    const dateRaw  = el.querySelector('.pne-edit-gdate').value; // YYYY-MM-DD
    if (!title || !dateRaw) return;

    const saveBtn = el.querySelector('.btn-primary');
    if (saveBtn) { saveBtn.textContent = 'Saving...'; saveBtn.disabled = true; }

    try {
        await postWrite(PATCH_NOTES_URL, { action: 'editGroup', oldTitle, oldDate, title, date: dateRaw });
        loadPatchNotesEditor();
    } catch (e) {
        if (saveBtn) { saveBtn.textContent = 'Save'; saveBtn.disabled = false; }
        alert('Failed to save changes: ' + (e.message || e));
    }
}

function startEditPatchItem(id) {
    const el = document.getElementById(`pne-item-${id}`);
    if (!el) return;
    const { category, summary } = el.dataset;
    const decodedSummary = summary.replace(/&#10;/g, '\n');
    const viewDiv = el.querySelector('.pne-item-view');
    if (viewDiv) viewDiv.style.display = 'none';

    const editDiv = document.createElement('div');
    editDiv.className = 'pne-item-edit';
    editDiv.innerHTML = `
        <select class="form-input-lg pne-edit-cat">
            <option value="New Features" ${category === 'New Features' ? 'selected' : ''}>✨ New Features</option>
            <option value="Improvements" ${category === 'Improvements' ? 'selected' : ''}>🚀 Improvements</option>
            <option value="Bug Fixes"    ${category === 'Bug Fixes'    ? 'selected' : ''}>🔧 Bug Fixes</option>
        </select>
        <textarea class="form-input-lg pn-textarea pne-edit-sum">${decodedSummary}</textarea>
        <div class="pne-edit-actions">
            <button class="btn-primary" onclick="saveEditPatchItem('${id}')">Save Changes</button>
            <button class="pne-btn" onclick="cancelEditPatchItem('${id}')">Cancel</button>
        </div>`;
    el.appendChild(editDiv);
}

function cancelEditPatchItem(id) {
    const el = document.getElementById(`pne-item-${id}`);
    if (!el) return;
    const viewDiv = el.querySelector('.pne-item-view');
    const editDiv = el.querySelector('.pne-item-edit');
    if (viewDiv) viewDiv.style.display = '';
    if (editDiv) editDiv.remove();
}

async function saveEditPatchItem(id) {
    const el       = document.getElementById(`pne-item-${id}`);
    if (!el) return;
    const category = el.querySelector('.pne-edit-cat').value;
    const summary  = el.querySelector('.pne-edit-sum').value.trim();
    const { title, date } = el.dataset;
    if (!category || !summary) return;

    const saveBtn = el.querySelector('.btn-primary');
    if (saveBtn) saveBtn.textContent = 'Saving...';
    if (saveBtn) saveBtn.disabled = true;

    try {
        await postWrite(PATCH_NOTES_URL, { action: 'editEntry', id, title, date, category, summary });
        loadPatchNotesEditor();
    } catch (e) {
        if (saveBtn) { saveBtn.textContent = 'Save Changes'; saveBtn.disabled = false; }
        alert('Failed to save changes: ' + (e.message || e));
    }
}

function promptDeletePatchItem(id) {
    const el = document.getElementById(`pne-item-${id}`);
    if (!el) return;
    const actions = el.querySelector('.pne-item-actions');
    if (!actions) return;
    actions.innerHTML = `
        <span class="pne-confirm-label">Delete this item?</span>
        <button class="pne-btn pne-btn-confirm-delete" onclick="confirmDeletePatchItem('${id}')">Yes, Delete</button>
        <button class="pne-btn" onclick="loadPatchNotesEditor()">Cancel</button>`;
}

async function confirmDeletePatchItem(id) {
    const btn = document.querySelector(`#pne-item-${id} .pne-btn-confirm-delete`);
    if (btn) { btn.textContent = 'Deleting...'; btn.disabled = true; }
    try {
        await postWrite(PATCH_NOTES_URL, { action: 'deleteEntry', id });
    } catch (e) {
        alert('Delete failed: ' + (e.message || e));
    }
    loadPatchNotesEditor();
}

// ============================================================
// BOX ORDER TOOL
// ============================================================

const BOX_STORE_NAMES = {
    'OVL': 'Overland Park',
    'LEE': "Lee's Summit",
    'WSP': 'Westport',
    'MPL': 'Maplewood',
    'BAL': 'Ballwin'
};

// Maps each store to the supplier email its box orders should be sent to.
const BOX_ORDER_STORE_EMAILS = {
    'OVL': 'doug@crosscorpusa.com',
    'LEE': 'doug@crosscorpusa.com',
    'WSP': 'doug@crosscorpusa.com',
    'MPL': 'jordan@cleancarton.com',
    'BAL': 'jordan@cleancarton.com'
};

// Store markets — used by the DM/CEO "Manage Items" tab to scope new catalog items.
// KC = Kansas City metro, STL = St. Louis metro. Empty = all stores.
const BOX_MARKET_STORES = { '': '', 'KC': 'OVL,LEE,WSP', 'STL': 'MPL,BAL' };
function _boxStoresToMarket(stores) {
    const s = (stores || '').replace(/\s+/g, '').toUpperCase();
    if (!s) return 'All';
    if (s === 'OVL,LEE,WSP') return 'KC';
    if (s === 'MPL,BAL') return 'STL';
    return s; // any custom combination
}

function _boxOrderGetStoreCode() {
    const selectorEl = document.getElementById('boxOrderStoreSelector');
    const corpVisible = selectorEl && selectorEl.style.display !== 'none';
    const sel = document.getElementById('boxOrderStoreSelect');
    return (corpVisible && sel && sel.value) ? sel.value : (sessionStorage.getItem('speeksUserStore') || '');
}

function _boxOrderGetStore() {
    const code = _boxOrderGetStoreCode();
    return BOX_STORE_NAMES[code] || code || 'Store';
}

// Resolves the destination email(s) from the selected store: the DB-managed
// list first (Email Recipients tool, key box_order_<STORE>; multiple addresses
// join with ';' — the Outlook-safe mailto separator), then the hardcoded
// per-store fallback, the configured primary email, and finally a placeholder.
function _boxOrderGetEmail() {
    const code = _boxOrderGetStoreCode();
    const dbList = _recipientsFor(`box_order_${code}`, []);
    if (dbList.length) return dbList.join(';');
    return BOX_ORDER_STORE_EMAILS[code] || _boxOrderEmails.primary || 'orders@placeholder.com';
}

let _boxOrderEmails = { primary: '', secondary: '' };
// Full box-order catalog (all store variants), kept so the vendor email can resolve
// the correct per-store spec for products that differ by store (e.g. Packing Paper).
let _boxOrderAllItems = [];

// Match a selected line back to a catalog item for the chosen store, so per-store
// products (e.g. Packing Paper) use the right spec + unit. Prefers a store-specific
// variant of the same product; falls back to any variant with that name.
function _resolveItemVariant(o) {
    if (!Array.isArray(_boxOrderAllItems)) return null;
    const code = (_boxOrderGetStoreCode() || '').toUpperCase();
    if (code) {
        const m = _boxOrderAllItems.find(it => it.name === o.name && it.category === o.category &&
            (it.stores || '').split(',').map(s => s.trim().toUpperCase()).includes(code));
        if (m) return m;
    }
    return _boxOrderAllItems.find(it => it.name === o.name && it.category === o.category) || null;
}

// Naive pluralizer for unit words: Box→Boxes, Roll→Rolls, Bundle→Bundles, Bag→Bags.
function _pluralizeUnit(w) {
    if (!w) return w;
    return /(?:s|x|z|ch|sh)$/i.test(w) ? w + 'es' : w + 's';
}

async function toggleBoxOrder() {
    closeAllModals();
    const modal = document.getElementById('boxOrderModal');
    if (!modal) return;
    _fetchEmailLists(); // warm the recipient cache for the supplier email
    // DM/CEO get a "Manage Items" tab to edit the catalog; managers just see the order flow.
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    const isCorpRole = role === 'ceo' || role === 'district manager';
    const tabs = document.getElementById('boxOrderTabs');
    if (tabs) tabs.style.display = isCorpRole ? 'flex' : 'none';
    boxOrderSwitchTab('order'); // reset to the order flow (page 1)
    const searchEl = document.getElementById('boxOrderSearch');
    if (searchEl) searchEl.value = '';
    modal.classList.add('show');
    lockAndBlurScreen();
    await _loadBoxOrderData();
}

// Switch between the order wizard and the DM/CEO "Manage Items" catalog editor.
function boxOrderSwitchTab(tab) {
    const isManage = tab === 'manage';
    const set = (id, disp) => { const el = document.getElementById(id); if (el) el.style.display = disp; };
    set('boxOrderManagePage', isManage ? '' : 'none');
    set('boxOrderManageFooter', isManage ? '' : 'none');
    if (isManage) {
        ['boxOrderPage1', 'boxOrderPage2', 'boxOrderFooter1', 'boxOrderFooter2'].forEach(id => set(id, 'none'));
        renderBoxAdminList();
    } else {
        set('boxOrderPage1', '');
        set('boxOrderFooter1', '');
        set('boxOrderPage2', 'none');
        set('boxOrderFooter2', 'none');
    }
    const to = document.getElementById('boxOrderTabOrder');
    const tm = document.getElementById('boxOrderTabManage');
    if (to) to.classList.toggle('active', !isManage);
    if (tm) tm.classList.toggle('active', isManage);
}

// Render the current catalog in the Manage Items tab, grouped by section, each with
// a remove button. Reads _boxOrderAllItems (the full, un-collapsed catalog).
function renderBoxAdminList() {
    const el = document.getElementById('boxAdminItemsList');
    if (!el) return;
    const items = Array.isArray(_boxOrderAllItems) ? _boxOrderAllItems : [];
    if (!items.length) {
        el.innerHTML = '<div style="color:#a0aab2;font-size:13px;padding:6px 0;">No items yet.</div>';
        return;
    }
    const cats = ['Small Box', 'Medium Box', 'Large Box', 'Shipping Supplies', 'White Storage Box', 'Bubble Mailer'];
    const label = {
        'Small Box': 'Small Boxes', 'Medium Box': 'Medium Boxes', 'Large Box': 'Large Boxes',
        'Shipping Supplies': 'Shipping Supplies', 'White Storage Box': 'White Storage Boxes', 'Bubble Mailer': 'Bubble Mailers'
    };
    let html = '';
    cats.forEach(cat => {
        const group = items.filter(i => i.category === cat);
        if (!group.length) return;
        html += `<div style="font-weight:800;font-size:12px;color:#64748b;margin:12px 0 6px;">${label[cat]}</div>`;
        group.forEach(it => {
            const meta = [
                _boxStoresToMarket(it.stores),
                (it.bundle_size > 1) ? `${it.bundle_size}/bundle` : '1/unit',
                it.unit_label ? _pluralizeUnit(it.unit_label) : '',
                it.order_name ? `“${escapeHtml(it.order_name)}”` : ''
            ].filter(Boolean).join(' · ');
            html += `<div class="box-admin-item">
                <div style="min-width:0;">
                    <div style="font-weight:800;color:var(--slate-charcoal);font-size:13px;">${escapeHtml(it.name)}</div>
                    <div style="font-size:11px;color:#94a3b8;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${meta}</div>
                </div>
                <button class="bai-del" title="Remove item" onclick="boxAdminDeleteItem('${it.id}', this)">🗑</button>
            </div>`;
        });
    });
    el.innerHTML = html;
}

async function boxAdminAddItem(btn) {
    const name = document.getElementById('boxAdminName')?.value.trim();
    const category = document.getElementById('boxAdminCategory')?.value;
    const market = document.getElementById('boxAdminMarket')?.value || '';
    const bundle = parseInt(document.getElementById('boxAdminBundle')?.value) || 1;
    const unit = document.getElementById('boxAdminUnit')?.value || 'Bundle';
    const orderName = document.getElementById('boxAdminOrderName')?.value.trim();
    if (!name) { alert('Enter a title (what managers see).'); return; }
    if (!orderName) { alert('Enter the email name — the full spec the vendor needs.'); return; }
    const stores = BOX_MARKET_STORES[market] || '';
    if (btn) { btn.disabled = true; btn.textContent = 'Adding…'; }
    try {
        const res = await fetch(BOX_ADMIN_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'add_item', name, category, order_name: orderName, unit_label: unit, bundle_size: bundle, stores }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        // Clear name + spec for the next entry; keep section/market/unit for quick repeats.
        ['boxAdminName', 'boxAdminOrderName'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
        const b = document.getElementById('boxAdminBundle'); if (b) b.value = '1';
        await _loadBoxOrderData();   // refresh the catalog + _boxOrderAllItems
        renderBoxAdminList();
    } catch (e) {
        alert('Could not add the item: ' + (e.message || e));
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = '+ Add item'; }
    }
}

async function boxAdminDeleteItem(id, btn) {
    if (!confirm('Remove this item from the Box Order catalog?')) return;
    if (btn) btn.disabled = true;
    try {
        const res = await fetch(BOX_ADMIN_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'delete_item', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        await _loadBoxOrderData();
        renderBoxAdminList();
    } catch (e) {
        alert('Could not remove: ' + (e.message || e));
        if (btn) btn.disabled = false;
    }
}

async function _loadBoxOrderData() {
    const container = document.getElementById('boxOrderItemsContainer');
    if (!container) return;
    container.innerHTML = '<div style="color:#a0aab2;font-size:13px;padding:12px 0;">Loading items...</div>';
    const h = { 'apikey': _SUPABASE_ANON_KEY, 'Authorization': `Bearer ${_SUPABASE_ANON_KEY}` };
    try {
        const [iRes, cRes] = await Promise.all([
            fetch(BOX_ITEMS_URL, { headers: h }),
            fetch(BOX_CONFIG_URL, { headers: h })
        ]);
        const items  = await iRes.json();
        const config = await cRes.json();
        if (Array.isArray(config)) {
            config.forEach(c => {
                if (c.key === 'email_primary')   _boxOrderEmails.primary   = c.value;
                if (c.key === 'email_secondary')  _boxOrderEmails.secondary = c.value;
            });
        }
        _renderBoxOrderItems(container, Array.isArray(items) ? items : []);
    } catch (e) {
        container.innerHTML = '<div style="color:#ef4444;font-size:13px;">Failed to load items. Please try again.</div>';
    }
}

function _renderBoxOrderItems(container, items) {
    // Keep the full catalog (every store variant) so the email can resolve the right
    // per-store spec later — even for rows corp collapses into one line.
    _boxOrderAllItems = Array.isArray(items) ? items.slice() : [];
    // Some items are store-specific (e.g. MPL/BAL use a different supplier than the
    // other stores). Show an item only if it has no store restriction, or the
    // current store is in its list. Corp roles (CEO/DM) choose the store on the
    // next page, so they see every item here.
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    const isCorp = role === 'ceo' || role === 'district manager';
    const storeCode = (sessionStorage.getItem('speeksUserStore') || '').toUpperCase();
    items = (items || []).filter(it => {
        const s = (it.stores || '').trim();
        if (!s) return true;        // no restriction → all stores
        if (isCorp) return true;    // corp picks the store later → show it
        return s.split(',').map(x => x.trim().toUpperCase()).includes(storeCode);
    });
    // Collapse per-store variants that share a name (e.g. "Packing Paper" differs by
    // supplier) into ONE row. Corp then sees a single line and the vendor email
    // resolves the correct spec from the store they pick on the next page. Managers
    // only ever have their own store's variant here, so this is a no-op for them.
    const seenVariant = new Set();
    items = items.filter(it => {
        if (!(it.stores || '').trim()) return true;   // non-scoped items never collapse
        const k = `${it.category}|${it.name}`;
        if (seenVariant.has(k)) return false;
        seenVariant.add(k);
        return true;
    });
    const BUCKETS = [
        { key: 'Small Box',        label: 'Small Boxes' },
        { key: 'Medium Box',       label: 'Medium Boxes' },
        { key: 'Large Box',        label: 'Large Boxes' },
        { key: 'Shipping Supplies',  label: 'Shipping Supplies' },
        { key: 'White Storage Box', label: 'White Storage Boxes' },
        { key: 'Bubble Mailer',     label: 'Bubble Mailers' },
    ];
    let html = '';

    const buildSection = (label, group, includeHdWarning) => {
        let itemsHtml = '';
        group.forEach(item => {
            itemsHtml += _buildBoxRow(item);
            if (includeHdWarning && item.is_heavy_duty) {
                itemsHtml += '<div class="box-order-warning">⚠ HD boxes are significantly more expensive per unit. Only order what is truly needed.</div>';
            }
        });
        return `<div class="box-order-section">
  <div class="box-order-section-label box-order-collapsible" onclick="boxOrderToggleSection(this)">
    <span>${label}</span><span class="box-order-chevron" style="transform:rotate(-90deg)">▾</span>
  </div>
  <div class="box-order-section-items" style="display:none">${itemsHtml}</div>
</div>`;
    };

    BUCKETS.forEach(({ key, label }) => {
        const group = items.filter(i => i.category === key);
        if (group.length) html += buildSection(label, group, key === 'Large Box');
    });

    container.innerHTML = html || '<div style="color:#a0aab2;font-size:13px;">No items found.</div>';
    // Stable ids so the live receipt can point its "remove" button back at a row.
    container.querySelectorAll('.box-order-row').forEach((r, i) => { r.id = 'box-row-' + i; });
    boxOrderRenderReceipt(); // reset to empty on a fresh load
}

// Live "receipt" of the current selection, pinned under the item list. Rebuilt from
// the rows' current quantities on every change so it always matches what's selected.
function boxOrderRenderReceipt() {
    const panel = document.getElementById('boxOrderReceipt');
    if (!panel) return;
    const rows = document.querySelectorAll('#boxOrderItemsContainer .box-order-row');
    const picked = [];
    rows.forEach(row => {
        const qty = parseInt(row.querySelector('.box-stepper-qty')?.textContent) || 0;
        if (qty > 0) picked.push({ id: row.id, name: row.dataset.name || row.dataset.item || '', qty });
    });
    if (!picked.length) { panel.style.display = 'none'; panel.innerHTML = ''; return; }
    const lines = picked.map(p => `
        <div class="box-receipt-line">
            <span class="box-receipt-name">${escapeHtml(p.name)}</span>
            <span class="box-receipt-qty">${p.qty}</span>
            <button class="box-receipt-x" title="Remove" onclick="boxReceiptRemove('${p.id}')">×</button>
        </div>`).join('');
    panel.innerHTML =
        `<div class="box-receipt-head">🧾 Your order · ${picked.length} item${picked.length === 1 ? '' : 's'}</div>` +
        `<div class="box-receipt-list">${lines}</div>`;
    panel.style.display = '';
}

// Remove a line from the receipt by zeroing that row's stepper.
function boxReceiptRemove(rowId) {
    const row = document.getElementById(rowId);
    if (row) {
        const qtyEl = row.querySelector('.box-stepper-qty');
        if (qtyEl) { qtyEl.textContent = '0'; qtyEl.classList.remove('box-stepper-active'); }
        row.classList.remove('box-row-selected');
    }
    boxOrderRenderReceipt();
}

// Live search over the box-order items. Matches name / category / dimensions
// (× and x treated the same). Matching sections expand; the rest collapse.
// Clearing the box restores the default collapsed accordion.
function filterBoxOrderItems() {
    const input = document.getElementById('boxOrderSearch');
    const container = document.getElementById('boxOrderItemsContainer');
    if (!input || !container) return;
    const norm = s => (s || '').toLowerCase().replace(/×/g, 'x');
    const q = norm(input.value.trim());
    container.querySelectorAll('.box-order-section').forEach(section => {
        const itemsEl = section.querySelector('.box-order-section-items');
        const chevron = section.querySelector('.box-order-chevron');
        let anyMatch = false;
        section.querySelectorAll('.box-order-row').forEach(row => {
            if (!q) { row.style.display = ''; return; }
            const hay = norm((row.dataset.name || '') + ' ' + (row.dataset.category || '') + ' ' +
                (row.querySelector('.box-order-subtype')?.textContent || ''));
            const match = hay.includes(q);
            row.style.display = match ? '' : 'none';
            if (match) anyMatch = true;
        });
        // Heavy-duty warnings are advisory — hide them while searching.
        section.querySelectorAll('.box-order-warning').forEach(w => { w.style.display = q ? 'none' : ''; });
        if (!q) {
            section.style.display = '';
            if (itemsEl) itemsEl.style.display = 'none';
            if (chevron) chevron.style.transform = 'rotate(-90deg)';
        } else {
            section.style.display = anyMatch ? '' : 'none';
            if (itemsEl) itemsEl.style.display = anyMatch ? '' : 'none';
            if (chevron) chevron.style.transform = anyMatch ? '' : 'rotate(-90deg)';
        }
    });
}

function boxOrderToggleSection(labelEl) {
    const section = labelEl.closest('.box-order-section');
    const itemsEl = section.querySelector('.box-order-section-items');
    const chevron = labelEl.querySelector('.box-order-chevron');
    const willOpen = itemsEl.style.display === 'none';
    // Accordion: close every section first, then open the clicked one (if it was
    // closed) — so only one section is ever open at a time.
    const container = section.parentElement;
    if (container) {
        container.querySelectorAll('.box-order-section').forEach(s => {
            const it = s.querySelector('.box-order-section-items');
            const ch = s.querySelector('.box-order-chevron');
            if (it) it.style.display = 'none';
            if (ch) ch.style.transform = 'rotate(-90deg)';
        });
    }
    if (willOpen) {
        itemsEl.style.display = '';
        chevron.style.transform = '';
    }
}

function _buildBoxRow(item) {
    const displayCat = item.category.replace(/^(?:Small |Medium |Large |Common |Rare |Very Rare )/, '');
    const label      = escapeHtml(`${item.name} ${displayCat}`);
    const nameHtml   = escapeHtml(item.name);
    const catHtml    = escapeHtml(item.category || '');
    const bundleSize = Math.max(1, parseInt(item.bundle_size) || 1);
    // The stepper counts individual units; clicking +/- jumps by one bundle so a
    // manager always sees the true unit count. Surface the bundle size so it's
    // clear why the number jumps the way it does.
    const subParts   = [item.dimensions, displayCat].filter(Boolean);
    if (bundleSize > 1) subParts.push(`${bundleSize}/bundle`);
    const subHtml    = escapeHtml(subParts.join(' · '));
    const orderNameHtml = escapeHtml(item.order_name || '');
    const unitLabelHtml = escapeHtml(item.unit_label || '');
    return `<div class="box-order-row" data-item="${label}" data-name="${nameHtml}" data-order-name="${orderNameHtml}" data-unit-label="${unitLabelHtml}" data-category="${catHtml}" data-bundle="${bundleSize}">
  <div class="box-order-info">
    <span class="box-order-name">${nameHtml}</span>
    <span class="box-order-subtype">${subHtml}</span>
  </div>
  <div class="box-order-stepper">
    <button class="box-stepper-btn" onclick="boxStepperChange(this,-1)">−</button>
    <span class="box-stepper-qty">0</span>
    <button class="box-stepper-btn" onclick="boxStepperChange(this,1)">+</button>
  </div>
</div>`;
}

function boxStepperChange(btn, delta) {
    const qtyEl  = btn.closest('.box-order-stepper').querySelector('.box-stepper-qty');
    const row    = btn.closest('.box-order-row');
    // Step by the bundle size so the displayed quantity is the actual unit count.
    const bundle = Math.max(1, parseInt(row.dataset.bundle) || 1);
    const next   = Math.max(0, (parseInt(qtyEl.textContent) || 0) + delta * bundle);
    qtyEl.textContent = next;
    qtyEl.classList.toggle('box-stepper-active', next > 0);
    row.classList.toggle('box-row-selected', next > 0);
    boxOrderRenderReceipt(); // keep the live receipt in sync
}

let _boxOrderSelected = [];

function boxOrderNextPage() {
    const rows = document.querySelectorAll('#boxOrderItemsContainer .box-order-row');
    _boxOrderSelected = [];
    rows.forEach(row => {
        const qty = parseInt(row.querySelector('.box-stepper-qty')?.textContent) || 0;
        const bundle = Math.max(1, parseInt(row.dataset.bundle) || 1);
        if (qty > 0) _boxOrderSelected.push({ item: row.dataset.item, name: row.dataset.name, orderName: row.dataset.orderName, unitLabel: row.dataset.unitLabel, category: row.dataset.category, qty, bundle });
    });
    if (!_boxOrderSelected.length) {
        alert('Please add at least one item before continuing.');
        return;
    }
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    const isCorpRole = role === 'ceo' || role === 'district manager';
    const selectorEl = document.getElementById('boxOrderStoreSelector');
    if (selectorEl) {
        selectorEl.style.display = isCorpRole ? '' : 'none';
        const sel = document.getElementById('boxOrderStoreSelect');
        // Corp picks a store here; default it to OVL so the preview is populated
        // right away (they can switch stores from the dropdown).
        if (sel) sel.value = isCorpRole ? 'OVL' : '';
    }
    const notesEl = document.getElementById('boxOrderNotes');
    if (notesEl) notesEl.value = '';
    boxOrderUpdatePreview();
    document.getElementById('boxOrderPage1').style.display    = 'none';
    document.getElementById('boxOrderFooter1').style.display  = 'none';
    document.getElementById('boxOrderPage2').style.display    = '';
    document.getElementById('boxOrderFooter2').style.display  = '';
}

function boxOrderBackPage() {
    document.getElementById('boxOrderPage2').style.display    = 'none';
    document.getElementById('boxOrderFooter2').style.display  = 'none';
    document.getElementById('boxOrderPage1').style.display    = '';
    document.getElementById('boxOrderFooter1').style.display  = '';
    boxOrderRenderReceipt(); // selection is preserved in the rows — reflect it again
}

// Format one selected item for the order: drop the word "Box" from box sizes
// and "Shipping Supplies" from supplies, and pick the unit per item type
// (Peanuts → Bag(s), Gum Tape → Box(es), everything else → Bundle(s)).
// The stepper tracks individual units; convert back to bundle count here so the
// vendor email keeps reading in bundles (qty ÷ bundle size).
function _boxOrderLine(o) {
    const displayCat = (o.category || '')
        .replace(/^(?:Small |Medium |Large |Common |Rare |Very Rare )/, '')
        .replace(/\bShipping Supplies\b/i, '')
        .replace(/\bBox(?:es)?\b/i, '')
        .replace(/\s+/g, ' ').trim();
    // A store-facing UI name can differ from the full spec the vendor needs on the
    // order — order_name (when set) is what goes on the email; UI keeps the short name.
    // For per-store products (e.g. Packing Paper) resolve the spec from the chosen store.
    const variant = _resolveItemVariant(o);
    const orderName = (variant && variant.order_name) || o.orderName || '';
    const display = orderName
        ? orderName
        : `${o.name || o.item || ''} ${displayCat}`.replace(/\s+/g, ' ').trim();
    const n = (o.name || '').toLowerCase();
    // Unit word: an explicit unit_label (set in Manage Items) wins; otherwise fall
    // back to the legacy heuristic for older items that never had one.
    const explicitUnit = (variant && variant.unit_label) || o.unitLabel || '';
    let one, many;
    if (explicitUnit) {
        one = explicitUnit; many = _pluralizeUnit(explicitUnit);
    } else {
        one = 'Bundle'; many = 'Bundles';
        if (n.includes('peanut'))        { one = 'Bag'; many = 'Bags'; }
        else if (n.includes('gum tape')) { one = 'Box'; many = 'Boxes'; }
        else if (n.includes('paper'))    { one = 'Roll'; many = 'Rolls'; }
    }
    const bundle  = Math.max(1, parseInt(o.bundle) || 1);
    const bundles = Math.max(1, Math.round((o.qty || 0) / bundle));
    return `${display}: ${bundles} ${bundles === 1 ? one : many}`;
}

function boxOrderUpdatePreview() {
    const preview  = document.getElementById('boxOrderEmailPreview');
    if (!preview) return;
    const store    = _boxOrderGetStore();
    const userName = sessionStorage.getItem('speeksUserName')  || '';
    const notes    = document.getElementById('boxOrderNotes')?.value.trim() || '';
    const to       = _boxOrderGetEmail();
    const lines    = _boxOrderSelected.map(o => `  • ${_boxOrderLine(o)}`).join('\n');
    const noteBlock = notes ? `\n\n${notes}` : '';
    preview.textContent =
        `To: ${to}\nSubject: PayMore ${store} Location\n\n` +
        `Hi,\n\nPlease process the following order for ${store}:\n\n${lines}${noteBlock}\n\n` +
        `Thank you,\n${userName}`;
}

// Corp roles (CEO/DM) must pick a store first; managers default to their own.
function _boxOrderEnsureStore() {
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    const isCorpRole = role === 'ceo' || role === 'district manager';
    const sel = document.getElementById('boxOrderStoreSelect');
    if (isCorpRole && (!sel || !sel.value)) {
        alert('Please select a store before sending.');
        return false;
    }
    return true;
}

// Build the order as plain text (real newlines) — shared by the email and the
// copy failsafe so both always say exactly the same thing.
function _boxOrderCompose() {
    const store    = _boxOrderGetStore();
    const userName = sessionStorage.getItem('speeksUserName') || '';
    const notes    = document.getElementById('boxOrderNotes')?.value.trim() || '';
    const lines    = _boxOrderSelected.map(o => `  • ${_boxOrderLine(o)}`).join('\n');
    const noteBlock = notes ? `\n\n${notes}` : '';
    const body = `Hi,\n\nPlease process the following order for ${store}:\n\n${lines}${noteBlock}\n\nThank you,\n${userName}`;
    return { email: _boxOrderGetEmail(), subject: `PayMore ${store} Location`, body };
}

function sendBoxOrder() {
    if (!_boxOrderEnsureStore()) return;
    const { email, subject, body } = _boxOrderCompose();
    window.location.href = `mailto:${encodeURIComponent(email)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
}

// Failsafe for machines with no default mail client: copy the full order
// (recipient, subject, body) to the clipboard to paste into any email.
function copyBoxOrder(button) {
    if (!_boxOrderEnsureStore()) return;
    const { email, subject, body } = _boxOrderCompose();
    const text = `To: ${email}\nSubject: ${subject}\n\n${body}`;
    navigator.clipboard.writeText(text).then(() => {
        const originalText = button.innerText;
        button.innerText = 'Copied!';
        button.style.background = '#d1fae5';
        button.style.color = '#065f46';
        button.style.borderColor = '#34d399';
        setTimeout(() => {
            button.innerText = originalText;
            button.style.background = '';
            button.style.color = '';
            button.style.borderColor = '';
        }, 2000);
    }).catch(() => alert('Could not copy automatically. Please select and copy the order manually.'));
}

// ============================================================
// RECYCLE INVENTORY TOOL
// ============================================================
// Stores log items that need to be recycled out of inventory. Each submission
// is saved to Supabase (recycle_requests) as a line item under the store — no
// more emails — and the DM reconciles per-store recycled cost at month end
// through the Recycle Requests oversight tool below.

const RECYCLE_STORES = ['OVL', 'LEE', 'WSP', 'MPL', 'BAL'];

// Which store(s) this user can file/view recycle requests for.
function _recycleStores() {
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    if (role === 'ceo' || role === 'district manager') return [...RECYCLE_STORES];
    if (typeof isMultiStoreManager === 'function' && isMultiStoreManager()) {
        return [...MULTISTORE_MANAGER_STORES];
    }
    const s = (sessionStorage.getItem('speeksUserStore') || '').toUpperCase();
    return (s && s !== 'ALL' && s !== 'CORP') ? [s] : [];
}

const _fmtRecycleMoney = v => (v == null || v === '') ? '—' :
    '$' + Number(v).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

// Keep money fields numeric as the user types: strip anything that isn't a
// digit or a decimal point (a typed "$" or letter simply vanishes) and allow
// only one decimal point.
function recycleInvSanitizeMoney(input) {
    let v = (input.value || '').replace(/[^\d.]/g, '');
    const firstDot = v.indexOf('.');
    if (firstDot !== -1) {
        v = v.slice(0, firstDot + 1) + v.slice(firstDot + 1).replace(/\./g, '');
    }
    input.value = v;
}

// Quantity is whole units only: digits, nothing else.
function recycleInvSanitizeInt(input) {
    input.value = (input.value || '').replace(/\D/g, '');
}

// cost is stored per unit; a line's recycled cost = cost × quantity.
function _recycleLineTotal(r) {
    if (r.cost == null || r.cost === '') return null;
    return Number(r.cost) * (Number(r.quantity) || 1);
}

function _recycleMonthKey(dateStr) {
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return '';
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

function _recycleMonthLabel(key) {
    const [y, m] = String(key).split('-').map(Number);
    if (!y || !m) return String(key);
    return new Date(y, m - 1, 1).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
}

// Month dropdown options: every month present in `rows`, plus the current month.
function _recycleMonthOptions(rows, selected) {
    const keys = new Set(rows.map(r => _recycleMonthKey(r.created_at)).filter(Boolean));
    keys.add(_recycleMonthKey(new Date()));
    return [...keys].sort().reverse()
        .map(k => `<option value="${k}" ${k === selected ? 'selected' : ''}>${_recycleMonthLabel(k)}</option>`).join('');
}

function toggleRecycleInventory() {
    toggleModal('recycleInvModal');
    _fetchEmailLists(); // warm the recipient cache for the month-end report
    _buildRecycleStorePicker();
    ['recycleInvSku', 'recycleInvDescription', 'recycleInvValue', 'recycleInvCost'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
    });
    const qty = document.getElementById('recycleInvQty');
    if (qty) qty.value = '1';
    switchRecycleTab('new');
}

function switchRecycleTab(tab) {
    const nb = document.getElementById('recycle-tab-new');
    const vb = document.getElementById('recycle-tab-view');
    if (nb) nb.classList.toggle('active', tab === 'new');
    if (vb) vb.classList.toggle('active', tab === 'view');
    const np = document.getElementById('recycle-panel-new');
    const vp = document.getElementById('recycle-panel-view');
    if (np) np.style.display = tab === 'new' ? 'block' : 'none';
    if (vp) vp.style.display = tab === 'view' ? 'block' : 'none';
    const sb = document.getElementById('submitRecycleBtn');
    if (sb) sb.style.display = tab === 'new' ? '' : 'none';
    if (tab === 'view') fetchMyRecycleRequests();
}

// MSM / corp roles get a store chooser; a single-store manager is locked to theirs.
function _buildRecycleStorePicker() {
    const row = document.getElementById('recycle-store-row');
    const sel = document.getElementById('recycleInvStoreSelect');
    if (!sel) return;
    const stores = _recycleStores();
    sel.innerHTML = stores.map(s => `<option value="${s}">${s}</option>`).join('');
    const multi = stores.length > 1;
    sel.disabled = !multi;
    sel.style.opacity = multi ? '1' : '0.7';
    sel.style.cursor = multi ? 'pointer' : 'not-allowed';
    if (row) row.style.display = stores.length ? 'block' : 'none';
    // Default to the store this open targets for an MSM — a single-store alert
    // override if pending, else the active dashboard store; everyone else keeps
    // their only option. Still switchable via the dropdown when multi-store.
    const def = _msmToolStore();
    if (def && [...sel.options].some(o => o.value === def)) sel.value = def;
    else if (sel.options.length) sel.selectedIndex = 0;
}

async function submitRecycleRequest() {
    const val = id => (document.getElementById(id) || {}).value;
    const store = (val('recycleInvStoreSelect') || '').toUpperCase();
    const sku = (val('recycleInvSku') || '').trim();
    const desc = (val('recycleInvDescription') || '').trim();
    const qty = Math.floor(Number(val('recycleInvQty')));
    const valueRaw = val('recycleInvValue');
    const costRaw = val('recycleInvCost');

    if (!store) { alert('Please select a store.'); return; }
    if (!sku) { alert('Please enter the SKU.'); return; }
    if (!Number.isFinite(qty) || qty < 1) { alert('Please enter a quantity of at least 1.'); return; }
    if (costRaw === '' || costRaw == null || !Number.isFinite(Number(costRaw))) {
        alert('Please enter the item cost (per unit).'); return;
    }
    if (!desc) { alert('Please describe the item and why it is being recycled.'); return; }

    const btn = document.getElementById('submitRecycleBtn');
    const old = btn ? btn.innerText : '';
    if (btn) { btn.disabled = true; btn.innerText = 'Submitting…'; }
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'submit_request', store, sku, description: desc, quantity: qty,
                value: valueRaw === '' ? null : Number(valueRaw),
                cost: Number(costRaw),
                created_by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
        // Stay on the New Request tab with a blank form (store selection kept)
        // so several items can be logged back-to-back; flash the button as the
        // confirmation instead of jumping to My Requests.
        ['recycleInvSku', 'recycleInvDescription', 'recycleInvValue', 'recycleInvCost'].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.value = '';
        });
        const qtyEl = document.getElementById('recycleInvQty');
        if (qtyEl) qtyEl.value = '1';
        const skuEl = document.getElementById('recycleInvSku');
        if (skuEl) skuEl.focus();
        if (btn) {
            btn.innerText = '✓ Submitted';
            setTimeout(() => { if (btn.innerText === '✓ Submitted') btn.innerText = old; }, 1500);
        }
    } catch (e) {
        alert('Could not submit the request: ' + e.message);
        if (btn) btn.innerText = old;
    } finally {
        if (btn) btn.disabled = false;
    }
}

let _recycleMine = []; // last fetched requests, so filter changes re-render without refetching
let _recycleReportPreviewing = false; // true = My Requests tab is showing the report email preview
let _recycleNoteOpen = new Set();  // line ids with the DM note editor expanded
let _recycleSeenBefore = {};       // id → ms this viewer had seen up to, snapshotted pre-stamp (drives NEW dots)

// A line needs the manager's attention when the DM's latest review or note is
// newer than the last time the manager opened their requests.
function _recycleNeedsAttention(r) {
    const act = Math.max(
        r.reviewed_at ? new Date(r.reviewed_at).getTime() : 0,
        r.dm_note_at ? new Date(r.dm_note_at).getTime() : 0,
    );
    if (!act) return false;
    const seen = r.manager_seen_at ? new Date(r.manager_seen_at).getTime() : 0;
    return act > seen;
}

async function fetchMyRecycleRequests() {
    const wrap = document.getElementById('recycle-table-wrap');
    if (!wrap) return;
    _recycleReportPreviewing = false; // fresh entry to the tab always starts on the table
    const stores = _recycleStores();
    if (!stores.length) {
        wrap.innerHTML = '<div style="padding:24px; text-align:center; color:#94a3b8; font-weight:600;">No store assigned to your account.</div>';
        return;
    }
    wrap.innerHTML = '<div style="padding:24px; text-align:center; color:#94a3b8; font-weight:600;">Loading requests…</div>';
    try {
        const res = await fetch(`${RECYCLE_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json.success) throw new Error(json.error);
        _recycleMine = json.data || [];
        // Snapshot what this viewer had already seen per line (drives the
        // pulsing NEW dots), then stamp the fresh lines seen for their side —
        // managers track review/note activity, the DM tracks new submissions,
        // delete requests and manager replies.
        const isReviewer = _recycleCanReview();
        const getT = v => (v ? new Date(v).getTime() : 0);
        const seenField = isReviewer ? 'dm_seen_at' : 'manager_seen_at';
        _recycleSeenBefore = {};
        _recycleMine.forEach(r => { _recycleSeenBefore[r.id] = getT(r[seenField]); });
        const fresh = _recycleMine.filter(r => {
            const seen = _recycleSeenBefore[r.id];
            return isReviewer
                ? (getT(r.created_at) > seen || getT(r.mgr_reply_at) > seen || getT(r.delete_requested_at) > seen)
                : (getT(r.reviewed_at) > seen || getT(r.dm_note_at) > seen);
        });
        if (fresh.length) {
            fetch(RECYCLE_URL, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'mark_seen', ids: fresh.map(r => r.id), role: isReviewer ? 'dm' : 'mgr' }),
            }).then(() => {
                // Opening the tool IS the acknowledgement, so re-run the check now
                // instead of leaving the alert up until the next 10-minute poll.
                // Chained off the POST so the re-fetch sees the new seen stamps.
                if (typeof checkRecycleReminders === 'function') checkRecycleReminders();
            }).catch(() => {});
            const now = new Date().toISOString();
            fresh.forEach(r => { r[seenField] = now; });
        }
        _buildRecycleViewFilters(stores);
        renderMyRecycleTable();
    } catch (e) {
        wrap.innerHTML = '<div style="color:var(--red-alert); padding:24px; text-align:center; font-weight:700;">Error loading requests.</div>';
    }
}

// Month filter always shows; the store filter only when the user spans multiple stores.
function _buildRecycleViewFilters(stores) {
    const mSel = document.getElementById('recycle-month-filter');
    if (mSel) {
        const current = mSel.value || _recycleMonthKey(new Date());
        mSel.innerHTML = _recycleMonthOptions(_recycleMine, current);
    }
    const row = document.getElementById('recycle-view-filter-row');
    const sel = document.getElementById('recycle-view-filter');
    if (!row || !sel) return;
    if (stores.length <= 1) { row.style.display = 'none'; return; }
    row.style.display = 'block';
    const current = sel.value;
    sel.innerHTML = `<option value="">All stores</option>` +
        stores.map(s => `<option value="${s}">${s}</option>`).join('');
    if ([...sel.options].some(o => o.value === current)) sel.value = current;
}

// DM/CEO review lines right in the My Requests tab (same verdicts as the
// oversight modal): against = truly recycled out of inventory, for = tool
// for store use.
function _recycleCanReview() {
    const role = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
    return role === 'ceo' || role === 'district manager';
}

function renderMyRecycleTable() {
    const wrap = document.getElementById('recycle-table-wrap');
    if (!wrap) return;
    const stores = _recycleStores();
    const multi = stores.length > 1;
    const canReview = _recycleCanReview();
    const month = (document.getElementById('recycle-month-filter') || {}).value || _recycleMonthKey(new Date());
    const filterStore = (document.getElementById('recycle-view-filter') || {}).value || '';
    let rows = _recycleMine.filter(r => _recycleMonthKey(r.created_at) === month);
    if (filterStore) rows = rows.filter(r => (r.store || '').toUpperCase() === filterStore);
    // Keep the Store column whenever the user spans multiple stores — even with
    // a single store filtered — so columns don't jump around as filters change.
    const showStore = multi;

    if (!rows.length && !_recycleReportPreviewing) {
        // Keep the report buttons visible for DM/CEO even on an empty month —
        // a month with zero recycles can still be reported.
        const emptyBtns = canReview
            ? `<div style="display:flex; justify-content:flex-end; gap:8px; margin-bottom:10px;">
                ${RECYCLE_MAIL_TIP}
                <button class="btn-secondary" onclick="copyRecycleReport(this)">📋 Copy</button>
                <button class="btn-primary" onclick="_recycleReportPreviewing=true; renderMyRecycleTable();">Send Email →</button>
            </div>`
            : '';
        wrap.innerHTML = `${emptyBtns}${_recycleDeleteReqPanel(canReview)}<div style="padding:28px 20px; text-align:center; color:#94a3b8; font-weight:600;">No recycle requests for ${_recycleMonthLabel(month)}.</div>`;
        return;
    }
    rows = [...rows].sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
    // Lines reviewed as "ignore" had their cost consolidated into another SKU
    // (e.g. 5 broken units merged into 1 rebuilt item) — they were never really
    // recycled out, so their cost is excluded from every total. "denied" lines
    // were rejected by the DM (item is NOT to be recycled) — excluded too.
    const ignoredTotal = rows.filter(r => r.review_verdict === 'ignore').reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);
    const deniedTotal = rows.filter(r => r.review_verdict === 'denied').reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);
    const total = rows.filter(r => r.review_verdict !== 'ignore' && r.review_verdict !== 'denied').reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);
    const fmtDate = d => { const x = new Date(d); return isNaN(x.getTime()) ? '' : x.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }); };

    const th = t => `<th style="text-align:left; font-size:9.5px; font-weight:800; text-transform:uppercase; letter-spacing:.4px; color:#94a3b8; padding:8px 10px; border-bottom:1px solid #e2e8f0; white-space:nowrap;">${t}</th>`;
    const td = (c, extra = '') => `<td style="padding:9px 10px; border-bottom:1px solid #f1f5f9; vertical-align:top; ${extra}">${c}</td>`;
    // Report preview "page" (DM/CEO) — mirrors the Box Order flow: Send Email
    // first shows the composed email, and the actual send happens from there.
    if (canReview && _recycleReportPreviewing) {
        const { subject, body } = _recycleReportCompose();
        wrap.innerHTML = `
            <div class="box-order-preview-label">Email Preview</div>
            <div class="box-order-email-preview">${escapeHtml(`To: ${_recycleReportTo().join(', ')}\nSubject: ${subject}\n\n${body}`)}</div>
            <div style="display:flex; justify-content:flex-end; gap:8px; margin-top:14px;">
                ${RECYCLE_MAIL_TIP}
                <button class="btn-secondary" onclick="_recycleReportPreviewing=false; renderMyRecycleTable();">← Back</button>
                <button class="btn-secondary" onclick="copyRecycleReport(this)">📋 Copy</button>
                <button class="btn-primary" onclick="sendRecycleReport()">Send Email →</button>
            </div>`;
        return;
    }

    let html = canReview
        ? `<div style="display:flex; justify-content:flex-end; gap:8px; margin-bottom:10px;">
            ${RECYCLE_MAIL_TIP}
            <button class="btn-secondary" onclick="copyRecycleReport(this)">📋 Copy</button>
            <button class="btn-primary" onclick="_recycleReportPreviewing=true; renderMyRecycleTable();">Send Email →</button>
        </div>`
        : '';
    html += _recycleDeleteReqPanel(canReview);
    const colCount = 9 + (showStore ? 1 : 0);
    html += `<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12.5px;">
        <thead><tr>${canReview ? th('Review') : th('Status')}${th('Date')}${showStore ? th('Store') : ''}${th('SKU')}${th('Description')}${th('Qty')}${th('Unit Cost')}${th('Total Cost')}${th('By')}${th('')}</tr></thead><tbody>`;
    rows.forEach(r => {
        // A line with a pending delete request is LOCKED — no reviewing, no
        // notes, no replies — until the DM approves/denies it or the manager
        // cancels their own request.
        const delPending = !!r.delete_requested_at;
        // Managers never delete directly — the trash button files a delete
        // request that the DM/CEO approves or denies (same model as claims).
        let delBtn = '';
        if (delPending) {
            delBtn = canReview
                ? `<span title="Delete request pending — approve or deny it in the panel above" style="display:inline-flex; align-items:center; gap:4px; font-size:10px; font-weight:800; color:#b45309; background:#fffbeb; border:1.5px solid #fde68a; border-radius:8px; padding:6px 8px; white-space:nowrap;">🗑 Requested</span>`
                : `<button onclick="cancelRecycleDeleteRequest('${r.id}')" title="Waiting on DM/CEO approval — click to cancel your delete request and unlock the line" style="display:inline-flex; align-items:center; gap:4px; font-size:10px; font-weight:800; color:#b45309; background:#fffbeb; border:1.5px solid #fde68a; border-radius:8px; padding:6px 8px; white-space:nowrap; cursor:pointer;">🗑 Requested — Cancel?</button>`;
        } else if (canReview) {
            delBtn = `<button onclick="deleteRecycleRequest('${r.id}')" title="Delete this line" style="display:inline-flex; align-items:center; justify-content:center; width:30px; height:30px; background:#fff5f5; border:1.5px solid #fecaca; border-radius:8px; cursor:pointer; font-size:15px; line-height:1;">🗑</button>`;
        } else {
            delBtn = `<button onclick="requestRecycleDelete('${r.id}')" title="Request deletion (a DM or CEO must approve)" style="display:inline-flex; align-items:center; justify-content:center; width:30px; height:30px; background:#fff5f5; border:1.5px solid #fecaca; border-radius:8px; cursor:pointer; font-size:15px; line-height:1;">🗑</button>`;
        }
        // DM gets the note button on every line; a manager gets a reply button
        // once there's a DM note to respond to (answer a question, push back
        // before the verdict, etc.). Both disappear while the line is locked.
        const noteBtn = delPending ? '' : (canReview
            ? `<button onclick="toggleRecycleNote('${r.id}')" title="${r.dm_note ? 'Edit your note' : 'Leave a note for the store'}" style="display:inline-flex; align-items:center; justify-content:center; width:30px; height:30px; background:${r.dm_note ? '#eff6ff' : '#f8fafc'}; border:1.5px solid ${r.dm_note ? '#bfdbfe' : '#e2e8f0'}; border-radius:8px; cursor:pointer; font-size:14px; line-height:1; margin-right:6px;">💬</button>`
            : (r.dm_note
                ? `<button onclick="toggleRecycleNote('${r.id}')" title="${r.mgr_reply ? 'Edit your reply' : "Reply to the DM's note"}" style="display:inline-flex; align-items:center; justify-content:center; width:30px; height:30px; background:${r.mgr_reply ? '#f0fdf4' : '#eff6ff'}; border:1.5px solid ${r.mgr_reply ? '#a7f3d0' : '#bfdbfe'}; border-radius:8px; cursor:pointer; font-size:14px; line-height:1; margin-right:6px;">↩</button>`
                : ''));
        const verdict = ['for', 'against', 'ignore', 'denied'].includes(r.review_verdict) ? r.review_verdict : '';
        // Pulsing dots pinpoint exactly what's new for THIS viewer: on the line
        // when the line itself changed (new verdict for a manager, a newly
        // submitted line for the DM), on a specific note when that note is new.
        const seenB = _recycleSeenBefore[r.id] || 0;
        const tOf = v => (v ? new Date(v).getTime() : 0);
        const NEW_DOT = '<span class="recycle-new-dot" title="New since you last looked"></span>';
        const lineIsNew = canReview ? tOf(r.created_at) > seenB : tOf(r.reviewed_at) > seenB;
        let firstCell = '';
        if (canReview) {
            const vColor = verdict === 'against' ? '#dc2626' : verdict === 'for' ? '#059669' : verdict === 'ignore' ? '#475569' : verdict === 'denied' ? '#b91c1c' : '#94a3b8';
            const vBorder = verdict === 'against' ? '#fecaca' : verdict === 'for' ? '#a7f3d0' : verdict === 'ignore' ? '#94a3b8' : verdict === 'denied' ? '#fca5a5' : '#cbd5e1';
            firstCell = td(`${lineIsNew ? NEW_DOT : ''}<select ${delPending ? 'disabled' : ''} onchange="setRecycleReviewed('${r.id}', this.value)" title="${delPending ? 'Locked — a delete request is pending on this line' : r.reviewed_at ? 'Reviewed' + (r.reviewed_by ? ' by ' + escapeHtml(r.reviewed_by) : '') : 'Against = out of inventory · For = store-use tool · Ignore = cost moved to another SKU · Deny = do not recycle'}" style="padding:5px 6px; border:1.5px solid ${vBorder}; border-radius:8px; font-size:11px; font-weight:800; color:${vColor}; background:#fff; cursor:${delPending ? 'not-allowed' : 'pointer'};${delPending ? ' opacity:0.55;' : ''}">
                <option value=""${verdict ? '' : ' selected'}>— Review —</option>
                <option value="against"${verdict === 'against' ? ' selected' : ''}>Against Store</option>
                <option value="for"${verdict === 'for' ? ' selected' : ''}>For Store</option>
                <option value="ignore"${verdict === 'ignore' ? ' selected' : ''}>Ignore</option>
                <option value="denied"${verdict === 'denied' ? ' selected' : ''}>Deny</option>
            </select>`, 'text-align:center; white-space:nowrap;');
        } else {
            // Manager-facing status: any verdict except "denied" means the DM
            // approved the recycle; no verdict yet = pending.
            const chip = verdict === 'denied'
                ? `<span style="display:inline-block; font-size:10.5px; font-weight:800; color:#b91c1c; background:#fee2e2; border:1px solid #fca5a5; border-radius:20px; padding:3px 10px; white-space:nowrap;">✕ Denied</span>`
                : verdict
                ? `<span style="display:inline-block; font-size:10.5px; font-weight:800; color:#166534; background:#dcfce7; border:1px solid #a7f3d0; border-radius:20px; padding:3px 10px; white-space:nowrap;">✓ Approved</span>`
                : `<span style="display:inline-block; font-size:10.5px; font-weight:800; color:#64748b; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:20px; padding:3px 10px; white-space:nowrap;">⏳ Pending</span>`;
            firstCell = td((lineIsNew ? NEW_DOT : '') + chip, 'white-space:nowrap;');
        }
        const struck = verdict === 'ignore' || verdict === 'denied';
        const struckTitle = verdict === 'ignore' ? 'Not counted — cost was moved into another SKU' : 'Not counted — the request was denied, item stays in inventory';
        const rowBg = delPending ? 'background:#fffbeb;' // locked amber while awaiting approve/deny/cancel
            : verdict === 'denied' ? 'background:#fee2e2;'
            : (canReview && verdict ? `background:${verdict === 'against' ? '#fef2f2' : verdict === 'for' ? '#f0fdf4' : '#f1f5f9'};` : '');
        // Full back-and-forth thread, in order — DM notes in blue, manager
        // replies indented in green. Nothing is ever overwritten by a new note.
        const thread = Array.isArray(r.note_thread) && r.note_thread.length
            ? r.note_thread
            : [ // legacy rows from before threading
                ...(r.dm_note ? [{ role: 'dm', text: r.dm_note, by: r.dm_note_by }] : []),
                ...(r.mgr_reply ? [{ role: 'mgr', text: r.mgr_reply, by: r.mgr_reply_by }] : []),
            ];
        // A dot lands on the specific note that's new — only for messages from
        // the OTHER side (your own notes are never "new" to you).
        const otherRole = canReview ? 'mgr' : 'dm';
        const noteLine = thread.map(n => {
            const noteDot = (n.role === otherRole && tOf(n.at) > seenB) ? NEW_DOT : '';
            return n.role === 'dm'
                ? `<div style="margin-top:4px; font-size:11.5px; font-weight:600; color:#1d4ed8; background:#eff6ff; border:1px solid #bfdbfe; border-radius:7px; padding:4px 8px;">${noteDot}💬 ${escapeHtml(n.text || '')}${n.by ? ` <span style="color:#94a3b8;">— ${escapeHtml(n.by)}</span>` : ''}</div>`
                : `<div style="margin-top:3px; margin-left:14px; font-size:11.5px; font-weight:600; color:#047857; background:#f0fdf4; border:1px solid #a7f3d0; border-radius:7px; padding:4px 8px;">${noteDot}↩ ${escapeHtml(n.text || '')}${n.by ? ` <span style="color:#94a3b8;">— ${escapeHtml(n.by)}</span>` : ''}</div>`;
        }).join('');
        html += `<tr style="${rowBg}">
            ${firstCell}
            ${td(`<span style="color:#94a3b8; white-space:nowrap;">${fmtDate(r.created_at)}</span>`)}
            ${showStore ? td(`<span style="font-weight:800; color:var(--slate-charcoal);">${escapeHtml(r.store || '')}</span>`) : ''}
            ${td(`<span style="font-weight:700; color:var(--slate-charcoal);">${escapeHtml(r.sku || '')}</span>`)}
            ${td(`<span style="color:#64748b;">${escapeHtml(r.description || '—')}</span>${noteLine}`)}
            ${td(`<span style="font-weight:800;">${Number(r.quantity) || 1}</span>`, 'text-align:center;')}
            ${td(_fmtRecycleMoney(r.cost), 'white-space:nowrap; font-weight:700; color:#64748b;')}
            ${td(struck
                ? `<span style="text-decoration:line-through; color:#94a3b8;" title="${struckTitle}">${_fmtRecycleMoney(_recycleLineTotal(r))}</span>`
                : _fmtRecycleMoney(_recycleLineTotal(r)), 'white-space:nowrap; font-weight:800;')}
            ${td(`<span style="color:#94a3b8; white-space:nowrap;">${escapeHtml(r.created_by || '—')}</span>`)}
            ${td(noteBtn + delBtn, 'text-align:right; white-space:nowrap;')}
        </tr>`;
        if (_recycleNoteOpen.has(r.id) && !delPending) {
            // Appends a NEW message to the thread — earlier notes are never
            // touched, so a longer back-and-forth can't override anything.
            if (canReview) {
                html += `<tr><td colspan="${colCount}" style="padding:4px 10px 12px; background:#f8fafc; border-bottom:1px solid #f1f5f9;">
                    <div style="display:flex; gap:8px; align-items:flex-start;">
                        <textarea id="recycle-note-ta-${r.id}" rows="2" placeholder="${r.dm_note ? 'Add another note for the store…' : 'Note for the store (e.g. why it\'s denied, what to do instead)…'}" style="flex:1; box-sizing:border-box; padding:7px 9px; border:1.5px solid #bfdbfe; border-radius:7px; font-size:12px; font-family:inherit; resize:vertical;"></textarea>
                        <button class="btn-primary" style="font-size:12px; padding:7px 14px;" onclick="saveRecycleNote('${r.id}', this)">Add note</button>
                        <button class="kpi-cancel-btn" onclick="toggleRecycleNote('${r.id}')">Cancel</button>
                    </div>
                </td></tr>`;
            } else if (r.dm_note) {
                html += `<tr><td colspan="${colCount}" style="padding:4px 10px 12px; background:#f8fafc; border-bottom:1px solid #f1f5f9;">
                    <div style="display:flex; gap:8px; align-items:flex-start;">
                        <textarea id="recycle-reply-ta-${r.id}" rows="2" placeholder="Reply to the DM's note…" style="flex:1; box-sizing:border-box; padding:7px 9px; border:1.5px solid #a7f3d0; border-radius:7px; font-size:12px; font-family:inherit; resize:vertical;"></textarea>
                        <button class="btn-primary" style="font-size:12px; padding:7px 14px;" onclick="saveRecycleReply('${r.id}', this)">Add reply</button>
                        <button class="kpi-cancel-btn" onclick="toggleRecycleNote('${r.id}')">Cancel</button>
                    </div>
                </td></tr>`;
            }
        }
    });
    const labelSpan = 1 + (showStore ? 1 : 0) + 5;
    const footLabel = (t, c) => `<td colspan="${labelSpan}" style="padding:${c ? '4px' : '11px'} 10px; font-weight:800; font-size:${c ? '10.5px' : '12px'}; color:#94a3b8; text-transform:uppercase; letter-spacing:.4px;">${t}</td>`;
    html += `</tbody><tfoot><tr>
        ${footLabel(`Total recycled cost · ${_recycleMonthLabel(month)}`)}
        <td style="padding:11px 10px; font-weight:900; font-size:14px; color:#dc2626; white-space:nowrap;">${_fmtRecycleMoney(total)}</td>
        <td colspan="2"></td>
    </tr>`;
    if (canReview) {
        const againstTotal = rows.filter(r => r.review_verdict === 'against').reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);
        const forTotal = rows.filter(r => r.review_verdict === 'for').reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);
        if (againstTotal || forTotal) {
            html += `<tr>${footLabel('Against store (out of inventory)', true)}<td style="padding:4px 10px; font-weight:900; font-size:12px; color:#dc2626; white-space:nowrap;">${_fmtRecycleMoney(againstTotal)}</td><td colspan="2"></td></tr>
            <tr>${footLabel('For store (store-use tools)', true)}<td style="padding:4px 10px 11px; font-weight:900; font-size:12px; color:#059669; white-space:nowrap;">${_fmtRecycleMoney(forTotal)}</td><td colspan="2"></td></tr>`;
        }
    }
    if (ignoredTotal) {
        // Shown to everyone so the month total visibly reconciles with the
        // struck-through lines above it.
        html += `<tr>${footLabel('Ignored (cost moved to another SKU)', true)}<td style="padding:4px 10px 11px; font-weight:900; font-size:12px; color:#94a3b8; white-space:nowrap; text-decoration:line-through;">${_fmtRecycleMoney(ignoredTotal)}</td><td colspan="2"></td></tr>`;
    }
    if (deniedTotal) {
        html += `<tr>${footLabel('Denied (not recycled — stays in inventory)', true)}<td style="padding:4px 10px 11px; font-weight:900; font-size:12px; color:#b91c1c; white-space:nowrap; text-decoration:line-through;">${_fmtRecycleMoney(deniedTotal)}</td><td colspan="2"></td></tr>`;
    }
    html += `</tfoot></table></div>`;
    wrap.innerHTML = html;
}

// Pending delete requests (DM/CEO) — pulled from every fetched month, not just
// the filtered one, so a request can't hide behind the month filter. Mirrors
// the insurance-claims approval queue.
function _recycleDeleteReqPanel(canReview) {
    if (!canReview) return '';
    const delReqs = _recycleMine.filter(r => r.delete_requested_at)
        .sort((a, b) => new Date(a.delete_requested_at) - new Date(b.delete_requested_at));
    if (!delReqs.length) return '';
    return `<div style="background:#fffbeb; border:1.5px solid #fde68a; border-radius:12px; padding:14px 16px; margin-bottom:14px;">
        <div style="font-weight:800; font-size:13px; color:#92400e; margin-bottom:10px;">🗑 Delete requests (${delReqs.length}) — approval needed</div>
        <div style="display:flex; flex-direction:column; gap:8px;">` +
        delReqs.map(r => `<div style="display:flex; align-items:center; justify-content:space-between; gap:12px; flex-wrap:wrap; background:#fff; border:1px solid #fde68a; border-radius:9px; padding:9px 12px;">
            <div style="font-size:12.5px; color:var(--slate-charcoal);">
                <span style="font-weight:800;">${escapeHtml(r.store || '')}</span>
                · <span style="font-weight:700;">${escapeHtml(r.sku || '')}</span>
                <span style="color:#94a3b8;"> — ${escapeHtml(r.description || '')} · qty ${Number(r.quantity) || 1} · ${_fmtRecycleMoney(_recycleLineTotal(r))}</span>
                <span style="color:#b45309; font-weight:700;"> · requested by ${escapeHtml(r.delete_requested_by || 'Manager')}</span>
            </div>
            <div style="display:flex; gap:8px;">
                <button onclick="approveRecycleDelete('${r.id}')" style="font-size:11px; font-weight:800; border-radius:7px; padding:6px 13px; cursor:pointer; background:#fef2f2; border:1.5px solid #fecaca; color:#b91c1c;">Approve delete</button>
                <button onclick="denyRecycleDelete('${r.id}')" style="font-size:11px; font-weight:800; border-radius:7px; padding:6px 13px; cursor:pointer; background:#f1f5f9; border:1.5px solid #cbd5e1; color:#475569;">Deny</button>
            </div>
        </div>`).join('') +
        `</div></div>`;
}

// Manager-side: request removal. Recycle lines are never deleted directly by a
// manager — a DM/CEO must approve, so nothing quietly disappears.
async function requestRecycleDelete(id) {
    if (!confirm('Request deletion of this recycle request?\n\nA DM or CEO must approve it before the line is removed.')) return;
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'request_delete', id, requested_by: sessionStorage.getItem('speeksUserName') || null }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Request failed');
        const row = _recycleMine.find(r => r.id === id);
        if (row) {
            row.delete_requested_at = new Date().toISOString();
            row.delete_requested_by = sessionStorage.getItem('speeksUserName') || null;
        }
        renderMyRecycleTable();
        alert('Delete request sent. A DM or CEO will review it.');
    } catch (e) {
        alert('Could not send the request: ' + (e.message || e));
    }
}

// DM/CEO-side: approve → permanently removes the line.
async function approveRecycleDelete(id) {
    if (!confirm('Approve deletion? This permanently removes the line and cannot be undone.')) return;
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'delete_request', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Delete failed');
        fetchMyRecycleRequests();
        if (typeof checkRecycleReminders === 'function') checkRecycleReminders();
    } catch (e) {
        alert('Could not delete: ' + (e.message || e));
    }
}

// Manager-side: cancel their own pending delete request — unlocks the line.
// Same server action as the DM's deny (both just clear the request flag).
async function cancelRecycleDeleteRequest(id) {
    if (!confirm('Cancel your delete request? The line stays and unlocks for notes/replies again.')) return;
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'deny_delete', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        const row = _recycleMine.find(r => r.id === id);
        if (row) { row.delete_requested_at = null; row.delete_requested_by = null; }
        renderMyRecycleTable();
    } catch (e) {
        alert('Could not cancel the request: ' + (e.message || e));
    }
}

// DM/CEO-side: deny → keeps the line, clears the request flag.
async function denyRecycleDelete(id) {
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'deny_delete', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        const row = _recycleMine.find(r => r.id === id);
        if (row) { row.delete_requested_at = null; row.delete_requested_by = null; }
        renderMyRecycleTable();
        if (typeof checkRecycleReminders === 'function') checkRecycleReminders();
    } catch (e) {
        alert('Could not deny: ' + (e.message || e));
    }
}

function toggleRecycleNote(id) {
    if (_recycleNoteOpen.has(id)) _recycleNoteOpen.delete(id); else _recycleNoteOpen.add(id);
    renderMyRecycleTable();
}

// Both sides append to the same per-line thread via add_note — the edge fn
// also mirrors the latest message per side into dm_note*/mgr_reply* so the
// alert timestamps keep working.
async function _recycleAddThreadNote(id, role, taId, btn, oldLabel) {
    const ta = document.getElementById(taId);
    if (!ta) return;
    const text = ta.value.trim();
    if (!text) { alert('Type a note first.'); return; }
    const name = sessionStorage.getItem('speeksUserName') || null;
    btn.disabled = true; btn.innerText = 'Saving…';
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'add_note', id, text, role, by: name }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        const row = _recycleMine.find(r => r.id === id);
        if (row) {
            if (!Array.isArray(row.note_thread)) row.note_thread = [];
            row.note_thread.push(json.entry || { role, text, by: name, at: new Date().toISOString() });
            if (role === 'dm') { row.dm_note = text; row.dm_note_by = name; row.dm_note_at = new Date().toISOString(); }
            else { row.mgr_reply = text; row.mgr_reply_by = name; row.mgr_reply_at = new Date().toISOString(); }
        }
        _recycleNoteOpen.delete(id);
        renderMyRecycleTable();
    } catch (e) {
        btn.disabled = false; btn.innerText = oldLabel;
        alert('Could not save: ' + e.message);
    }
}

function saveRecycleNote(id, btn) { _recycleAddThreadNote(id, 'dm', `recycle-note-ta-${id}`, btn, 'Add note'); }
function saveRecycleReply(id, btn) { _recycleAddThreadNote(id, 'mgr', `recycle-reply-ta-${id}`, btn, 'Add reply'); }

// ---- recycle alerts ----------------------------------------------------------
// Managers: popup when the DM reviews or notes their requests (opening the My
// Requests tab marks lines seen, which stops it re-firing on other devices).
// DM/CEO: popup when a manager replies to one of their notes.
// The popup lives in its OWN bubble so it never fights with the claims/variance
// red bubble or the green store comment — they stack vertically instead.
let _recycleRemindersStarted = false;

// Roles that get the SUBMITTER-side recycle alert ("your request was reviewed").
// ASMs can open the tool and file requests (see the tools-panel role list), so they
// need to hear back about them — the check used to borrow Variance's manager set,
// which has no ASM, leaving them able to submit but never told the outcome.
const _RECYCLE_ALERT_ROLES = new Set(['manager', 'owner (manager)', 'owner manager', 'assistant manager']);

// Alert seen-stamps are per-USER. Browser-global keys meant one person's alert
// silenced the next login on a shared store computer — the same bug we hit twice
// on claims. See the feed-suppression notes.
function _recycleSeenKey(name) {
    const u = (sessionStorage.getItem('speeksUserName') || 'anon').trim().toLowerCase();
    return name + '_' + u;
}

async function checkRecycleReminders() {
    const isReviewer = _recycleCanReview();
    const role = _vrRole();
    // CEO is deliberately excluded: they keep full approve/deny authority inside the
    // tool (_recycleCanReview still returns true for them, so the reviewer UI is
    // unchanged) but receive no notifications — the same rule we applied to claims,
    // access without the nagging. Only the DM is actually on the hook for reviews.
    const wantsAlert = isReviewer ? role === 'district manager' : _RECYCLE_ALERT_ROLES.has(role);
    if (!wantsAlert) return;
    const stores = _recycleStores();
    if (!stores.length) return;
    if (!_recycleRemindersStarted) {
        _recycleRemindersStarted = true;
        setInterval(checkRecycleReminders, 10 * 60 * 1000);
    }
    try {
        const res = await fetch(`${RECYCLE_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json || json.success === false) return;
        const rows = json.data || [];

        if (isReviewer) {
            const getT = v => (v ? new Date(v).getTime() : 0);

            // Two kinds of DM signal, handled differently on purpose:
            //
            //  • ACTION items block a store: a manager can't recycle until you review
            //    their submission or approve/deny a delete request. These are
            //    STATE-based — opening the tool does NOT clear them, only actually
            //    reviewing/resolving does. That's the check-and-balance: a glance
            //    can't dismiss work a manager is waiting on, and it keeps surfacing
            //    (and re-fires next login) until it's genuinely done. Review one of
            //    several and the count drops but the row stays for the rest — and
            //    since the summary changed, it even breaks a prior snooze.
            //    (This replaced a dm_seen_at "seen on open" model that let a glance
            //    silence unreviewed work the manager was still blocked on.)
            //
            //  • A manager REPLY to your note blocks nobody, so it stays seen-based:
            //    surface it once, then the high-water mark hides it.
            const needsReview   = rows.filter(r => !r.reviewed_at && !r.delete_requested_at);
            const pendingDelete = rows.filter(r => r.delete_requested_at);

            const sRep = Number(localStorage.getItem(_recycleSeenKey('speeksRecycleReplySeen')) || 0);
            const freshRep = rows.filter(r => getT(r.mgr_reply_at) > sRep);

            if (!needsReview.length && !pendingDelete.length && !freshRep.length) {
                // Nothing waiting and no new reply — drop the bubble so the feed row
                // goes with it, rather than leaving a stale "N need your review" up.
                const rb = document.getElementById('recycleAlertBubble');
                if (rb && getComputedStyle(rb).display !== 'none') {
                    rb.style.display = 'none';
                    if (typeof _positionRecycleAlert === 'function') _positionRecycleAlert();
                }
                return;
            }

            // Replies are the only seen-based part, so advance their mark now that
            // we're surfacing them; the action items intentionally have no mark.
            if (freshRep.length) {
                localStorage.setItem(_recycleSeenKey('speeksRecycleReplySeen'),
                    String(Math.max(...freshRep.map(r => getT(r.mgr_reply_at)))));
            }

            const storeList = list => [...new Set(list.map(r => (r.store || '').toUpperCase()))].join(', ');
            const parts = [];
            if (needsReview.length)   parts.push(`${needsReview.length} awaiting your review from ${storeList(needsReview)}`);
            if (pendingDelete.length) parts.push(`${pendingDelete.length} delete request${pendingDelete.length > 1 ? 's' : ''} awaiting approval`);
            if (freshRep.length)      parts.push(`${freshRep.length} ${freshRep.length > 1 ? 'replies' : 'reply'} to your notes`);
            const summary = parts.join(' · ');
            _recycleRenderBubble('♻️', 'Recycle requests need your review', summary + '.', summary);
            return;
        }

        // Manager/ASM: reviews + notes on this store's requests the STORE hasn't
        // picked up yet. Read state is deliberately shared via manager_seen_at —
        // the manager and ASM work the same queue, so once either one opens it the
        // other doesn't need to be told again. (Per-user tracking was tried and
        // reverted: it made both of them action the same review.)
        const fresh = rows.filter(_recycleNeedsAttention);
        if (!fresh.length) {
            // Someone at the store opened the tool, so the queue is acknowledged.
            // Returning without hiding left a stale "3 reviewed by the DM" row sitting
            // in the feed for the rest of the session after the work was done — the
            // same trap fixed on the claims aging alert.
            const rb = document.getElementById('recycleAlertBubble');
            if (rb && getComputedStyle(rb).display !== 'none') {
                rb.style.display = 'none';
                if (typeof _positionRecycleAlert === 'function') _positionRecycleAlert();
            }
            return;
        }
        // One popup per batch of activity: remember the newest activity stamp we
        // alerted on, so the same reviews don't re-popup every poll — but a NEWER
        // review/note after that fires again.
        const latest = Math.max(...fresh.map(r => Math.max(
            r.reviewed_at ? new Date(r.reviewed_at).getTime() : 0,
            r.dm_note_at ? new Date(r.dm_note_at).getTime() : 0,
        )));
        if (Number(localStorage.getItem(_recycleSeenKey('speeksRecycleAlertSeen')) || 0) >= latest) return;
        localStorage.setItem(_recycleSeenKey('speeksRecycleAlertSeen'), String(latest));

        const approved = fresh.filter(r => r.review_verdict && r.review_verdict !== 'denied').length;
        const denied = fresh.filter(r => r.review_verdict === 'denied').length;
        const noted = fresh.filter(r => r.dm_note).length;
        const parts = [];
        if (approved) parts.push(`${approved} approved`);
        if (denied) parts.push(`${denied} denied`);
        const summary = parts.length ? ` — ${parts.join(', ')}` : '';
        const noteTxt = noted ? ` ${noted === 1 ? '1 has' : noted + ' have'} a note for you.` : '';
        _recycleRenderBubble('♻️', 'Your recycle requests were reviewed',
            `${fresh.length} of your recycle request${fresh.length > 1 ? 's' : ''} ${fresh.length > 1 ? 'have' : 'has'} new activity from the DM${summary}.${noteTxt}`,
            // Compact feed line — counts first, so nothing useful is lost to the cap.
            `${fresh.length} reviewed by the DM${summary}` + (noted ? ` · ${noted} with a note` : ''),
            fresh.map(r => r.store));
    } catch (e) { /* next poll retries */ }
}

// Recycle's own bubble — created on demand next to the shared claim bubble so
// it inherits the same header stacking context (over the dashboard, under the
// side panels/modals). Positioned below whichever other bubbles are showing.
function _recycleBubbleEl() {
    let b = document.getElementById('recycleAlertBubble');
    if (b) return b;
    const claim = document.getElementById('claimAlertBubble');
    if (!claim || !claim.parentElement) return null;
    b = document.createElement('div');
    b.id = 'recycleAlertBubble';
    b.style.cssText = 'display:none; position:fixed; top:116px; right:24px; background:linear-gradient(135deg, #2563eb, #1e40af); color:white; padding:11px 14px 11px 16px; border-radius:14px; align-items:flex-start; gap:8px; font-size:13px; box-shadow:0 10px 28px rgba(30, 64, 175, 0.38); max-width:min(380px, calc(100vw - 48px)); z-index:999;';
    b.innerHTML = `<span id="recycleAlertBubbleIcon" style="font-size:16px; flex-shrink:0; margin-top:2px;">♻️</span>
        <span id="recycleAlertBubbleText" style="white-space:normal; overflow-y:auto; max-height:220px;"></span>
        <button onclick="closeRecycleAlertBubble()" class="daily-bubble-close" title="Dismiss">
            <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
        </button>`;
    claim.parentElement.appendChild(b);
    return b;
}

// Stack under the store comment and/or claim bubble when they're visible.
function _positionRecycleAlert() {
    const b = document.getElementById('recycleAlertBubble');
    if (b) {
        let top = 116;
        ['dailyMessageBubble', 'claimAlertBubble'].forEach(id => {
            const el = document.getElementById(id);
            if (el && getComputedStyle(el).display !== 'none' && el.offsetHeight > 0) {
                top = Math.max(top, el.getBoundingClientRect().bottom + 12);
            }
        });
        b.style.top = top + 'px';
    }
    // The variance bubble sits below this one — re-flow it whenever this moves.
    if (typeof _positionVarianceAlert === 'function') _positionVarianceAlert();
}

function closeRecycleAlertBubble() {
    const b = document.getElementById('recycleAlertBubble');
    if (b) b.style.display = 'none';
}

function _recycleRenderBubble(icon, title, bodyText, summary, stores) {
    const b = _recycleBubbleEl();
    if (!b) return;
    const iconEl = document.getElementById('recycleAlertBubbleIcon');
    const textEl = document.getElementById('recycleAlertBubbleText');
    // Feed one-liner. Without this the Action Menu scrapes the bubble and repeats
    // the title, which is already the feed row's own title ("Recycle review").
    // The body alone is the useful part.
    textEl.dataset.summary = String(summary || bodyText).replace(/\s+/g, ' ').trim();
    // Stores this alert covers → routes an MSM single-store click (see
    // _samGatherReminders).
    if (stores && stores.length) textEl.dataset.stores = [...new Set(stores.map(s => String(s).toUpperCase()))].join(',');
    else delete textEl.dataset.stores;
    if (iconEl) iconEl.textContent = icon;
    textEl.style.display = 'flex';
    textEl.style.flexDirection = 'column';
    textEl.style.gap = '7px';
    textEl.innerHTML = `
        <div style="line-height:1.4;"><strong>${escapeHtml(title)}</strong></div>
        <div style="line-height:1.4; opacity:0.96;">${escapeHtml(bodyText)}</div>
        <button onclick="closeRecycleAlertBubble(); toggleRecycleInventory(); switchRecycleTab('view');"
            style="align-self:flex-start; background:rgba(255,255,255,0.18); border:1px solid rgba(255,255,255,0.5); color:#fff; font-weight:800; font-size:12px; border-radius:8px; padding:6px 12px; cursor:pointer;"
            onmouseover="this.style.background='rgba(255,255,255,0.3)';" onmouseout="this.style.background='rgba(255,255,255,0.18)';">Open Recycle Requests</button>`;
    b.style.display = 'flex';
    _positionRecycleAlert();
    // Re-stack shortly after: the store-comment bubble fades in on its own
    // 1.5s timer and the claim bubble may land on a later check.
    setTimeout(_positionRecycleAlert, 2200);
    b.animate([
        { transform: 'scale(0.95) translateX(10px)', opacity: 0 },
        { transform: 'scale(1) translateX(0)', opacity: 1 }
    ], { duration: 400, easing: 'cubic-bezier(0.4, 0, 0.2, 1)' });
}

async function deleteRecycleRequest(id) {
    if (!confirm('Delete this recycle request?')) return;
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'delete_request', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        fetchMyRecycleRequests();
    } catch (e) {
        alert('Could not delete: ' + e.message);
    }
}

// =========================================================
//  MONTH-END RECYCLE REPORT EMAIL (DM/CEO) — one email at the start of the
//  month covering every store's total recycled cost for the selected month,
//  broken down by verdict. Mimics the Box Order tool: Send Email opens the
//  machine's mail service with the report prefilled (nothing auto-sends, so
//  the email goes out from the DM's own mailbox and replies come back to
//  them); the Copy button is the failsafe for machines with no mail client.
// =========================================================
// =========================================================
//  EMAIL RECIPIENTS (DB-driven, shared by every emailing tool)
//  One cache for all recipient lists (email_recipients table via the
//  email-recipients fn): the recycle month-end report, per-store box-order
//  suppliers, and — server-side — the weekly SPEEKS report emails. Each tool
//  keeps its hardcoded list as a fallback for when the fetch hasn't landed.
//  DM/CEO manage the lists in the 📧 Email Recipients tool below.
// =========================================================
let _emailLists = null;

async function _fetchEmailLists(force = false) {
    if (_emailLists && !force) return _emailLists;
    try {
        const r = await fetch(`${EMAIL_RECIPIENTS_URL}?v=${Date.now()}`).then(x => x.json());
        if (r && r.lists) _emailLists = r.lists;
    } catch (e) { /* keep whatever we have — callers fall back */ }
    return _emailLists;
}

function _recipientsFor(key, fallback) {
    const list = _emailLists && _emailLists[key];
    return (list && list.length) ? list.slice() : (fallback || []).slice();
}

// ---- the DM/CEO management tool ----
const EMAIL_LIST_STORES = ['OVL', 'LEE', 'WSP', 'MPL', 'BAL'];
const EMAIL_LIST_GROUPS = [
    {
        title: '♻️ Recycle Month-End Report',
        desc: 'Who the month-end recycle report email is addressed to.',
        lists: [{ key: 'recycle_report', label: 'Recipients' }],
    },
    {
        title: '📦 Box Orders',
        desc: 'Supplier address each store\'s box order email opens to.',
        lists: EMAIL_LIST_STORES.map(s => ({ key: `box_order_${s}`, label: s })),
    },
    {
        title: '📈 Weekly SPEEKS Reports',
        desc: 'Monday morning performance emails (sent automatically).',
        lists: [
            { key: 'weekly_leadership', label: 'Leadership report' },
            ...EMAIL_LIST_STORES.map(s => ({ key: `weekly_store_${s}`, label: `${s} manager report` })),
        ],
    },
];

async function openEmailRecipients() {
    closeAllModals();
    toggleModal('emailRecipientsModal');
    const body = document.getElementById('emailRecipientsBody');
    if (body) body.innerHTML = '<div class="status-message">Loading recipients…</div>';
    await _fetchEmailLists(true);
    renderEmailRecipients();
}

function renderEmailRecipients() {
    const body = document.getElementById('emailRecipientsBody');
    if (!body) return;
    if (!_emailLists) {
        body.innerHTML = '<div style="color: var(--red-alert); font-weight: bold; text-align: center; padding: 20px 0;">Could not load recipients. Close and try again.</div>';
        return;
    }

    let html = `<p style="font-size: 12.5px; color: #64748b; margin: 0 0 14px;">
        These lists control where each tool's emails go. Changes apply immediately —
        the recycle report and box orders read them when composing, and the weekly
        report reads them on every send.</p>`;

    EMAIL_LIST_GROUPS.forEach(group => {
        html += `<div style="margin-bottom: 18px;">
            <div style="font-size: 13.5px; font-weight: 900; color: var(--slate-charcoal);">${group.title}</div>
            <div style="font-size: 11.5px; color: #94a3b8; font-weight: 600; margin: 1px 0 8px;">${group.desc}</div>`;
        group.lists.forEach(l => {
            const emails = _recipientsFor(l.key, []);
            const chips = emails.length
                ? emails.map(e => `<span style="display: inline-flex; align-items: center; gap: 6px; background: #f1f5f9; border: 1px solid #e2e8f0; border-radius: 999px; padding: 3px 6px 3px 10px; font-size: 12px; font-weight: 700; color: var(--slate-charcoal); margin: 0 6px 6px 0;">
                        ${escapeHtml(e)}
                        <button data-key="${escapeHtml(l.key)}" data-email="${escapeHtml(e)}" onclick="emailRecipientRemove(this.dataset.key, this.dataset.email)" title="Remove" style="border: none; background: #e2e8f0; color: #64748b; width: 18px; height: 18px; border-radius: 50%; font-size: 11px; font-weight: 900; cursor: pointer; line-height: 1;">✕</button>
                    </span>`).join('')
                : '<span style="font-size: 12px; color: #94a3b8; font-weight: 600; margin-right: 6px;">None — the built-in default applies.</span>';
            const inputId = `email-add-${l.key}`;
            html += `<div style="border: 1px solid #e2e8f0; border-radius: 10px; padding: 10px 12px; margin-bottom: 8px;">
                <div style="font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: .4px; color: #64748b; margin-bottom: 7px;">${escapeHtml(l.label)}</div>
                <div>${chips}</div>
                <div style="display: flex; gap: 6px; margin-top: 6px;">
                    <input type="email" id="${inputId}" placeholder="name@company.com" style="flex: 1; border: 1px solid #e2e8f0; border-radius: 8px; padding: 6px 10px; font-size: 12.5px;"
                        onkeydown="if(event.key==='Enter'){event.preventDefault(); emailRecipientAdd('${l.key}', '${inputId}', this.nextElementSibling);}">
                    <button class="btn-secondary" style="padding: 6px 14px; font-size: 12px;" onclick="emailRecipientAdd('${l.key}', '${inputId}', this)">+ Add</button>
                </div>
            </div>`;
        });
        html += `</div>`;
    });
    body.innerHTML = html;
}

async function _emailRecipientsPost(payload) {
    const pin = sessionStorage.getItem('speeksUserPin') || '';
    const r = await fetch(EMAIL_RECIPIENTS_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-user-pin': pin },
        body: JSON.stringify(payload),
    });
    return r.json();
}

async function emailRecipientAdd(listKey, inputId, btn) {
    const input = document.getElementById(inputId);
    const email = (input?.value || '').trim();
    if (!email) return;
    if (btn) btn.disabled = true;
    const res = await _emailRecipientsPost({ action: 'add', list_key: listKey, email }).catch(() => null);
    if (btn) btn.disabled = false;
    if (res && res.success) { await _fetchEmailLists(true); renderEmailRecipients(); }
    else alert((res && res.error) || 'Could not add — please try again.');
}

async function emailRecipientRemove(listKey, email) {
    if (!confirm(`Remove ${email} from this list?`)) return;
    const res = await _emailRecipientsPost({ action: 'remove', list_key: listKey, email }).catch(() => null);
    if (res && res.success) { await _fetchEmailLists(true); renderEmailRecipients(); }
    else alert((res && res.error) || 'Could not remove — please try again.');
}

// FALLBACK only — the live list comes from the email_recipients table (key
// 'recycle_report'), editable in the DM's Email Recipients tool.
const RECYCLE_REPORT_EMAILS = ['paul.kushnir@pikinvestments.com', 'dave.chaffin@pikinvestments.com'];
function _recycleReportTo() { return _recipientsFor('recycle_report', RECYCLE_REPORT_EMAILS); }

// Hover "i" (site-standard goals-info-i tooltip) explaining what Send Email
// does and how to fix a machine where mailto: links open nothing.
const RECYCLE_MAIL_TIP = `<span class="goals-info-i" style="align-self:center;" data-tip-title="Send Email opens your mail app" data-tip-desc="Clicking Send Email opens your computer's default email app with the report pre-filled — nothing sends until you hit Send there. If nothing opens: go to Windows Settings → Apps → Default apps → scroll to Choose defaults by link type → set MAILTO to Outlook (or your mail app). Or click 📋 Copy and paste the report into any email.">i</span>`;

function _recycleReportCompose() {
    const month = (document.getElementById('recycle-month-filter') || {}).value || _recycleMonthKey(new Date());
    const monthLabel = _recycleMonthLabel(month);
    const rows = _recycleMine.filter(r => _recycleMonthKey(r.created_at) === month);
    const userName = sessionStorage.getItem('speeksUserName') || '';
    const sum = list => list.reduce((a, r) => a + (_recycleLineTotal(r) || 0), 0);

    let unreviewed = 0, grandCounted = 0, grandAgainst = 0, grandFor = 0;
    const sections = RECYCLE_STORES.map(s => {
        const sRows = rows.filter(r => (r.store || '').toUpperCase() === s);
        const name = BOX_STORE_NAMES[s] || s;
        if (!sRows.length) return `${s} - ${name}\n  No recycle requests this month.`;
        const counted = sum(sRows.filter(r => r.review_verdict !== 'ignore' && r.review_verdict !== 'denied'));
        const against = sum(sRows.filter(r => r.review_verdict === 'against'));
        const forUse  = sum(sRows.filter(r => r.review_verdict === 'for'));
        const ignored = sum(sRows.filter(r => r.review_verdict === 'ignore'));
        const denied  = sum(sRows.filter(r => r.review_verdict === 'denied'));
        unreviewed += sRows.filter(r => !r.reviewed_at).length;
        grandCounted += counted; grandAgainst += against; grandFor += forUse;
        let block = `${s} - ${name}\n  Total Recycled Cost: ${_fmtRecycleMoney(counted)}\n` +
            `    - Recycled out of inventory (against the store): ${_fmtRecycleMoney(against)}\n` +
            `    - Repurposed for store use: ${_fmtRecycleMoney(forUse)}`;
        if (ignored) block += `\n    - Not counted (cost consolidated into another SKU): ${_fmtRecycleMoney(ignored)}`;
        if (denied) block += `\n    - Not counted (request denied, item kept in inventory): ${_fmtRecycleMoney(denied)}`;
        return block;
    });

    const warn = unreviewed
        ? `\n\nNOTE: ${unreviewed} line item${unreviewed === 1 ? ' has' : 's have'} not been reviewed yet - ` +
          `their cost is included in the store totals but not in the breakdowns.`
        : '';
    const body = `Hi,\n\nHere is the recycled inventory report for ${monthLabel}:\n\n` +
        sections.join('\n\n') +
        `\n\nAll Stores Combined: ${_fmtRecycleMoney(grandCounted)}\n` +
        `    - Recycled out of inventory: ${_fmtRecycleMoney(grandAgainst)}\n` +
        `    - Repurposed for store use: ${_fmtRecycleMoney(grandFor)}${warn}\n\n` +
        `Thank you,\n${userName}`;
    return {
        email: _recycleReportTo().join(','),
        subject: `PayMore Recycle Report - ${monthLabel}`,
        body,
    };
}

// Open the machine's mail service with the report prefilled — same mechanism
// as sendBoxOrder. Nothing sends until the DM hits send in their mail app.
// Recipients are joined with ';' — Outlook rejects the whole mailto link when
// multiple addresses are comma-separated (the RFC separator), so don't "fix"
// this back to ','.
function sendRecycleReport() {
    const { subject, body } = _recycleReportCompose();
    const to = _recycleReportTo().join(';');
    window.location.href = `mailto:${to}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
}

// Same copy failsafe as the Box Order tool, same button flash. Copies just
// the report body — recipient and subject get filled in by hand.
function copyRecycleReport(button) {
    const { body } = _recycleReportCompose();
    navigator.clipboard.writeText(body).then(() => {
        const originalText = button.innerText;
        button.innerText = 'Copied!';
        button.style.background = '#d1fae5';
        button.style.color = '#065f46';
        button.style.borderColor = '#34d399';
        setTimeout(() => {
            button.innerText = originalText;
            button.style.background = '';
            button.style.color = '';
            button.style.borderColor = '';
        }, 2000);
    }).catch(() => alert('Could not copy automatically. Please select and copy the report manually.'));
}

// Review / clear a line (DM/CEO, from the My Requests tab). verdict is
// 'against' (truly recycled out of inventory), 'for' (tool for store use),
// 'ignore' (cost consolidated into another SKU — excluded from totals) or
// '' to clear the review. Updates the local cache and re-renders so the
// scroll position and month stay put.
async function setRecycleReviewed(id, verdict) {
    const reviewed = ['for', 'against', 'ignore', 'denied'].includes(verdict);
    try {
        const res = await fetch(RECYCLE_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'set_reviewed', id, reviewed,
                verdict: reviewed ? verdict : null,
                reviewed_by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        const row = _recycleMine.find(r => r.id === id);
        if (row) {
            row.reviewed_at = reviewed ? new Date().toISOString() : null;
            row.reviewed_by = reviewed ? (sessionStorage.getItem('speeksUserName') || null) : null;
            row.review_verdict = reviewed ? verdict : null;
        }
        renderMyRecycleTable();
        // Reviewing IS the work the DM alert nags about, so recompute it now: the
        // row drops when the last one's done, or updates its count if some remain.
        if (typeof checkRecycleReminders === 'function') checkRecycleReminders();
    } catch (e) {
        alert('Could not update: ' + e.message);
        fetchMyRecycleRequests();
    }
}

