// The settings UI only lets you toggle a feature that's in the list above — but
// enforcement is DOM-driven, so ANY element tagged data-feature is already
// controllable in effect. To keep the two from drifting (and so a newly-tagged
// element shows up in this tool automatically, without anyone editing the
// catalog), the tool renders from _faCatalog(): the curated list above merged
// with every data-feature found in the live DOM. Curated entries win (nice
// label/group/defaults); anything else is auto-derived into an "Uncatalogued"
// group so it's still togglable the moment it's added to the page.
function _faCatalog() {
    const byKey = {};
    FEATURE_CATALOG.forEach(f => { byKey[f.key] = true; });
    const merged = FEATURE_CATALOG.slice();
    // 1) anything tagged on THIS page
    document.querySelectorAll('[data-feature]').forEach(el => {
        const key = el.getAttribute('data-feature');
        if (!key || byKey[key]) return;
        byKey[key] = true; // dedupe repeats of the same key across the page
        merged.push(_faDeriveEntry(key, el));
    });
    // 2) anything tagged on the OTHER shell pages (scanned by _faScanPages when
    //    the tool opens) so you see the whole site's features from any page
    _faRemoteFeatures.forEach(entry => {
        if (byKey[entry.key]) return;
        byKey[entry.key] = true;
        merged.push(entry);
    });
    return merged;
}

// The tool can be opened from any of the 5 shells, but the DOM only holds the
// current page's features. So when it loads, fetch the sibling shells (static,
// same-origin) and read their data-feature tags directly — that's how a feature
// living only on Operations shows up while you're on QuickPortal. Runs once per
// open; results feed _faCatalog() via _faRemoteFeatures.
const _FA_SHELLS = ['index.html', 'workspace.html', 'operations.html', 'docs.html', 'stats.html'];
let _faRemoteFeatures = [];
let _faScanned = false;

async function _faScanPages() {
    const here = (location.pathname.split('/').pop() || 'index.html').toLowerCase() || 'index.html';
    const known = {};
    FEATURE_CATALOG.forEach(f => { known[f.key] = true; });
    document.querySelectorAll('[data-feature]').forEach(el => { known[el.getAttribute('data-feature')] = true; });
    const found = {};
    await Promise.all(_FA_SHELLS.filter(p => p !== here).map(async page => {
        try {
            const html = await fetch(`${page}?v=${Date.now()}`).then(r => r.text());
            const doc = new DOMParser().parseFromString(html, 'text/html');
            doc.querySelectorAll('[data-feature]').forEach(el => {
                const key = el.getAttribute('data-feature');
                if (!key || known[key] || found[key]) return;
                found[key] = _faDeriveEntry(key, el);
            });
        } catch (_) { /* a page that won't load just contributes no features */ }
    }));
    _faRemoteFeatures = Object.values(found);
    _faScanned = true;
    if (_faRemoteFeatures.length) {
        console.info('[Feature Access] discovered un-catalogued feature(s) on other pages — add FEATURE_CATALOG entries for tidy labels:', _faRemoteFeatures.map(f => f.key));
    }
}

// Best-effort metadata for a data-feature key that isn't in FEATURE_CATALOG:
// bucket by key prefix, default visibility from the element's own role-* classes
// (exactly what enforcement reads when there's no override), label from its text.
function _faDeriveEntry(key, el) {
    let tab = 'widgets';
    if (key.startsWith('tool-')) tab = 'tools';
    else if (key.startsWith('hb-')) tab = 'hotbar';
    const roles = Array.from(el.classList)
        .filter(c => c.startsWith('role-')).map(c => c.slice(5));
    // ASM inherits the employee default the same way enforcement does
    if (roles.includes('employee') && !roles.includes('assistant-manager')) roles.push('assistant-manager');
    const def = roles.length ? roles : 'all';
    let label = (el.textContent || '').replace(/\s+/g, ' ').trim();
    if (!label || label.length > 44) {
        label = key.replace(/^(tool|hb|widget|nav)-/, '').replace(/-/g, ' ')
            .replace(/\b\w/g, c => c.toUpperCase());
    }
    return { key, label, tab, group: '✨ Uncatalogued', def, _auto: true };
}

// ---- runtime override state ------------------------------------------------
let _featureOv = { role: {}, user: {} };  // resolved lookup maps
let _featureOvRaw = [];                    // raw rows (settings UI needs subjects)
(function () {
    try {
        const cached = JSON.parse(localStorage.getItem('speeksFeatureOv') || 'null');
        if (cached && cached.role && cached.user) _featureOv = cached;
    } catch (e) { /* corrupt cache — defaults apply until the refresh lands */ }
})();

function _buildFeatureOvMaps(rows) {
    const maps = { role: {}, user: {} };
    (rows || []).forEach(r => {
        const bucket = maps[r.subject_type];
        if (!bucket) return;
        (bucket[r.feature_key] = bucket[r.feature_key] || {})[String(r.subject).toLowerCase()] = !!r.enabled;
    });
    return maps;
}

function _featureOverrideFor(featureKey, userRoleClass, userName) {
    // The Feature Access tool can never be hidden from a District Manager —
    // it's the tool that undoes bad overrides (the backend blocks this too).
    if (featureKey === 'tool-feature-access' && userRoleClass === 'role-district-manager') return null;
    const byUser = _featureOv.user[featureKey];
    const name = String(userName || '').trim().toLowerCase();
    if (byUser && Object.prototype.hasOwnProperty.call(byUser, name)) return byUser[name];
    const byRole = _featureOv.role[featureKey];
    const roleSlug = String(userRoleClass || '').replace(/^role-/, '');
    if (byRole && Object.prototype.hasOwnProperty.call(byRole, roleSlug)) return byRole[roleSlug];
    return null;
}

// Effective visibility of a feature key for this user: an override wins, else
// the catalog default for their role (mirroring enforcement, incl. the
// ASM-inherits-employee rule). Used to derive section nav visibility.
function _featureEffectiveVisible(featureKey, userRoleClass, userName) {
    const ov = _featureOverrideFor(featureKey, userRoleClass, userName);
    if (ov !== null) return ov;
    const feat = FEATURE_CATALOG.find(f => f.key === featureKey);
    if (!feat) return false;
    if (feat.def === 'all') return true;
    const slug = String(userRoleClass || '').replace(/^role-/, '');
    if (feat.def.includes(slug)) return true;
    if (slug === 'assistant-manager' && feat.def.includes('employee')) return true;
    return false;
}

// Tabbed sections keyed by their nav-link href → the sub-tab feature keys they
// contain. A section's nav link shows if ANY of its sub-tabs is visible.
const _SECTION_TABS = {
    'workspace.html': ['widget-ws-monthly-breakdown', 'widget-ws-weekly-kpis', 'widget-variance-replies', 'widget-aging-inventory'],
    'operations.html': ['widget-ops-callbacks'],
};

function _applySectionNavVisibility(userRoleClass, userName) {
    Object.keys(_SECTION_TABS).forEach(href => {
        const link = document.querySelector(`.nav-bar a.nav-link[href="${href}"]`);
        if (!link) return;
        const vis = _SECTION_TABS[href].some(k => _featureEffectiveVisible(k, userRoleClass, userName));
        link.style.setProperty('display', vis ? 'flex' : 'none', 'important');
    });
}

// Overrides on plain (non role-gated) elements — e.g. individual hotbar links,
// which normally just inherit their bar's visibility. Only "off" does work
// here; "on" simply falls back to the inherited default.
function _applyFeatureOverridesToPlainEls(userRoleClass, userName) {
    document.querySelectorAll('[data-feature]').forEach(el => {
        if (el.classList.contains('dynamic-module') || el.classList.contains('dynamic-module-flex') || el.classList.contains('dynamic-module-block')) return;
        const ov = _featureOverrideFor(el.getAttribute('data-feature'), userRoleClass, userName);
        if (ov === false) el.style.setProperty('display', 'none', 'important');
        else el.style.removeProperty('display');
    });
}

// Surface force-enabled hotbar links that live inside bars this user doesn't
// see. Enabling EVERY link of a bar shows the real bar; enabling just some
// appends those links to the user's main (first visible) hotbar — one
// borrowed link never drags in a whole foreign hotbar. A standalone EXTRAS
// bar is only created for users who have no visible hotbar to attach to.
function _syncHotbarExtras(userRoleClass, userName) {
    const stack = document.querySelector('.hotbars-stack');
    if (!stack) return; // hotbars only exist on the dashboard
    // rebuild from scratch on every apply
    stack.querySelectorAll('.hotbar-extra-clone').forEach(c => c.remove());
    const oldBar = document.getElementById('hotbarExtras');
    if (oldBar) oldBar.remove();

    const extras = []; // [{ a, barLabel }]
    stack.querySelectorAll('.hotbar-wrapper').forEach(wrap => {
        if (wrap.id === 'hotbarExtras') return;
        const links = Array.from(wrap.querySelectorAll('.hotbar-btn[data-feature]'));
        if (!links.length) return;
        if (wrap.style.display !== 'none') return; // visible bars: the plain-els pass already handled their links
        const enabled = links.filter(a => _featureOverrideFor(a.getAttribute('data-feature'), userRoleClass, userName) === true);
        if (!enabled.length) return;
        if (enabled.length === links.length) {
            // the entire bar was granted → show it as itself
            wrap.style.setProperty('display', 'flex', 'important');
        } else {
            const labelEl = wrap.querySelector('.hotbar-label');
            const barLabel = labelEl ? String(labelEl.textContent || '').trim() : '';
            enabled.forEach(a => extras.push({ a, barLabel }));
        }
    });
    if (!extras.length) return;

    // skip borrowed links whose URL is already visible in one of the user's bars
    const visibleBars = Array.from(stack.querySelectorAll('.hotbar-wrapper'))
        .filter(w => w.id !== 'hotbarExtras' && w.style.display !== 'none');
    const visibleHrefs = new Set();
    visibleBars.forEach(w => {
        w.querySelectorAll('.hotbar-btn[data-feature]').forEach(a => {
            if (a.style.display !== 'none') visibleHrefs.add(a.getAttribute('href'));
        });
    });
    const fresh = extras.filter(e => !visibleHrefs.has(e.a.getAttribute('href')));
    if (!fresh.length) return;

    // Borrowed links from a DIFFERENT store's bar carry a small store badge
    // (e.g. Nick at OVL borrowing WSP's Passwords sees "Passwords · WSP") so
    // nobody opens another store's sheet thinking it's their own. Role-bar
    // borrows (CEO/DM/TOM/MGR/ASM/Resources) are company links — no badge.
    const STORE_BAR_LABELS = ['OVL', 'LEE', 'WSP', 'MPL', 'BAL'];
    const userStore = (sessionStorage.getItem('speeksUserStore') || '').toUpperCase();
    const makeClone = ({ a, barLabel }) => {
        const clone = a.cloneNode(true);
        // the clone is display-only; the hidden original stays the canonical
        // override target, so strip the key to avoid double-processing
        clone.removeAttribute('data-feature');
        clone.style.removeProperty('display');
        clone.classList.add('hotbar-extra-clone');
        const src = String(barLabel || '').toUpperCase();
        if (STORE_BAR_LABELS.includes(src) && src !== userStore) {
            const badge = document.createElement('span');
            badge.className = 'hotbar-src-badge';
            badge.textContent = src;
            clone.appendChild(badge);
        }
        return clone;
    };

    // append to the user's main (first visible) hotbar
    const host = visibleBars[0];
    const hostLinks = host ? host.querySelector('.hotbar-links') : null;
    if (hostLinks) {
        fresh.forEach(e => hostLinks.appendChild(makeClone(e)));
        return;
    }

    // no visible bar to attach to → standalone EXTRAS bar as a fallback
    const div = document.createElement('div');
    div.id = 'hotbarExtras';
    div.className = 'hotbar-wrapper';
    div.style.display = 'flex';
    const inner = document.createElement('div');
    inner.className = 'hotbar-container';
    const label = document.createElement('span');
    label.className = 'hotbar-label';
    label.textContent = 'EXTRAS';
    const linksDiv = document.createElement('div');
    linksDiv.className = 'hotbar-links';
    fresh.forEach(e => linksDiv.appendChild(makeClone(e)));
    inner.appendChild(label);
    inner.appendChild(linksDiv);
    div.appendChild(inner);
    stack.appendChild(div);
}

// Rebalance dashboard card rows where a Feature Access override hid a card
// (marked data-fa-hidden in the module pass). Rows the overrides didn't touch
// keep their designed layout — e.g. managers see two 33%-wide cards in the
// main row by default, and that must not change. When an override DID remove
// a card: 2 remaining cards split the row 50/50, a lone card sits centered at
// half width, and a fully-emptied row disappears. The mobile media queries
// use !important full-width rules, so phones stack cards exactly as before.
function _rebalanceDashboardRows() {
    document.querySelectorAll('.employee-dashboard-row, .top-alerts-row').forEach(row => {
        const cards = Array.from(row.children).filter(c => c.classList && c.classList.contains('employee-widget-card'));
        if (!cards.length) return;
        // reset any previous rebalance before recomputing
        cards.forEach(c => { c.style.removeProperty('flex'); c.style.removeProperty('max-width'); });
        row.style.removeProperty('justify-content');
        if (!cards.some(c => c.hasAttribute('data-fa-hidden'))) return;
        const visible = cards.filter(c => c.style.display !== 'none');
        if (!visible.length) { row.style.setProperty('display', 'none', 'important'); return; }
        if (visible.length === 2) {
            visible.forEach(c => {
                c.style.setProperty('flex', '1 1 calc(50% - 15px)');
                c.style.setProperty('max-width', 'calc(50% - 15px)');
            });
        } else if (visible.length === 1) {
            visible[0].style.setProperty('flex', '0 1 50%');
            visible[0].style.setProperty('max-width', '50%');
            row.style.setProperty('justify-content', 'center');
        }
        // 3+ visible: the designed 33% layout already fits
    });
}

// The SPEEKS Tools button/panel/groups follow whatever is actually visible
// inside the panel, so overrides can add or remove tools for any role without
// the static role-class unions drifting out of sync.
function _syncToolsPanelChrome() {
    const panel = document.getElementById('toolsSidePanel');
    if (!panel) return;
    let anyVisible = false;
    panel.querySelectorAll('.tools-group').forEach(g => {
        const vis = Array.from(g.querySelectorAll('.tools-item')).some(a => a.style.display !== 'none');
        g.style.setProperty('display', vis ? 'block' : 'none', 'important');
        if (vis) anyVisible = true;
    });
    panel.style.setProperty('display', anyVisible ? 'flex' : 'none', 'important');
    const btn = document.getElementById('toolsNavBtn');
    if (btn) btn.style.setProperty('display', anyVisible ? 'flex' : 'none', 'important');
    if (!anyVisible && typeof _closeToolsPanel === 'function') _closeToolsPanel();
}

let _featureOvRefreshStarted = false;
function _kickFeatureOverridesRefresh() {
    if (_featureOvRefreshStarted) return;
    _featureOvRefreshStarted = true;
    fetch(`${FEATURE_ACCESS_URL}?v=${Date.now()}`).then(r => r.json()).then(json => {
        if (!json || json.success === false) return;
        _featureOvRaw = json.data || [];
        const next = _buildFeatureOvMaps(_featureOvRaw);
        const changed = JSON.stringify(next) !== JSON.stringify(_featureOv);
        _featureOv = next;
        localStorage.setItem('speeksFeatureOv', JSON.stringify(next));
        if (changed) applyRoleBasedUI();
    }).catch(() => {});
}

// ---- Feature Access settings modal ------------------------------------------
let _faTab = 'tools';
let _faUser = '';    // selected user (lowercased name) on the Per-User tab
let _faUsers = [];   // [{name, role, store}] from the auth directory
let _faFilter = '';

function openFeatureAccess() {
    toggleModal('featureAccessModal');
    _faTab = 'tools';
    _faFilter = '';
    _faSyncTabButtons();
    const body = document.getElementById('fa-body');
    if (body) body.innerHTML = '<div class="status-message">Loading…</div>';
    _faLoad();
}

async function _faLoad() {
    try {
        const [ovJson] = await Promise.all([
            fetch(`${FEATURE_ACCESS_URL}?v=${Date.now()}`).then(r => r.json()),
            _faLoadUsers(),
        ]);
        if (!ovJson || ovJson.success === false) throw new Error((ovJson && ovJson.error) || 'Load failed');
        _featureOvRaw = ovJson.data || [];
        _featureOv = _buildFeatureOvMaps(_featureOvRaw);
        localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
        renderFaBody();
        applyRoleBasedUI();
        // Pull in features that live on the other shell pages, then re-render so
        // they appear no matter which page the tool was opened from. Cached for
        // the session so re-opening is instant.
        if (!_faScanned) { await _faScanPages(); renderFaBody(); }
    } catch (e) {
        const body = document.getElementById('fa-body');
        if (body) body.innerHTML = '<div class="status-message" style="color:var(--red-alert);">Failed to load feature settings.</div>';
    }
}

async function _faLoadUsers() {
    if (_faUsers.length) return _faUsers;
    try {
        let data = null;
        try { data = JSON.parse(localStorage.getItem('speeksAuthCache') || 'null'); } catch (e) { /* refetch below */ }
        if (!data || !Array.isArray(data.users)) {
            const res = await fetch(`${AUTH_URL}?v=${Date.now()}`);
            data = await res.json();
        }
        _faUsers = (data.users || []).filter(u => u && u.name)
            .sort((a, b) => String(a.name).localeCompare(String(b.name)));
    } catch (e) { _faUsers = []; }
    return _faUsers;
}

function switchFaTab(tab) {
    _faTab = tab;
    _faSyncTabButtons();
    renderFaBody();
}

function _faSyncTabButtons() {
    ['tools', 'hotbar', 'widgets', 'user', 'coverage'].forEach(t => {
        const b = document.getElementById('fa-tab-' + t);
        if (b) b.classList.toggle('active', t === _faTab);
    });
}

function _faDefaultFor(feat, roleSlug) {
    return feat.def === 'all' ? true : feat.def.includes(roleSlug);
}

function _faRoleOverride(key, slug) {
    const m = _featureOv.role[key];
    return (m && Object.prototype.hasOwnProperty.call(m, slug)) ? m[slug] : null;
}

function _faUserOverride(key, name) {
    const m = _featureOv.user[key];
    return (m && Object.prototype.hasOwnProperty.call(m, name)) ? m[name] : null;
}

function renderFaBody() {
    const body = document.getElementById('fa-body');
    if (!body) return;
    body.innerHTML = _faTab === 'user' ? _faUserTabHtml()
        : _faTab === 'coverage' ? _faCoverageHtml()
        : _faMatrixHtml(_faTab);
}

function _faMatrixHtml(tab) {
    const feats = _faCatalog().filter(f => f.tab === tab);
    const hints = {
        tools: 'Click a chip to force a tool on (✓) or off (✕) for that role — an amber ring means it\'s manually overridden; click again to flip it back (matching the default clears the override). Per-user exceptions on the Per-User tab beat these.',
        hotbar: 'OFF always hides a link. Turning a link ON for a role/user that doesn\'t normally see its bar adds it to the end of their main hotbar — and if you enable every link of a bar, the whole bar shows up instead. Store-bar links (LEE…BAL) default to everyone in that store.',
        widgets: 'Dashboard cards and sidebar panels. Same rules as tools: per-user exceptions beat these role settings.',
    };
    let html = `<div style="font-size:12px; color:#64748b; font-weight:600; margin-bottom:12px; line-height:1.5;">${hints[tab] || ''}</div>`;
    const headerRow = `<div style="display:flex; align-items:center; gap:6px; padding:0 2px; margin-bottom:2px;">
        <span style="flex:1;"></span>
        ${FA_ROLES.map(r => `<span title="${r.label}" style="width:38px; text-align:center; font-size:9px; font-weight:800; color:#94a3b8; letter-spacing:.3px; flex-shrink:0;">${r.short}</span>`).join('')}
    </div>`;
    let lastGroup = '';
    feats.forEach(f => {
        if (f.group !== lastGroup) {
            lastGroup = f.group;
            html += `<div style="font-size:10.5px; font-weight:800; text-transform:uppercase; letter-spacing:.5px; color:#94a3b8; margin:16px 2px 4px;">${f.group}</div>${headerRow}`;
        }
        html += `<div style="display:flex; align-items:center; gap:6px; padding:4px 2px; border-bottom:1px solid #f1f5f9;">
            <span style="flex:1; font-size:12.5px; font-weight:700; color:var(--slate-charcoal);">${f.label}</span>
            ${FA_ROLES.map(r => _faChipHtml(f, r)).join('')}
        </div>`;
    });
    return html;
}

function _faChipHtml(f, role) {
    const def = _faDefaultFor(f, role.slug);
    const ovr = _faRoleOverride(f.key, role.slug);
    const eff = ovr === null ? def : ovr;
    const locked = f.key === 'tool-feature-access' && role.slug === 'district-manager';
    const title = locked
        ? 'Always on for District Managers (safety lock)'
        : `${role.label}: ${eff ? 'visible' : 'hidden'}${ovr !== null ? ' (overridden)' : ' (default)'} — click to ${eff ? 'hide' : 'show'}`;
    return `<button class="fa-chip ${eff ? 'fa-on' : 'fa-off'}${ovr !== null ? ' fa-ovr' : ''}"${locked ? ' disabled' : ''} onclick="faToggleRole('${f.key}', '${role.slug}')" title="${escapeHtml(title)}">${locked ? '🔒' : (eff ? '✓' : '✕')}</button>`;
}

async function faToggleRole(key, slug) {
    const feat = _faCatalog().find(f => f.key === key);
    if (!feat) return;
    const def = _faDefaultFor(feat, slug);
    const cur = _faRoleOverride(key, slug);
    const eff = cur === null ? def : cur;
    const next = !eff;
    const clearing = next === def; // back to default → remove the override row
    const m = (_featureOv.role[key] = _featureOv.role[key] || {});
    if (clearing) delete m[slug]; else m[slug] = next;
    if (!Object.keys(m).length) delete _featureOv.role[key];
    _featureOvRaw = _featureOvRaw.filter(r => !(r.subject_type === 'role' && r.feature_key === key && r.subject === slug));
    if (!clearing) _featureOvRaw.push({ feature_key: key, subject_type: 'role', subject: slug, enabled: next });
    localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
    renderFaBody();
    applyRoleBasedUI(); // live-preview on this device
    try {
        const res = await fetch(FEATURE_ACCESS_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'set_override', feature_key: key, subject_type: 'role', subject: slug,
                enabled: clearing ? null : next,
                updated_by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
    } catch (e) {
        alert('Could not save: ' + e.message);
        _faLoad(); // resync with the server's truth
    }
}

// ---- Coverage tab: hand your tools to whoever's covering while you're out ---
// A convenience layer over per-user overrides: pick the managers covering, tick
// the tools to lend them, Grant → writes user overrides (enabled=true) in bulk.
// Their own tools stay (overrides only add), so they see both versions. Manual
// on/off — the "End coverage" buttons revoke. Nothing expires on its own.
const _FA_COVER_ROLES = new Set(['manager', 'owner (manager)', 'owner manager', 'multi-store manager']);

// Features offered for delegation: DM-only SPEEKS Tools + DM-only
// workspace/operations-style section actions (tabs). Explicitly NOT dashboard
// cards or sidebar panels (e.g. District Command Center) — those aren't "DM
// actions" to hand off. Built off _faCatalog() (curated + live DOM + other-page
// scan) and it excludes groups by NAME rather than allow-listing, so a new
// section/group we add later shows up here automatically like the main FA tabs.
// Regular tools managers already have (Insurance Claims store / Box Order /
// Recycle) are filtered out by the manager-default check.
const _FA_NON_DELEGABLE_WIDGET_GROUPS = ['Dashboard', 'Side Panels'];
function _faCoverageTools() {
    return _faCatalog().filter(f =>
        f.key !== 'tool-feature-access'
        && f.def !== 'all' && !f.def.includes('manager')
        && (f.tab === 'tools'
            || (f.tab === 'widgets' && !_FA_NON_DELEGABLE_WIDGET_GROUPS.includes(f.group))));
}
function _faCoverageDefaultChecked() {
    return new Set(); // always start with everything unchecked
}

// A feature is the "DM version" of something managers also have if a sibling
// feature shares its key stem (e.g. tool-claims-oversight ↔ tool-claims-store)
// and that sibling is visible to managers by default. Used to append "(DM)" in
// Delegation so it's clear which version you're lending. Auto-detected (3+ key
// segments), so new DM/manager pairs get the tag with no extra wiring.
function _faManagerCounterpart(f) {
    const parts = f.key.split('-');
    if (parts.length < 3) return null; // need a shared stem like tool-claims-*
    const stem = parts.slice(0, -1).join('-') + '-';
    return _faCatalog().find(o => o.key !== f.key && o.key.startsWith(stem)
        && (o.def === 'all' || (Array.isArray(o.def) && o.def.includes('manager')))) || null;
}
function _faDelegationLabel(f) {
    if (!_faManagerCounterpart(f)) return f.label;
    const base = f.label.replace(/\s*\([^)]*\)\s*$/, '').trim(); // drop a trailing "(...)"
    return `${base} (DM)`;
}

// The users who currently hold a granted tool (enabled user override on a tool),
// grouped by subject → [feature keys]. Powers the "active coverage" list.
function _faActiveCoverage() {
    const byUser = {};
    const toolKeys = new Set(_faCoverageTools().map(f => f.key));
    _featureOvRaw.filter(r => r.subject_type === 'user' && r.enabled === true && toolKeys.has(r.feature_key))
        .forEach(r => { (byUser[String(r.subject).toLowerCase()] = byUser[String(r.subject).toLowerCase()] || []).push(r.feature_key); });
    return byUser;
}

function _faCoverageHtml() {
    const checked = _faCoverageDefaultChecked();
    const covering = _faUsers
        .filter(u => _FA_COVER_ROLES.has(String(u.role || '').toLowerCase().trim()))
        .sort((a, b) => a.name.localeCompare(b.name));
    const labelFor = key => { const f = _faCatalog().find(x => x.key === key); return f ? _faDelegationLabel(f) : key; };

    let html = `<div style="font-size:12px; color:#64748b; font-weight:600; margin-bottom:14px; line-height:1.5;">
        Let a manager use your DM tools — while you're away or just need a hand. Pick who and which tools, then <b>Delegate tools</b>. Their own tools stay; it lasts until you <b>End delegation</b>.</div>`;

    // 1) recipients
    html += `<div style="font-size:10.5px; font-weight:800; text-transform:uppercase; letter-spacing:.5px; color:#94a3b8; margin:4px 2px 6px;">Delegate to</div>`;
    if (!covering.length) {
        html += `<div style="font-size:12px; color:#94a3b8; padding:6px 2px;">No manager-level users found in the directory.</div>`;
    } else {
        html += `<div style="display:flex; flex-wrap:wrap; gap:8px; margin-bottom:16px;">` + covering.map(u => {
            const low = u.name.toLowerCase();
            return `<label class="fa-cover-pick" style="display:inline-flex; align-items:center; gap:7px; border:1.5px solid #e2e8f0; border-radius:9px; padding:7px 11px; font-size:12.5px; font-weight:700; color:var(--slate-charcoal); cursor:pointer;">
                <input type="checkbox" class="fa-cover-user" value="${escapeHtml(low)}" style="width:15px; height:15px; cursor:pointer;">
                ${escapeHtml(u.name)} <span style="font-weight:600; color:#94a3b8;">${escapeHtml(u.store || u.role || '')}</span>
            </label>`;
        }).join('') + `</div>`;
    }

    // 2) tools to lend
    html += `<div style="font-size:10.5px; font-weight:800; text-transform:uppercase; letter-spacing:.5px; color:#94a3b8; margin:4px 2px 6px;">Tools to lend</div>`;
    html += `<div style="display:grid; grid-template-columns:repeat(auto-fill,minmax(230px,1fr)); gap:6px 14px; margin-bottom:16px;">` + _faCoverageTools().map(f => `
        <label style="display:flex; align-items:center; gap:8px; font-size:12.5px; font-weight:600; color:var(--slate-charcoal); cursor:pointer; padding:3px 0;">
            <input type="checkbox" class="fa-cover-tool" value="${f.key}" ${checked.has(f.key) ? 'checked' : ''} style="width:15px; height:15px; cursor:pointer;">
            ${escapeHtml(_faDelegationLabel(f))}
        </label>`).join('') + `</div>`;

    html += `<button class="btn-primary" style="font-size:13px; padding:9px 18px;" onclick="faGrantCoverage(this)">Delegate tools</button>`;

    // 3) active delegations
    const active = _faActiveCoverage();
    const users = Object.keys(active).sort();
    html += `<div style="font-size:10.5px; font-weight:800; text-transform:uppercase; letter-spacing:.5px; color:#94a3b8; margin:22px 2px 6px;">Active delegations</div>`;
    if (!users.length) {
        html += `<div style="font-size:12px; color:#94a3b8; padding:6px 2px;">No one currently has borrowed tools.</div>`;
    } else {
        html += users.map(low => {
            const u = _faUsers.find(x => x.name.toLowerCase() === low);
            const disp = u ? u.name : low;
            const chips = active[low].map(k => `<span style="display:inline-flex; align-items:center; gap:6px; background:#eef2ff; color:#3730a3; font-size:11.5px; font-weight:700; border-radius:7px; padding:3px 8px;">${escapeHtml(labelFor(k))}<button title="Remove this tool" onclick="faRevokeCoverage('${escapeHtml(low)}','${k}')" style="border:none; background:none; color:#6366f1; cursor:pointer; font-weight:800; font-size:13px; line-height:1;">×</button></span>`).join(' ');
            return `<div style="display:flex; align-items:flex-start; gap:10px; justify-content:space-between; padding:8px 2px; border-bottom:1px solid #f1f5f9;">
                <div style="flex:1;"><div style="font-size:12.5px; font-weight:800; color:var(--slate-charcoal); margin-bottom:5px;">${escapeHtml(disp)}${u ? '' : ' <span style=\"font-weight:600;color:#cbd5e1;\">(not in directory)</span>'}</div><div style="display:flex; flex-wrap:wrap; gap:6px;">${chips}</div></div>
                <button class="btn-secondary" style="height:28px; font-size:11.5px; padding:0 11px; border-radius:7px; flex-shrink:0;" onclick="faEndCoverage('${escapeHtml(low)}')">End delegation</button>
            </div>`;
        }).join('');
    }
    return html;
}

// Apply one user override locally + persist to the server. Shared by grant/revoke.
async function _faSetUserOverride(key, userLow, enabled) {
    const m = (_featureOv.user[key] = _featureOv.user[key] || {});
    if (enabled === null) delete m[userLow]; else m[userLow] = enabled;
    if (!Object.keys(m).length) delete _featureOv.user[key];
    _featureOvRaw = _featureOvRaw.filter(r => !(r.subject_type === 'user' && r.feature_key === key && String(r.subject).toLowerCase() === userLow));
    if (enabled !== null) _featureOvRaw.push({ feature_key: key, subject_type: 'user', subject: userLow, enabled });
    const res = await fetch(FEATURE_ACCESS_URL, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'set_override', feature_key: key, subject_type: 'user', subject: userLow, enabled, updated_by: sessionStorage.getItem('speeksUserName') || null }),
    });
    const json = await res.json().catch(() => ({}));
    if (!res.ok || json.success === false) throw new Error((json && json.error) || 'Save failed');
}

async function faGrantCoverage(btn) {
    const body = document.getElementById('fa-body');
    const users = Array.from(body.querySelectorAll('.fa-cover-user:checked')).map(c => c.value);
    const tools = Array.from(body.querySelectorAll('.fa-cover-tool:checked')).map(c => c.value);
    if (!users.length) { alert('Pick at least one manager to delegate to.'); return; }
    if (!tools.length) { alert('Tick at least one tool to lend.'); return; }
    const old = btn.textContent;
    btn.disabled = true; btn.textContent = 'Granting…';
    try {
        for (const userLow of users) {
            for (const key of tools) await _faSetUserOverride(key, userLow, true);
        }
        localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
        renderFaBody();
        applyRoleBasedUI();
    } catch (e) {
        alert('Could not grant coverage: ' + e.message);
        _faLoad();
    } finally {
        btn.disabled = false; btn.textContent = old;
    }
}

async function faRevokeCoverage(userLow, key) {
    try {
        await _faSetUserOverride(key, userLow, null);
        localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
        renderFaBody();
        applyRoleBasedUI();
    } catch (e) { alert('Could not revoke: ' + e.message); _faLoad(); }
}

async function faEndCoverage(userLow) {
    const keys = (_faActiveCoverage()[userLow] || []).slice();
    if (!keys.length) return;
    if (!confirm(`Remove all ${keys.length} borrowed tool(s) from this person?`)) return;
    try {
        for (const key of keys) await _faSetUserOverride(key, userLow, null);
        localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
        renderFaBody();
        applyRoleBasedUI();
    } catch (e) { alert('Could not end coverage: ' + e.message); _faLoad(); }
}

function _faUserTabHtml() {
    const ovCounts = {};
    _featureOvRaw.filter(r => r.subject_type === 'user').forEach(r => {
        const s = String(r.subject).toLowerCase();
        ovCounts[s] = (ovCounts[s] || 0) + 1;
    });
    const names = _faUsers.map(u => u.name);
    Object.keys(ovCounts).forEach(n => {
        if (!names.some(x => x.toLowerCase() === n)) names.push(n); // keep orphaned overrides reachable
    });
    const opts = ['<option value="">Select a user…</option>'].concat(names.map(n => {
        const low = n.toLowerCase();
        const u = _faUsers.find(x => x.name.toLowerCase() === low);
        const meta = u ? ` — ${u.role}${u.store ? ' · ' + u.store : ''}` : ' — (no longer in directory)';
        const cnt = ovCounts[low] ? ` · ${ovCounts[low]} override${ovCounts[low] > 1 ? 's' : ''}` : '';
        return `<option value="${escapeHtml(low)}" ${low === _faUser ? 'selected' : ''}>${escapeHtml(n + meta + cnt)}</option>`;
    }));
    let html = `<div style="font-size:12px; color:#64748b; font-weight:600; margin-bottom:12px; line-height:1.5;">
        Per-user exceptions beat the role settings: force any tool, hotbar link or widget on or off for one person.
        “Default” means the role rules decide.</div>
    <div style="display:flex; gap:10px; flex-wrap:wrap; margin-bottom:14px;">
        <select class="form-input-lg" style="flex:2; min-width:220px; margin-top:0;" onchange="_faUser=this.value; renderFaBody();">${opts.join('')}</select>
        <input class="form-input-lg" style="flex:1; min-width:140px; margin-top:0;" placeholder="Filter features…" value="${escapeHtml(_faFilter)}" oninput="_faFilter=this.value; _faRenderUserRows();">
    </div>`;
    if (!_faUser) return html + '<div style="padding:20px; text-align:center; color:#94a3b8; font-weight:600;">Pick a user to manage their exceptions.</div>';
    const cnt = ovCounts[_faUser] || 0;
    if (cnt) {
        html += `<div style="display:flex; justify-content:flex-end; margin-bottom:8px;">
            <button class="btn-secondary" style="font-size:11.5px; padding:6px 12px;" onclick="faClearUser()">↺ Clear all ${cnt} override${cnt > 1 ? 's' : ''} for this user</button></div>`;
    }
    return html + `<div id="fa-user-rows">${_faUserRowsHtml()}</div>`;
}

function _faRenderUserRows() {
    const wrap = document.getElementById('fa-user-rows');
    if (wrap) wrap.innerHTML = _faUserRowsHtml();
}

function _faUserRowsHtml() {
    const filter = _faFilter.trim().toLowerCase();
    const u = _faUsers.find(x => x.name.toLowerCase() === _faUser);
    // effective role slug (Multi-Store Manager logs in with role 'manager')
    let roleSlug = u ? String(u.role || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, '-') : '';
    if (roleSlug === 'multi-store-manager') roleSlug = 'manager';
    let html = '', lastGroup = '';
    _faCatalog().forEach(f => {
        if (filter && !(`${f.label} ${f.group}`).toLowerCase().includes(filter)) return;
        if (f.group !== lastGroup) {
            lastGroup = f.group;
            html += `<div style="font-size:10.5px; font-weight:800; text-transform:uppercase; letter-spacing:.5px; color:#94a3b8; margin:16px 2px 4px;">${f.group}</div>`;
        }
        const ovr = _faUserOverride(f.key, _faUser);
        let inherited = null;
        if (roleSlug) {
            const roleOvr = _faRoleOverride(f.key, roleSlug);
            inherited = roleOvr === null ? _faDefaultFor(f, roleSlug) : roleOvr;
        }
        const seg = (val, txt) => {
            const active = (ovr === null && val === 'default') || (ovr === true && val === 'on') || (ovr === false && val === 'off');
            const cls = active ? (val === 'on' ? ' fa-seg-active fa-seg-on' : (val === 'off' ? ' fa-seg-active fa-seg-off' : ' fa-seg-active')) : '';
            return `<button class="fa-seg${cls}" onclick="faSetUser('${f.key}', '${val}')">${txt}</button>`;
        };
        html += `<div style="display:flex; align-items:center; gap:8px; padding:4px 2px; border-bottom:1px solid #f1f5f9;">
            <span style="flex:1; font-size:12.5px; font-weight:700; color:var(--slate-charcoal);">${f.label}${inherited !== null ? `<span style="font-weight:600; color:#cbd5e1; font-size:11px;"> · role default: ${inherited ? 'visible' : 'hidden'}</span>` : ''}</span>
            <div style="display:inline-flex; border:1.5px solid #e2e8f0; border-radius:8px; overflow:hidden; flex-shrink:0;">
                ${seg('default', 'Default')}${seg('on', 'On')}${seg('off', 'Off')}
            </div>
        </div>`;
    });
    return html || '<div style="padding:16px; text-align:center; color:#94a3b8; font-weight:600;">No features match the filter.</div>';
}

async function faSetUser(key, val) {
    if (!_faUser) return;
    const enabled = val === 'default' ? null : (val === 'on');
    const m = (_featureOv.user[key] = _featureOv.user[key] || {});
    if (enabled === null) delete m[_faUser]; else m[_faUser] = enabled;
    if (!Object.keys(m).length) delete _featureOv.user[key];
    _featureOvRaw = _featureOvRaw.filter(r => !(r.subject_type === 'user' && r.feature_key === key && String(r.subject).toLowerCase() === _faUser));
    if (enabled !== null) _featureOvRaw.push({ feature_key: key, subject_type: 'user', subject: _faUser, enabled });
    localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
    renderFaBody();
    applyRoleBasedUI();
    try {
        const res = await fetch(FEATURE_ACCESS_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'set_override', feature_key: key, subject_type: 'user', subject: _faUser,
                enabled,
                updated_by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
    } catch (e) {
        alert('Could not save: ' + e.message);
        _faLoad();
    }
}

async function faClearUser() {
    if (!_faUser) return;
    if (!confirm('Clear ALL feature overrides for this user? Their role settings will apply again.')) return;
    Object.keys(_featureOv.user).forEach(k => {
        delete _featureOv.user[k][_faUser];
        if (!Object.keys(_featureOv.user[k]).length) delete _featureOv.user[k];
    });
    _featureOvRaw = _featureOvRaw.filter(r => !(r.subject_type === 'user' && String(r.subject).toLowerCase() === _faUser));
    localStorage.setItem('speeksFeatureOv', JSON.stringify(_featureOv));
    renderFaBody();
    applyRoleBasedUI();
    try {
        const res = await fetch(FEATURE_ACCESS_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'clear_user', subject: _faUser }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
    } catch (e) {
        alert('Could not clear: ' + e.message);
        _faLoad();
    }
}

// ============================================================
// VARIANCE REPLIES (workspace tab)
// ============================================================
// The DM uploads the ≤ -10% variance line items per store per period (parsed
// client-side from the Excel sheet via SheetJS on workspace.html); store
// managers explain each line (GM Notes), the DM responds (DM Notes) within
// the week, and managers reply back (Replies to DM Notes) — replacing the
// shared spreadsheet. Pulsing dots + the shared red reminder bubble nudge
// managers the day before the deadline and when DM notes land.

const _VR_MANAGER_ROLES = new Set(['manager', 'owner (manager)', 'owner manager']);

function _vrRole() { return (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim(); }
// A manager can be delegated the DM side of Variance Replies (Feature Access →
// Delegation → "Variance Replies (DM)"), which flips them to the DM experience
// here: store dropdown across all 5 stores, upload panel, DM notes, DM popups.
function _vrHasDmDelegation() {
    if (typeof _featureOverrideFor !== 'function') return false;
    const roleClass = 'role-' + _vrRole().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, '-');
    const name = sessionStorage.getItem('speeksUserName') || '';
    return _featureOverrideFor('cap-variance-dm', roleClass, name) === true;
}
function _vrIsDM() { return _vrRole() === 'district manager' || _vrHasDmDelegation(); }
// A delegated manager wears the DM hat here, not their own GM hat, so the two
// stay mutually exclusive and the render logic doesn't get both at once.
function _vrIsManager() { return _VR_MANAGER_ROLES.has(_vrRole()) && !_vrHasDmDelegation(); }

// Stores whose periods the tab loads: the DM gets every store at once (they
// pick a date range first, then flip between stores within it); an MSM sees
// both managed stores; a manager is locked to their own.
function _vrStores() {
    if (_vrIsDM()) return ['OVL', 'LEE', 'WSP', 'MPL', 'BAL'];
    return _vrMyStores();
}

// The manager's own store(s) — used for reminders/dots regardless of UI state.
function _vrMyStores() {
    if (typeof isMultiStoreManager === 'function' && isMultiStoreManager()) {
        return [...MULTISTORE_MANAGER_STORES];
    }
    const s = (sessionStorage.getItem('speeksUserStore') || '').toUpperCase();
    return (s && s !== 'ALL' && s !== 'CORP') ? [s] : [];
}

let _vrPeriods = [];      // period summaries for the pickers
let _vrCurrent = null;    // { period, items } currently open
let _vrUploadOpen = false;
let _vrParsed = null;     // parsed Excel rows awaiting confirm
let _vrFileName = '';     // name of the parsed file (the <input> can't keep it across re-renders)
let _vrEditing = false;   // notes are locked until ✏️ Edit is clicked (KPI-style)
let _vrDrafts = {};       // "itemId|field" → unsaved textarea text, survives re-renders
let _vrStoreStatus = {};  // store → { in_the_clear, updated_by, updated_at } (DM control)
let _vrClearedTV = {};    // store → latest team variance summary (for cleared stores)
let _vrRawFileB64 = '';   // base64 of the raw uploaded workbook, kept for storage
let _vrClearedPanelsPending = ''; // cleared-store summary panels to prepend (MSM mix)
const _VR_VARIANCE_CUTOFF = -10; // only lines at this variance % or worse are imported

// A store the DM has marked "in the clear": its managers stop seeing/answering
// line items and get no dots/popups — they just see their team + store total.
function _vrStoreCleared(store) {
    const s = _vrStoreStatus[(store || '').toUpperCase()];
    return !!(s && s.in_the_clear);
}

const _vrFmtPct = v => (v == null || v === '') ? '—'
    : `${Number(v) > 0 ? '+' : ''}${Number(v).toFixed(1)}%`;
const _vrFmtDate = d => { const x = new Date(d); return isNaN(x.getTime()) ? '' : x.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }); };

async function loadVarianceReplies() {
    const body = document.getElementById('vr-body');
    if (!body) return;
    body.innerHTML = '<div class="status-message">Loading variance replies…</div>';
    const stores = _vrStores();
    if (!stores.length) {
        body.innerHTML = '<div class="status-message">No store assigned to your account.</div>';
        return;
    }
    try {
        const res = await fetch(`${VARIANCE_REPLIES_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json.success) throw new Error(json.error);
        _vrPeriods = json.data || [];
        _vrStoreStatus = json.store_status || {};
        _vrClearedTV = json.cleared_team_variance || {};
        // Opening the tool is the manager reviewing the DM's notes, so clear the
        // "DM reviewed your replies" FYI for the store(s) visible here — the active
        // store only for an MSM (they switch dashboards for the other), all periods
        // for a single-store manager. The reply-REQUESTED nag is untouched (it's
        // state-based and clears only when they actually answer).
        if (!_vrIsDM()) {
            const active = _msmDefaultStore();
            const seen = _vrGetReviewSeen();
            _vrPeriods.forEach(p => {
                if (p.dm_notes_at && (!active || (p.store || '').toUpperCase() === active)) {
                    seen[p.id] = new Date(p.dm_notes_at).getTime();
                }
            });
            _vrSetReviewSeen(seen);
            if (typeof checkVarianceReminders === 'function') checkVarianceReminders();
        }
        _vrBuildPeriodPicker();
        // DM: an alert can ask us to land on a specific store that needs review
        // (set as the tool-store override). The DM picks store via vr-store-select,
        // so point it there before resolving the period. One-time — normal opens
        // keep the DM's current store.
        if (_vrIsDM()) {
            const target = _consumeMsmAlertStore();
            const sSel = document.getElementById('vr-store-select');
            if (target && sSel && [...sSel.options].some(o => o.value === target)) sSel.value = target;
        }
        const pid = _vrSelectedPeriodId();
        if (pid) await vrOpenPeriod(pid);
        else { _vrCurrent = null; renderVarianceReplies(); }
    } catch (e) {
        body.innerHTML = '<div class="status-message" style="color:var(--red-alert);">Failed to load variance replies.</div>';
    }
}

function _vrBuildPeriodPicker() {
    const sel = document.getElementById('vr-period-select');
    if (!sel) return;
    if (!_vrPeriods.length) { sel.style.display = 'none'; sel.innerHTML = ''; return; }
    const current = sel.value;
    if (_vrIsDM()) {
        // The DM picks the DATE RANGE first (uploads share a range across
        // stores), then flips between stores with the store dropdown.
        const seen = new Set();
        sel.innerHTML = _vrPeriods.map(p => {
            const key = `${p.date_from}|${p.date_to}`;
            if (seen.has(key)) return '';
            seen.add(key);
            return `<option value="${key}">${escapeHtml(formatVarianceRange(p.date_from, p.date_to))}</option>`;
        }).join('');
    } else {
        const multi = _vrStores().length > 1;
        sel.innerHTML = _vrPeriods.map(p => {
            const label = `${multi ? p.store + ' · ' : ''}${formatVarianceRange(p.date_from, p.date_to)}${p.timeframe ? ' · ' + p.timeframe : ''}`;
            return `<option value="${p.id}">${escapeHtml(label)}</option>`;
        }).join('');
    }
    sel.style.display = '';
    if (current && [...sel.options].some(o => o.value === current)) {
        sel.value = current; // keep the user's current pick across re-renders
    } else if (!_vrIsDM()) {
        // First load for a manager/MSM: default to a period for the store this open
        // is meant to show — a single-store alert override if one is pending, else
        // the active dashboard store — rather than the first in the list. Re-renders
        // preserve the current pick (the `current` branch above).
        const def = _msmToolStore();
        const match = def && _vrPeriods.find(p => (p.store || '').toUpperCase() === def);
        if (match) sel.value = match.id;
    }
}

// The open period: managers' picker holds period ids directly; the DM's
// holds a date-range key that combines with the store dropdown.
function _vrSelectedPeriodId() {
    const sel = document.getElementById('vr-period-select');
    if (!sel || !sel.value) return '';
    if (!_vrIsDM()) return sel.value;
    const [from, to] = sel.value.split('|');
    const store = ((document.getElementById('vr-store-select') || {}).value || '').toUpperCase();
    const p = _vrPeriods.find(p => p.date_from === from && p.date_to === to && p.store === store);
    return p ? p.id : '';
}

function vrOnStoreChange() {
    _vrUploadOpen = false; _vrParsed = null; _vrEditing = false; _vrDrafts = {};
    if (_vrIsDM() && _vrPeriods.length) {
        // all stores are already loaded — just resolve within the picked range
        const pid = _vrSelectedPeriodId();
        if (pid) vrOpenPeriod(pid);
        else { _vrCurrent = null; renderVarianceReplies(); }
        return;
    }
    loadVarianceReplies();
}
function vrOnPeriodChange() {
    const pid = _vrSelectedPeriodId();
    if (pid) vrOpenPeriod(pid);
    else { _vrCurrent = null; renderVarianceReplies(); }
}

async function vrOpenPeriod(pid) {
    const body = document.getElementById('vr-body');
    try {
        const res = await fetch(`${VARIANCE_REPLIES_URL}?period_id=${encodeURIComponent(pid)}&v=${Date.now()}`);
        const json = await res.json();
        if (!json.success) throw new Error(json.error);
        _vrCurrent = json;
        _vrEditing = false;
        _vrDrafts = {};
        renderVarianceReplies();
    } catch (e) {
        if (body) body.innerHTML = '<div class="status-message" style="color:var(--red-alert);">Failed to load that period.</div>';
    }
}

function _vrSubtitleText() {
    if (!_vrCurrent || !_vrCurrent.period) return '';
    const p = _vrCurrent.period;
    // Cleared managers have no reply deadline — don't nag them with one.
    if (_vrIsManager() && _vrStoreCleared(p.store)) return 'In the clear';
    const items = _vrCurrent.items || [];
    const answered = items.filter(i => i.gm_note).length;
    const due = new Date(p.manager_due_at);
    const overdue = Date.now() > due.getTime() && answered < items.length;
    // The n/n-explained scoreboard is for managers; the DM just gets the date.
    const progress = _vrIsDM() ? '' : ` · ${answered}/${items.length} explained`;
    return `Replies due ${due.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}${overdue ? ' (overdue)' : ''}${progress}`;
}

function _vrUpdateProgressLine() {
    const sub = document.getElementById('vr-subtitle');
    if (sub) sub.textContent = _vrSubtitleText();
}

// The team variance summary card shown above the reply lines — mirrors the
// numbers on the manager variance widget (store total % + each person's %).
// `tv` is the backend's matched Submit-Variance-Report entry (may be null).
function _vrTeamVarianceHtml(tv, period) {
    if (!tv) return '';
    const badge = v => {
        const n = Number(v);
        const cls = n < 0 ? 'delta-neg' : (n > 0 ? 'delta-pos' : 'delta-neutral');
        return `<span class="delta-badge ${cls}">${formatVariancePct(n)}</span>`;
    };
    // If the matched team-variance entry's dates differ from this reply
    // period's, show its own range so it's clear which report it came from.
    const rangeDiffers = !tv.exact && tv.date_from && tv.date_to
        && (tv.date_from !== period.date_from || tv.date_to !== period.date_to);
    const rangeNote = rangeDiffers
        ? `<span style="font-weight:600; color:#94a3b8; text-transform:none; letter-spacing:0; margin-left:8px;">${formatVarianceRange(tv.date_from, tv.date_to)}</span>`
        : '';
    const emps = (tv.employees || []).map(e => `
        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px; padding:7px 14px; border-top:1px solid #f1f5f9;">
            <span style="font-size:12px; font-weight:600; color:#334155;">${escapeHtml(e.name)}</span>
            ${badge(e.val)}
        </div>`).join('');
    return `<details open style="border:1px solid #e2e8f0; border-radius:12px; background:#fff; overflow:hidden; margin-bottom:16px;">
        <summary style="list-style:none; cursor:pointer; display:flex; align-items:center; justify-content:space-between; gap:10px; background:#f8fafc; padding:12px 16px; border-bottom:1px solid #e2e8f0;">
            <span style="font-size:12px; font-weight:800; color:var(--slate-charcoal); text-transform:uppercase; letter-spacing:.4px;">Team Variance${rangeNote}</span>
            <span style="display:flex; align-items:center; gap:10px;"><span style="font-size:10px; font-weight:700; color:#94a3b8; text-transform:uppercase;">Store Total</span>${badge(tv.total)}</span>
        </summary>
        <div>${emps || '<div style="padding:12px 16px; font-size:12px; color:#94a3b8;">No per-person variance recorded.</div>'}</div>
    </details>`;
}

// What a manager of an "in the clear" store sees instead of the reply sheet:
// a friendly heads-up plus their team + store-total variance summary. No line
// items, no reply obligation — the DM flips them back if things slip.
function _vrClearedPanelHtml(store, tv) {
    const rangeTxt = (tv && tv.date_from && tv.date_to)
        ? `<div style="font-size:11px; font-weight:600; color:#94a3b8; margin-top:4px;">Latest variance · ${escapeHtml(formatVarianceRange(tv.date_from, tv.date_to))}</div>`
        : '';
    const summary = tv
        ? _vrTeamVarianceHtml(tv, { date_from: tv.date_from, date_to: tv.date_to })
        : `<div style="padding:14px 16px; font-size:12px; color:#94a3b8; background:#fff; border:1px solid #e2e8f0; border-radius:12px;">No team variance recorded yet.</div>`;
    return `<div style="margin-bottom:16px;">
        <div style="background:linear-gradient(135deg,#ecfdf5,#d1fae5); border:1.5px solid #a7f3d0; border-radius:14px; padding:18px 20px; margin-bottom:16px;">
            <div style="display:flex; align-items:center; gap:10px;">
                <span style="font-size:22px;">✅</span>
                <span style="font-size:15px; font-weight:800; color:#065f46;">${escapeHtml(store)} is in the clear</span>
            </div>
            <div style="font-size:12.5px; font-weight:600; color:#047857; line-height:1.5; margin-top:8px;">
                Your variance is in a great place — there are no line items to explain right now. Just keep an eye on your team and store totals below. If things start to slip, the DM will switch replies back on.
            </div>
            ${rangeTxt}
        </div>
        ${summary}
    </div>`;
}

// Slim banner atop a cleared store's report (when uploads exist): the manager
// can read it, switch date ranges and download it, but owes no replies.
function _vrMgrClearedBannerHtml(store) {
    return `<div style="background:linear-gradient(135deg,#ecfdf5,#d1fae5); border:1.5px solid #a7f3d0; border-radius:12px; padding:12px 16px; margin-bottom:14px; font-size:12.5px; font-weight:700; color:#065f46; line-height:1.5;">
        ✅ <b>${escapeHtml(store)}</b> is in the clear — you don't need to reply to these lines. They're here for reference: check your team variance below, switch date ranges with the dropdown, and download the full report anytime.
    </div>`;
}

function renderVarianceReplies() {
    const body = document.getElementById('vr-body');
    if (!body) return;
    _vrClearedPanelsPending = '';
    // "In the clear" managers still see their reports — read-only, switchable by
    // date range, with team variance + the download button — they just have no
    // reply obligation. The only time we fall back to the standalone summary
    // panel is a cleared store that has NO uploads yet (nothing to show a
    // report for). With multiple managed stores, that panel is prepended above
    // whatever active/other store's report is open.
    if (_vrIsManager()) {
        const clearedNoUploads = _vrMyStores().filter(s => _vrStoreCleared(s) && !_vrPeriods.some(p => p.store === s));
        if (clearedNoUploads.length) {
            const panels = clearedNoUploads.map(s => _vrClearedPanelHtml(s, _vrClearedTV[s])).join('');
            if (!_vrPeriods.length) {
                ['vr-edit-btn', 'vr-save-btn', 'vr-edit-cancel-btn'].forEach(id => {
                    const b = document.getElementById(id); if (b) b.style.display = 'none';
                });
                const sub = document.getElementById('vr-subtitle'); if (sub) sub.textContent = '';
                body.innerHTML = panels;
                return;
            }
            _vrClearedPanelsPending = panels;
        }
    }
    // Rebuilding the table destroys the textareas — stash what's typed so an
    // unexpected re-render mid-edit can never delete someone's notes. The
    // "needs a reply" checkboxes ride along the same way.
    if (_vrEditing) {
        body.querySelectorAll('textarea[data-vr-item]').forEach(ta => {
            _vrDrafts[ta.dataset.vrItem + '|' + ta.dataset.vrField] = ta.value;
        });
        body.querySelectorAll('input[data-vr-rr]').forEach(cb => {
            _vrDrafts['rr|' + cb.dataset.vrRr] = cb.checked;
        });
    }
    // The header Cancel button only shows while the upload panel is open.
    const cancelBtn = document.getElementById('vr-cancel-upload-btn');
    if (cancelBtn) cancelBtn.style.display = (_vrIsDM() && _vrUploadOpen) ? 'inline-flex' : 'none';
    // DM "In the Clear" toggle: reflects the currently selected store's status.
    _vrSyncStatusButton();
    let html = _vrClearedPanelsPending || '';
    // DM banner: remind them this store is in the clear (managers aren't replying).
    if (_vrIsDM()) {
        const dmStore = ((document.getElementById('vr-store-select') || {}).value || '').toUpperCase();
        if (_vrStoreCleared(dmStore)) html += _vrDmClearedBannerHtml(dmStore);
    }
    if (_vrIsDM() && _vrUploadOpen) html += _vrUploadPanelHtml();

    if (!_vrCurrent || !_vrCurrent.period) {
        ['vr-edit-btn', 'vr-save-btn', 'vr-edit-cancel-btn'].forEach(id => {
            const b = document.getElementById(id);
            if (b) b.style.display = 'none';
        });
        const hint = _vrIsDM()
            ? (_vrPeriods.length ? 'No upload for this store in the selected date range.' : 'No variance uploads yet.')
            : 'No variance report has been uploaded for your store yet.';
        body.innerHTML = html + `<div style="padding:36px 20px; text-align:center; color:#94a3b8; font-weight:600;">${hint}</div>`;
        _vrUpdateProgressLine();
        return;
    }

    const p = _vrCurrent.period;
    const items = _vrCurrent.items || [];
    // A manager whose store is "in the clear" views the report read-only — no
    // reply obligation — so they can't edit notes (canGm off) but still see the
    // line items, team variance and download. A banner explains it.
    const mgrCleared = _vrIsManager() && _vrStoreCleared(p.store);
    if (mgrCleared) html += _vrMgrClearedBannerHtml(p.store);
    const canGm = _vrIsManager() && !mgrCleared;
    const canDm = _vrIsDM();

    // The reply cycle reveals columns as each side takes its turn:
    //   1. Managers fill GM Notes (extra-wide while it's the only note column);
    //      the DM sees only the line items during this phase.
    //   2. GM Notes + DM Notes appear for the DM once every line is explained
    //      or the managers' deadline passes — whichever comes first.
    //   3. All note columns (incl. Replies) appear for everyone once the DM
    //      has actually written a note.
    const anyDmNote = items.some(i => i.dm_note);
    const dmNotesOpen = _vrDmNotesOpen(p) || (items.length > 0 && items.every(i => i.gm_note));
    const showGmCol = canGm || dmNotesOpen || anyDmNote;
    const showDmCol = canDm ? (dmNotesOpen || anyDmNote) : anyDmNote;
    const showReplyCol = anyDmNote;

    // Notes are locked behind the KPI-style ✏️ Edit / Save / Cancel header
    // buttons; canEditNow decides whether the viewer has anything to unlock.
    // Edit mode and the upload panel are mutually exclusive in the header:
    // while editing, only Save/Cancel show (Upload Report is hidden so it
    // can't wipe unsaved notes); while the upload panel is open, only its
    // Cancel + Upload Report show.
    // Once every note the DM flagged has its manager reply, the round trip is
    // over — the DM's Edit button goes away entirely (nothing left that needs
    // them). Managers keep theirs while any flagged note still wants a reply.
    const flaggedNotes = items.filter(i => i.dm_note && i.dm_reply_requested);
    const dmCycleDone = flaggedNotes.length > 0 && flaggedNotes.every(i => i.mgr_reply);
    // A manager only needs Edit while there's actually something for them to do:
    // still explaining lines before the DM reviews (phase 1), or a flagged note
    // awaiting their reply. Once the DM has reviewed and requested no reply, the
    // report is review-only — hide Edit so it doesn't imply an action is pending.
    const gmUnexplained = items.some(i => !i.gm_note);
    const replyPending = items.some(i => i.dm_note && i.dm_reply_requested && !i.mgr_reply);
    const mgrHasWork = !anyDmNote || gmUnexplained || replyPending;
    const canEditNow = items.length > 0 && ((canGm && mgrHasWork) || (canDm && dmNotesOpen && !dmCycleDone)) && !_vrUploadOpen;
    const editBtn = document.getElementById('vr-edit-btn');
    const saveBtn = document.getElementById('vr-save-btn');
    const cancelEditBtn = document.getElementById('vr-edit-cancel-btn');
    const uploadBtn = document.getElementById('vr-upload-btn');
    if (editBtn) editBtn.style.display = (canEditNow && !_vrEditing) ? 'inline-block' : 'none';
    if (saveBtn) saveBtn.style.display = (canEditNow && _vrEditing) ? 'inline-block' : 'none';
    if (cancelEditBtn) cancelEditBtn.style.display = (canEditNow && _vrEditing) ? 'inline-block' : 'none';
    if (uploadBtn && canDm) uploadBtn.style.display = _vrEditing ? 'none' : 'inline-flex';

    // The raw workbook the DM uploaded is downloadable by anyone who can see the
    // period (managers + DM) so they can pull the full breakdown, including the
    // lines below the -10% cutoff that we don't import as reply rows.
    const dlBtn = p.raw_file_path
        ? `<button class="btn-secondary" style="height:30px; font-size:12px; padding:0 14px; border-radius:7px;" onclick="vrDownloadRaw('${p.id}', this)">⬇ Download full report</button>`
        : '';
    html += `<div style="display:flex; align-items:center; justify-content:space-between; gap:10px; flex-wrap:wrap; margin:12px 0 16px;">
        <div style="font-size:12px; color:#64748b; font-weight:600; line-height:1.5; padding-left:14px;">
            <b>${escapeHtml(p.store)}</b> · ${formatVarianceRange(p.date_from, p.date_to)}${p.timeframe ? ' · ' + escapeHtml(p.timeframe) : ''}
        </div>
        <div class="align-center gap-8" style="margin-right:14px;">
            ${dlBtn}
            ${canDm ? `<button class="btn-secondary" style="height:30px; font-size:12px; padding:0 14px; border-radius:7px;" onclick="vrDeletePeriod('${p.id}')">Delete this upload</button>` : ''}
        </div>
    </div>`;

    // Team variance for this period (store total % + per-person %), the same
    // numbers the manager variance widget shows — surfaced here as context for
    // the lines being explained. Pulled by the backend from the matching
    // Submit-Variance-Report entry (both uploaded together).
    html += _vrTeamVarianceHtml(_vrCurrent.team_variance, p);

    const th = t => `<th style="text-align:left; font-size:9.5px; font-weight:800; text-transform:uppercase; letter-spacing:.4px; color:#94a3b8; padding:8px 14px; border-bottom:1px solid #e2e8f0; white-space:nowrap;">${t}</th>`;
    const td = (c, extra = '') => `<td style="padding:8px 14px; border-bottom:1px solid #f1f5f9; vertical-align:top; font-size:12px; ${extra}">${c}</td>`;
    html += `<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; min-width:${680 + (showGmCol ? 220 : 0) + (showDmCol ? 220 : 0) + (showReplyCol ? 220 : 0)}px;">
        <thead><tr>${th('Order #')}${th('SKU')}${th('Item Title')}${th('Buyer')}${th('Lister')}${th('Var.')}${showGmCol ? th('GM Notes') : ''}${showDmCol ? th('DM Notes') : ''}${showReplyCol ? th('Replies to DM Notes') : ''}</tr></thead><tbody>`;

    // Empty GM-note boxes turn light red once the managers' deadline has
    // passed — a visible mark on exactly which lines were missed.
    const pastDue = p.manager_due_at && Date.now() > new Date(p.manager_due_at).getTime();

    items.forEach(it => {
        const pct = it.variance_pct == null ? null : Number(it.variance_pct);
        const missedGm = pastDue && !it.gm_note;
        html += `<tr>
            ${td(`<span style="font-weight:700; white-space:nowrap;">${escapeHtml(it.order_number || '—')}</span>`)}
            ${td(`<span style="white-space:nowrap; color:#64748b;">${escapeHtml(it.sku || '—')}</span>`)}
            ${td(`<span style="color:var(--slate-charcoal);">${escapeHtml(it.item_title || '—')}</span>`, 'min-width:200px;')}
            ${td(escapeHtml(it.buyer_name || '—'), 'white-space:nowrap; padding-right:22px;')}
            ${td(escapeHtml(it.lister_name || '—'), 'white-space:nowrap; padding-right:22px;')}
            ${td(`<span style="font-weight:900; color:${pct == null ? '#94a3b8' : '#dc2626'}; white-space:nowrap;">${_vrFmtPct(pct)}</span>`, 'padding-right:22px;')}
            ${showGmCol ? td((() => {
                // Once the DM has responded to an explanation it locks — the
                // conversation moved on, rewriting history would orphan replies.
                return _vrNoteCell(it, 'gm_note', canGm && _vrEditing && !it.dm_note, 'Why did this sell so far under projection?');
            })(), (showDmCol || showReplyCol ? '' : 'width:45%;') + (missedGm ? ' background:#fee2e2;' : '')) : ''}
            ${showDmCol ? td((() => {
                // Same lock the other way: a DM note the manager already
                // replied to can't be edited out from under the reply.
                const dmEditing = canDm && dmNotesOpen && _vrEditing && !!it.gm_note && !it.mgr_reply;
                let cell = _vrNoteCell(it, 'dm_note', dmEditing, 'Advice or a question for the manager…');
                // Read-only views get a chip that says whether this note wants
                // an answer or is FYI-only — that's how the manager tells what
                // to respond to vs what's just for them to read.
                if (it.dm_note && !dmEditing) {
                    cell += it.dm_reply_requested
                        ? (it.mgr_reply
                            ? `<span style="display:inline-block; margin-top:4px; font-size:9.5px; font-weight:800; color:#166534; background:#dcfce7; border:1px solid #a7f3d0; border-radius:20px; padding:2px 8px; white-space:nowrap;">✓ Replied</span>`
                            : `<span style="display:inline-block; margin-top:4px; font-size:9.5px; font-weight:800; color:#b91c1c; background:#fee2e2; border:1px solid #fca5a5; border-radius:20px; padding:2px 8px; white-space:nowrap;">↩ Response requested</span>`)
                        : `<span style="display:inline-block; margin-top:4px; font-size:9.5px; font-weight:800; color:#64748b; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:20px; padding:2px 8px; white-space:nowrap;">FYI — no reply needed</span>`;
                }
                return cell;
            })()) : ''}
            ${showReplyCol ? td(_vrNoteCell(it, 'mgr_reply', canGm && !!it.dm_note && !!it.dm_reply_requested && _vrEditing, it.dm_note && it.dm_reply_requested ? 'Reply to the DM note…' : '')) : ''}
        </tr>`;
    });
    html += `</tbody></table></div>`;
    body.innerHTML = html;
    _vrUpdateProgressLine();
}

// DM notes stay locked until the managers' reply window closes — managers
// explain first, then the DM weighs in.
function _vrDmNotesOpen(p) {
    return !p.manager_due_at || new Date(p.manager_due_at) <= new Date();
}

// One note cell: read-only text + author/date caption normally; a textarea
// while the viewer is in ✏️ Edit mode (saved in bulk by vrSaveEdits).
function _vrNoteCell(it, field, editable, placeholder) {
    const val = it[field] || '';
    const by = it[field + '_by'];
    const at = it[field + '_at'];
    const caption = (val && (by || at))
        ? `<div style="font-size:10px; color:#94a3b8; font-weight:700; margin-top:3px;">${escapeHtml(by || '')}${at ? ' · ' + _vrFmtDate(at) : ''}</div>` : '';
    if (!editable) {
        const txt = val ? escapeHtml(val) : `<span style="color:#cbd5e1;">${field === 'mgr_reply' && !it.dm_note ? '' : '—'}</span>`;
        return `<div style="min-width:190px; line-height:1.45; color:#334155;">${txt}${caption}</div>`;
    }
    const draft = _vrDrafts[it.id + '|' + field];
    const shownText = draft !== undefined ? draft : val;
    // The DM flags each note as needing a manager reply or FYI-only — that's
    // what decides whether the manager gets a reply box + nudges for it. The
    // flag only means something WITH a note, so the box stays disabled until
    // there's text (a tick on an empty note used to be silently dropped).
    let rrBox = '';
    if (field === 'dm_note') {
        const rrDraft = _vrDrafts['rr|' + it.id];
        const checked = rrDraft !== undefined ? rrDraft : !!it.dm_reply_requested;
        const hasText = String(shownText || '').trim() !== '';
        rrBox = `<label title="${hasText ? 'The manager gets a reply box + reminders for this note' : 'Write the note first — then you can request a reply'}" style="display:flex; align-items:center; gap:5px; margin-top:4px; font-size:10.5px; font-weight:700; color:#64748b; cursor:pointer; user-select:none;${hasText ? '' : ' opacity:0.45;'}">
            <input type="checkbox" data-vr-rr="${it.id}"${checked && hasText ? ' checked' : ''}${hasText ? '' : ' disabled'} style="width:13px; height:13px; cursor:pointer;"> Needs a reply from the manager
        </label>`;
    }
    const rrSync = field === 'dm_note'
        ? ` oninput="const c=this.parentElement.querySelector('input[data-vr-rr]'); if(c){const t=!!this.value.trim(); c.disabled=!t; if(!t)c.checked=false; c.parentElement.style.opacity=t?'':'0.45';}"`
        : '';
    return `<div style="min-width:210px;">
        <textarea rows="2" placeholder="${escapeHtml(placeholder || '')}"
            data-vr-item="${it.id}" data-vr-field="${field}"${rrSync}
            style="width:100%; box-sizing:border-box; padding:7px 9px; border:1.5px solid #cbd5e1; border-radius:7px; font-size:12px; font-weight:500; font-family:inherit; line-height:1.4; resize:vertical; background:#fff; transition:border-color .3s;"
        >${escapeHtml(shownText)}</textarea>${rrBox}${caption}</div>`;
}

function vrStartEdit() { _vrEditing = true; _vrDrafts = {}; renderVarianceReplies(); }
function vrCancelEdit() { _vrEditing = false; _vrDrafts = {}; renderVarianceReplies(); }

// Saves every changed textarea in one pass, then locks the notes again.
async function vrSaveEdits(btn) {
    const items = (_vrCurrent && _vrCurrent.items) || [];
    const changes = [];
    document.querySelectorAll('#vr-body textarea[data-vr-item]').forEach(ta => {
        const it = items.find(i => i.id === ta.dataset.vrItem);
        if (!it) return;
        const field = ta.dataset.vrField;
        const text = ta.value.trim();
        // DM notes carry the "needs a reply" flag — a flag flip alone (text
        // unchanged) still needs saving.
        let rr;
        if (field === 'dm_note') {
            const cb = document.querySelector(`#vr-body input[data-vr-rr="${it.id}"]`);
            rr = cb ? cb.checked : !!it.dm_reply_requested;
        }
        const textChanged = (it[field] || '') !== text;
        const rrChanged = field === 'dm_note' && !!text && rr !== !!it.dm_reply_requested;
        if (textChanged || rrChanged) changes.push({ it, field, text, ta, rr });
    });
    if (!changes.length) { _vrEditing = false; renderVarianceReplies(); return; }

    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Saving…';
    const name = sessionStorage.getItem('speeksUserName') || null;
    let failed = 0;
    await Promise.all(changes.map(async c => {
        try {
            const res = await fetch(VARIANCE_REPLIES_URL, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'save_note', item_id: c.it.id, field: c.field, text: c.text, by: name,
                    ...(c.field === 'dm_note' ? { reply_requested: !!c.rr } : {}),
                }),
            });
            const json = await res.json().catch(() => ({}));
            if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
            c.it[c.field] = c.text || null;
            c.it[c.field + '_by'] = c.text ? name : null;
            c.it[c.field + '_at'] = c.text ? new Date().toISOString() : null;
            if (c.field === 'dm_note') {
                c.it.dm_reply_requested = c.text ? !!c.rr : false;
                if (c.text && _vrCurrent.period && !_vrCurrent.period.dm_notes_at) {
                    _vrCurrent.period.dm_notes_at = new Date().toISOString();
                }
            }
        } catch (e) {
            failed++;
            c.ta.style.borderColor = '#dc2626';
        }
    }));
    btn.disabled = false; btn.innerText = old;
    if (failed) {
        alert(`${failed} note${failed > 1 ? 's' : ''} failed to save — outlined in red. Click Save to retry.`);
        return; // stay in edit mode so nothing typed is lost
    }
    _vrEditing = false;
    _vrDrafts = {};
    renderVarianceReplies();
}

async function vrDeletePeriod(id) {
    if (!confirm('Delete this entire variance upload (all line items and replies)?')) return;
    try {
        const res = await fetch(VARIANCE_REPLIES_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'delete_period', id }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        _vrCurrent = null;
        loadVarianceReplies();
    } catch (e) {
        alert('Could not delete: ' + e.message);
    }
}

// ---- "In the Clear" store status (DM only) ----------------------------------
// Keeps the header toggle in sync with the selected store's status.
function _vrSyncStatusButton() {
    const btn = document.getElementById('vr-status-btn');
    if (!btn) return;
    if (!_vrIsDM() || _vrUploadOpen || _vrEditing) { btn.style.display = 'none'; return; }
    const store = ((document.getElementById('vr-store-select') || {}).value || '').toUpperCase();
    if (!store) { btn.style.display = 'none'; return; }
    const cleared = _vrStoreCleared(store);
    btn.style.display = 'inline-flex';
    btn.disabled = false; // clear the "Saving…" lock after a reload re-syncs it
    btn.textContent = cleared ? 'Reactivate replies' : 'Mark in the clear';
    btn.title = cleared
        ? `${store} is in the clear — click to require variance replies again`
        : `Mark ${store} as in the clear — its managers stop replying to variance lines`;
}

// The DM's reminder banner shown above a cleared store's sheet/empty state.
function _vrDmClearedBannerHtml(store) {
    const s = _vrStoreStatus[store] || {};
    const who = s.updated_by ? ` by ${escapeHtml(s.updated_by)}` : '';
    return `<div style="background:linear-gradient(135deg,#ecfdf5,#d1fae5); border:1.5px solid #a7f3d0; border-radius:12px; padding:12px 16px; margin-bottom:16px; display:flex; align-items:center; justify-content:space-between; gap:12px; flex-wrap:wrap;">
        <div style="font-size:12.5px; font-weight:700; color:#065f46; line-height:1.5;">
            ✅ <b>${escapeHtml(store)}</b> is in the clear — its managers aren't being asked to reply to variance lines${who}. They just see their team + store total.
        </div>
        <button class="btn-secondary" style="height:30px; font-size:12px; padding:0 14px; border-radius:7px; flex-shrink:0;" onclick="vrToggleStoreStatus(this)">Reactivate replies</button>
    </div>`;
}

async function vrToggleStoreStatus(btn) {
    if (!_vrIsDM()) return;
    const store = ((document.getElementById('vr-store-select') || {}).value || '').toUpperCase();
    if (!store) { alert('Pick a store first.'); return; }
    const cleared = _vrStoreCleared(store);
    const next = !cleared;
    const msg = next
        ? `Mark ${store} as in the clear?\n\nIts managers will stop seeing and replying to variance line items (and get no reminders) — they'll just see their team + store total. You can reactivate this anytime.`
        : `Reactivate variance replies for ${store}?\n\nIts managers will start seeing and replying to variance line items again.`;
    if (!confirm(msg)) return;
    const old = btn ? btn.textContent : '';
    if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }
    try {
        const res = await fetch(VARIANCE_REPLIES_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'set_store_status', store, in_the_clear: next,
                by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        await loadVarianceReplies();
    } catch (e) {
        alert('Could not update the store status: ' + (e.message || e));
        if (btn) { btn.disabled = false; btn.textContent = old; }
    }
}

// Fetches a short-lived signed URL for the period's raw workbook and downloads it.
async function vrDownloadRaw(periodId, btn) {
    const old = btn ? btn.textContent : '';
    if (btn) { btn.disabled = true; btn.textContent = 'Preparing…'; }
    try {
        const res = await fetch(`${VARIANCE_REPLIES_URL}?file=${encodeURIComponent(periodId)}&v=${Date.now()}`);
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false || !json.url) throw new Error(json.error || 'No file');
        const a = document.createElement('a');
        a.href = json.url;
        if (json.name) a.download = json.name;
        document.body.appendChild(a);
        a.click();
        a.remove();
    } catch (e) {
        alert('Could not download the report: ' + (e.message || e));
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = old; }
    }
}

// ---- DM upload flow (SheetJS parses the sheet in the browser) ---------------
function vrToggleUpload() {
    _vrUploadOpen = !_vrUploadOpen;
    _vrParsed = null;
    _vrFileName = '';
    _vrRawFileB64 = '';
    renderVarianceReplies();
}

function _vrUploadPanelHtml() {
    const lbl = t => `<label class="vr-up-label">${t}</label>`;
    const store = (document.getElementById('vr-store-select') || {}).value || 'OVL';
    // The panel is rebuilt on every render (e.g. right after a file is parsed),
    // which recreates the date inputs — carry their values over so dates typed
    // before picking the file aren't wiped.
    const curFrom = (document.getElementById('vr-up-from') || {}).value || '';
    const curTo = (document.getElementById('vr-up-to') || {}).value || '';
    let preview = '';
    if (_vrParsed) {
        if (_vrParsed.items.length) {
            const pcts = _vrParsed.items.map(i => i.variance_pct).filter(v => v != null);
            preview = `<div style="margin-top:10px; font-size:12px; font-weight:600; color:#334155;">
                ✅ Parsed <b>${_vrParsed.items.length}</b> line item${_vrParsed.items.length > 1 ? 's' : ''} at ${_VR_VARIANCE_CUTOFF}% or worse${pcts.length ? ` · variance ${_vrFmtPct(Math.max(...pcts))} to ${_vrFmtPct(Math.min(...pcts))}` : ''}${_vrParsed.aboveCutoff ? ` · <span style="color:#94a3b8;">${_vrParsed.aboveCutoff} line${_vrParsed.aboveCutoff > 1 ? 's' : ''} above the cutoff left out</span>` : ''}${_vrParsed.skipped ? ` · <span style="color:#d97706;">${_vrParsed.skipped} row${_vrParsed.skipped > 1 ? 's' : ''} skipped (no order # / SKU)</span>` : ''}
                <button class="btn-primary" style="margin-left:12px; font-size:12px; padding:7px 16px;" onclick="vrConfirmUpload(this)">Upload ${_vrParsed.items.length} items to ${store} →</button>
            </div>`;
        } else if (_vrParsed.aboveCutoff) {
            preview = `<div style="margin-top:10px; font-size:12px; font-weight:700; color:#d97706;">No line items at ${_VR_VARIANCE_CUTOFF}% variance or worse in this file — nothing needs a manager reply. (${_vrParsed.aboveCutoff} line${_vrParsed.aboveCutoff > 1 ? 's' : ''} above the cutoff.)</div>`;
        } else {
            preview = `<div style="margin-top:10px; font-size:12px; font-weight:700; color:#dc2626;">Couldn't find any line items — make sure the workbook has a sheet (e.g. "Detail") with an Order ID and SKU header row.</div>`;
        }
    }
    return `<div style="background:#f8fafc; border:1.5px solid #e2e8f0; border-radius:12px; padding:14px 16px; margin-bottom:16px;">
        <div style="font-weight:800; font-size:13px; color:var(--slate-charcoal); margin-bottom:10px;">Upload variance report for <b>${store}</b> <span style="font-weight:600; color:#94a3b8;">(store is picked in the dropdown above)</span></div>
        <div style="display:flex; gap:12px; flex-wrap:wrap; align-items:flex-end;">
            <div class="vr-up-field">${lbl('Date range')}<div class="vr-daterange"><input type="date" id="vr-up-from" class="vr-daterange-input" value="${curFrom}"><span class="vr-daterange-arrow">→</span><input type="date" id="vr-up-to" class="vr-daterange-input" value="${curTo}"></div></div>
            <div class="vr-up-field">${lbl('Excel file (.xlsx)')}${_vrParsed && _vrFileName
                ? `<div class="vr-file-chip"><span>📄 ${escapeHtml(_vrFileName)}</span><button type="button" title="Choose a different file" onclick="vrClearFile()">✕</button></div>`
                : `<input type="file" id="vr-up-file" accept=".xlsx,.xls,.csv" class="vr-up-input" onchange="vrHandleFile(this)">`}</div>
        </div>
        ${preview}
    </div>`;
}

// SheetJS is loaded from a CDN at page load, but that request can fail (blip,
// ad-blocker, offline moment). Rather than telling the user to refresh, fetch
// it on demand when a file is picked, falling back across mirrors.
let _vrXlsxLoading = null;
function _vrEnsureXlsx() {
    if (typeof XLSX !== 'undefined') return Promise.resolve();
    if (_vrXlsxLoading) return _vrXlsxLoading;
    const srcs = [
        'xlsx.full.min.js?v=0.18.5', // vendored copy — same origin, can't be CDN-blocked
        'https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js',
        'https://unpkg.com/xlsx@0.18.5/dist/xlsx.full.min.js',
        'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js',
    ];
    _vrXlsxLoading = new Promise((resolve, reject) => {
        const tryNext = i => {
            if (i >= srcs.length) {
                _vrXlsxLoading = null; // allow a retry on the next file pick
                return reject(new Error('parser unavailable'));
            }
            const s = document.createElement('script');
            s.src = srcs[i];
            s.onload = () => (typeof XLSX !== 'undefined') ? resolve() : tryNext(i + 1);
            s.onerror = () => { s.remove(); tryNext(i + 1); };
            document.head.appendChild(s);
        };
        tryNext(0);
    });
    return _vrXlsxLoading;
}

async function vrHandleFile(input) {
    const file = input.files && input.files[0];
    if (!file) return;
    try {
        await _vrEnsureXlsx();
    } catch (e) {
        alert('Could not load the Excel parser — check your internet connection and pick the file again.');
        return;
    }
    const reader = new FileReader();
    reader.onload = e => {
        try {
            const bytes = new Uint8Array(e.target.result);
            // Keep the original file (base64) so it can be stored for managers to
            // download the full breakdown later. Chunked to avoid a call-stack
            // blow-up on String.fromCharCode with a big spread.
            let bin = '';
            for (let i = 0; i < bytes.length; i += 8192) {
                bin += String.fromCharCode.apply(null, bytes.subarray(i, i + 8192));
            }
            _vrRawFileB64 = btoa(bin);
            const wb = XLSX.read(bytes, { type: 'array' });
            // The report often has a summary sheet before the line-item "Detail"
            // sheet, so scan every sheet and keep whichever one actually parses.
            let best = { items: [], skipped: 0, aboveCutoff: 0 };
            for (const name of wb.SheetNames) {
                const rows = XLSX.utils.sheet_to_json(wb.Sheets[name], { header: 1, raw: false, defval: '' });
                const parsed = _vrParseRows(rows);
                // Most importable items wins; tie-break on lines seen above the
                // cutoff so an all-filtered sheet still beats an unparsed one.
                if (parsed.items.length > best.items.length ||
                    (parsed.items.length === best.items.length && parsed.aboveCutoff > best.aboveCutoff)) best = parsed;
            }
            _vrParsed = best;
            _vrFileName = file.name;
            renderVarianceReplies();
        } catch (err) {
            alert('Could not read that file: ' + err.message);
        }
    };
    reader.readAsArrayBuffer(file);
}

// Turns the raw sheet grid into line items. Finds the header row (a row that
// mentions both "order" and "sku"), maps columns by header text, and reads
// everything below it. Tolerant of the title/banner rows above the header.
function _vrParseRows(rows) {
    const norm = s => String(s || '').trim().toLowerCase();
    let headerIdx = -1, colMap = {};
    for (let i = 0; i < Math.min(rows.length, 15); i++) {
        const joined = rows[i].map(norm).join('|');
        if (joined.includes('order') && joined.includes('sku')) { headerIdx = i; break; }
    }
    if (headerIdx === -1) return { items: [], skipped: 0 };
    // First match wins, so when two headers could match one field the left-most
    // (primary) column is kept — e.g. "Shopify Order ID" over "eBay Order ID",
    // "Buyer" over "Buyer Est (unit)".
    const set = (k, c) => { if (colMap[k] === undefined) colMap[k] = c; };
    rows[headerIdx].forEach((h, c) => {
        const n = norm(h);
        if (!n) return;
        if (n.includes('order') && !n.includes('ebay')) set('order_number', c);   // "Shopify Order ID", not "eBay Order ID"
        else if (n.includes('sku')) set('sku', c);
        else if (n.includes('title') || n.includes('description') || n.includes('product')) set('item_title', c);
        else if (n.includes('buyer') && !n.includes('est')) set('buyer_name', c);  // "Buyer", not "Buyer Est (unit)"
        else if (n.includes('lister')) set('lister_name', c);
        else if (n.includes('variance')) set('variance_pct', c);
        else if (n.includes('gm note')) set('gm_note', c);
        else if (n.includes('repl')) set('mgr_reply', c);       // "Replies to DM Notes" — check before "dm note"
        else if (n.includes('dm note')) set('dm_note', c);
    });
    const items = [];
    let skipped = 0, aboveCutoff = 0;
    for (let i = headerIdx + 1; i < rows.length; i++) {
        const row = rows[i] || [];
        const get = k => colMap[k] === undefined ? '' : String(row[colMap[k]] || '').trim();
        const orderNumber = get('order_number');
        const sku = get('sku');
        if (!orderNumber && !sku) {
            if (row.some(c => String(c).trim() !== '')) skipped++;
            continue;
        }
        const variancePct = _vrParseVariance(get('variance_pct'));
        // Only lines at -10% or worse need a manager explanation — the rest of
        // the report is noise here, so drop them at parse time.
        if (variancePct == null || variancePct > _VR_VARIANCE_CUTOFF) { aboveCutoff++; continue; }
        items.push({
            order_number: orderNumber || null,
            sku: sku || null,
            item_title: get('item_title') || null,
            buyer_name: get('buyer_name') || null,
            lister_name: get('lister_name') || null,
            variance_pct: variancePct,
            gm_note: get('gm_note') || null,
            dm_note: get('dm_note') || null,
            mgr_reply: get('mgr_reply') || null,
        });
    }
    return { items, skipped, aboveCutoff };
}

// "-25.00%" → -25; "-0.25" (an unformatted Excel percent) → -25; "-25" → -25.
function _vrParseVariance(raw) {
    const s = String(raw || '').trim();
    if (!s) return null;
    const hadPct = s.includes('%');
    const n = parseFloat(s.replace(/[%,\s]/g, ''));
    if (!Number.isFinite(n)) return null;
    if (!hadPct && Math.abs(n) <= 1.5) return Math.round(n * 10000) / 100;
    return Math.round(n * 100) / 100;
}

// Cancels the whole upload process: closes the panel and discards any parsed
// file. The file <input> lives inside the panel and is removed on re-render.
function vrCancelUpload() {
    _vrUploadOpen = false;
    _vrParsed = null;
    _vrFileName = '';
    _vrRawFileB64 = '';
    renderVarianceReplies();
}

// Swaps the parsed file out for the picker again (panel stays open).
function vrClearFile() {
    _vrParsed = null;
    _vrFileName = '';
    _vrRawFileB64 = '';
    renderVarianceReplies();
}

async function vrConfirmUpload(btn) {
    if (!_vrParsed || !_vrParsed.items.length) return;
    const store = (document.getElementById('vr-store-select') || {}).value || '';
    const timeframe = '';
    const from = (document.getElementById('vr-up-from') || {}).value;
    const to = (document.getElementById('vr-up-to') || {}).value;
    if (!from || !to) { alert('Please set the From and To dates for this report period.'); return; }
    if (from > to) { alert('The From date must be before the To date.'); return; }
    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Uploading…';
    try {
        const res = await fetch(VARIANCE_REPLIES_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'upload_period', store, date_from: from, date_to: to, timeframe,
                uploaded_by: sessionStorage.getItem('speeksUserName') || null,
                items: _vrParsed.items,
                raw_file_b64: _vrRawFileB64 || null,
                raw_file_name: _vrFileName || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Upload failed');
        _vrUploadOpen = false;
        _vrParsed = null;
        _vrFileName = '';
        _vrRawFileB64 = '';
        await loadVarianceReplies();
        // jump the pickers straight to the period we just uploaded
        const rSel = document.getElementById('vr-period-select');
        const sSel = document.getElementById('vr-store-select');
        const key = `${from}|${to}`;
        if (rSel && [...rSel.options].some(o => o.value === key)) rSel.value = key;
        if (sSel) sSel.value = store;
        const pid = _vrSelectedPeriodId();
        if (pid && (!_vrCurrent || !_vrCurrent.period || _vrCurrent.period.id !== pid)) vrOpenPeriod(pid);
    } catch (e) {
        alert('Upload failed: ' + e.message);
        btn.disabled = false; btn.innerText = old;
    }
}

// ---- reminders: pulsing dots + shared red bubble -----------------------------
// Managers get a dot on the Analytics nav-link and the Variance Replies tab
// while lines await their explanation, and again when DM notes await a reply.
// The red bubble fires once per day per period: the day before the deadline
// ("get this done before EOD tomorrow") and while DM notes sit unanswered.
let _vrRemindersStarted = false;
let _vrMyPeriodsCache = [];

function _vrDotNeeded() {
    // Cleared stores owe no replies, so they never light the action dot.
    return _vrMyPeriodsCache.some(p => !_vrStoreCleared(p.store) && ((p.items - p.answered) > 0 || p.awaiting_reply > 0));
}

async function checkVarianceReminders() {
    if (!_vrIsManager()) return;
    const stores = _vrMyStores();
    if (!stores.length) return;
    if (!_vrRemindersStarted) {
        _vrRemindersStarted = true;
        setInterval(checkVarianceReminders, 10 * 60 * 1000);
    }
    try {
        const res = await fetch(`${VARIANCE_REPLIES_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json || json.success === false) return;
        _vrStoreStatus = json.store_status || {};
        // ignore stale periods so a forgotten upload can't pin the dot forever.
        // Cleared stores stay in the cache (they still get the "report is live"
        // announcement) — the dot + reply nags are gated on cleared separately.
        const cutoff = Date.now() - 45 * 86400000;
        _vrMyPeriodsCache = (json.data || []).filter(p => new Date(p.uploaded_at).getTime() > cutoff);
        applyKpiReminder(); // re-evaluates the shared workspace nav dot + tab dot
        _vrMaybePopup();
    } catch (e) { /* next poll retries */ }
}

// DM-side reminder: fires once per period when the managers' reply window
// closes — the deadline passes, or every line gets explained early — and the
// DM hasn't left any notes yet. The manager-side popups above don't apply to
// the DM, so this is their "your turn" ping.
async function checkVarianceDmReminders() {
    if (!_vrIsDM()) return;
    if (!_vrDmRemindersStarted) {
        _vrDmRemindersStarted = true;
        setInterval(checkVarianceDmReminders, 10 * 60 * 1000);
    }
    try {
        const res = await fetch(`${VARIANCE_REPLIES_URL}?stores=OVL,LEE,WSP,MPL,BAL&v=${Date.now()}`);
        const json = await res.json();
        if (!json || json.success === false) return;
        _vrStoreStatus = json.store_status || {};
        const now = Date.now();
        const cutoff = now - 45 * 86400000;
        // Skip stores the DM has marked "in the clear" — no review nudges for them.
        const periods = (json.data || []).filter(p =>
            new Date(p.uploaded_at).getTime() > cutoff && !_vrStoreCleared(p.store));
        // State-based, like the manager side: persists until the DM acts, then
        // clears — no one-shot localStorage that vanished on navigation.
        // Track WHICH stores need the DM's eyes, so clicking the alert lands on one
        // that actually needs review (not a default/empty store). Stores where a
        // manager has replied to a flagged note sort first — that's the "see the
        // manager's replies" case the DM cares about.
        const readyStores = []; // managers done / deadline passed, no DM notes yet
        const closedStores = []; // reply window fully closed → final review
        const repliedClosed = new Set(); // closed stores where a mgr reply came in
        for (const p of periods) {
            if (!p.items) continue;
            const store = (p.store || '').toUpperCase();
            if (!p.dm_notes_at) {
                const allDone = p.answered >= p.items;
                const duePassed = now > new Date(p.manager_due_at).getTime();
                if (allDone || duePassed) readyStores.push(store);
            } else {
                const replyDue = Math.max(new Date(p.manager_due_at).getTime(), new Date(p.dm_notes_at).getTime()) + 2 * 86400000;
                if (now >= replyDue) {
                    closedStores.push(store);
                    // A flagged note the manager HAS answered (mgr_replied, from the
                    // edge fn) means there's a reply here for the DM to read.
                    if (p.mgr_replied > 0) repliedClosed.add(store);
                }
            }
        }
        // Put stores with actual manager replies first so the click lands there.
        const closedOrdered = [...closedStores].sort((a, b) => (repliedClosed.has(b) ? 1 : 0) - (repliedClosed.has(a) ? 1 : 0));
        const readyForReview = readyStores.length > 0;
        const windowClosed = closedStores.length > 0;
        // Ethan wants these lightweight — no store names or counts, just a nudge
        // to go look. "Ready for review" (their turn) outranks the wrap-up.
        if (readyForReview) {
            _vrRenderBubble('📝', 'Variance replies are ready for review',
                'Manager explanations are in — review them and add your DM notes.',
                'Manager explanations are in — review and add your DM notes.', readyStores);
        } else if (windowClosed) {
            _vrRenderBubble('📬', 'Variance reply window closed',
                'The managers’ response window has ended — give the replies a final review.',
                'Reply window closed — give the replies a final review.', closedOrdered);
        } else {
            const b = document.getElementById('varianceAlertBubble');
            if (b && getComputedStyle(b).display !== 'none') {
                b.style.display = 'none';
                if (typeof _positionVarianceAlert === 'function') _positionVarianceAlert();
            }
        }
    } catch (e) { /* next poll retries */ }
}
let _vrDmRemindersStarted = false;

// "DM reviewed your replies" is an FYI (no reply requested), so it clears once the
// manager opens the tool — tracked per user as { periodId: dm_notes_at_ms }. A
// reply-REQUESTED note is different: that's state-based and nags until answered.
function _vrReviewSeenKey() {
    const u = (sessionStorage.getItem('speeksUserName') || 'anon').trim().toLowerCase();
    return 'speeksVRReviewSeen_' + u;
}
function _vrGetReviewSeen() {
    try { return JSON.parse(localStorage.getItem(_vrReviewSeenKey()) || '{}') || {}; } catch (_) { return {}; }
}
function _vrSetReviewSeen(m) { try { localStorage.setItem(_vrReviewSeenKey(), JSON.stringify(m || {})); } catch (_) {} }

// Combine a store list into "BAL", "BAL and MPL", "OVL, LEE, and WSP".
function _vrFmtStores(stores) {
    const u = [...new Set(stores.map(s => (s || '').toUpperCase()).filter(Boolean))];
    if (u.length <= 1) return u[0] || '';
    if (u.length === 2) return `${u[0]} and ${u[1]}`;
    return `${u.slice(0, -1).join(', ')}, and ${u[u.length - 1]}`;
}

// Manager / MSM variance feed row. STATE-based, NOT one-shot: it reflects the
// actual outstanding work and re-derives every poll, so it survives navigating
// into the tool and only leaves when the work is done (or the user snoozes it in
// the feed). The old version fired a one-time toast per period gated by a
// localStorage "seen" key — so clicking through to the tool set the key and the
// row vanished even with nothing answered. An MSM covers two stores and the DM
// normally uploads all five the same day (so BAL + MPL arrive together), hence
// ONE combined row that lists the stores ("BAL and MPL: …") rather than a
// separate popup per store. Cleared stores owe nothing, so they add no row.
function _vrMaybePopup() {
    const now = Date.now();
    const reviewSeen = _vrGetReviewSeen();
    const explainStores = [];   // stores with unexplained lines
    let explainCount = 0, explainOverdue = false, explainDueSoon = false;
    const replyStores = [];     // stores with DM notes still awaiting a reply
    let replyCount = 0, replyOverdue = false;
    const reviewedStores = [];  // DM reviewed, no reply needed — FYI until they look

    for (const p of _vrMyPeriodsCache) {
        if (_vrStoreCleared(p.store)) continue;
        const store = (p.store || '').toUpperCase();
        const unanswered = (p.items || 0) - (p.answered || 0);
        const due = new Date(p.manager_due_at).getTime();
        if (unanswered > 0) {
            explainStores.push(store);
            explainCount += unanswered;
            if (now > due) explainOverdue = true;
            else if (due - now < 24 * 3600 * 1000) explainDueSoon = true; // last day before the deadline
        }
        if (p.dm_notes_at) {
            if (p.awaiting_reply > 0) {
                // Reply REQUESTED → action, nags until answered.
                replyStores.push(store);
                replyCount += p.awaiting_reply;
                const replyDue = Math.max(due, new Date(p.dm_notes_at).getTime()) + 2 * 86400000;
                if (now > replyDue) replyOverdue = true;
            } else {
                // DM reviewed with NO reply requested (or all replies already in) →
                // one-time FYI so the manager reads the notes. Clears when they open
                // the tool (loadVarianceReplies stamps the seen map).
                const notesMs = new Date(p.dm_notes_at).getTime();
                if (notesMs > (reviewSeen[p.id] || 0)) reviewedStores.push(store);
            }
        }
    }

    if (!explainStores.length && !replyStores.length && !reviewedStores.length) {
        // Nothing outstanding — drop the row so it clears once the work's done.
        const b = document.getElementById('varianceAlertBubble');
        if (b && getComputedStyle(b).display !== 'none') {
            b.style.display = 'none';
            if (typeof _positionVarianceAlert === 'function') _positionVarianceAlert();
        }
        return;
    }

    const parts = [];
    if (explainStores.length) {
        const tag = explainOverdue ? ' (overdue)' : (explainDueSoon ? ' (due tomorrow)' : '');
        parts.push(`${_vrFmtStores(explainStores)}: ${explainCount} variance line${explainCount > 1 ? 's need' : ' needs'} an explanation${tag}`);
    }
    if (replyStores.length) {
        parts.push(`${_vrFmtStores(replyStores)}: reply to ${replyCount} DM note${replyCount > 1 ? 's' : ''}${replyOverdue ? ' (overdue)' : ''}`);
    }
    if (reviewedStores.length) {
        parts.push(`${_vrFmtStores(reviewedStores)}: DM reviewed your replies — take a look`);
    }
    const summary = parts.join(' · ');
    const overdue = explainOverdue || replyOverdue;
    const coveredStores = [...explainStores, ...replyStores, ...reviewedStores];
    // Three tiers: overdue → dueSoon → normal. The bubble itself is invisible
    // (retired toast); only the summary reaches the feed, which drives both the row
    // text and — since no data-sig is set — the snooze signature, so a changed
    // count OR a changed urgency tag re-surfaces a snoozed row.
    _vrRenderBubble(overdue ? '🚨' : (explainDueSoon ? '⏰' : '📊'),
        overdue ? 'Variance replies overdue' : (explainDueSoon ? 'Variance replies due tomorrow' : 'Variance replies needed'),
        summary + '.', summary, coveredStores);
}

// Same shared red bubble as the claim reminders, with a button into the tab.
// Variance's own bubble — amber, created on demand next to the shared claim
// bubble so it inherits the same header stacking context. Like the recycle
// bubble, it stacks below whatever other bubbles are showing instead of
// fighting them for the shared red one.
function _vrBubbleEl() {
    let b = document.getElementById('varianceAlertBubble');
    if (b) return b;
    const claim = document.getElementById('claimAlertBubble');
    if (!claim || !claim.parentElement) return null;
    b = document.createElement('div');
    b.id = 'varianceAlertBubble';
    b.style.cssText = 'display:none; position:fixed; top:116px; right:24px; background:linear-gradient(135deg, #d97706, #92400e); color:white; padding:11px 14px 11px 16px; border-radius:14px; align-items:flex-start; gap:8px; font-size:13px; box-shadow:0 10px 28px rgba(120, 53, 15, 0.38); max-width:min(380px, calc(100vw - 48px)); z-index:998;';
    b.innerHTML = `<span id="varianceAlertBubbleIcon" style="font-size:16px; flex-shrink:0; margin-top:2px;">📊</span>
        <span id="varianceAlertBubbleText" style="white-space:normal; overflow-y:auto; max-height:220px;"></span>
        <button onclick="closeVarianceAlertBubble()" class="daily-bubble-close" title="Dismiss">
            <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
        </button>`;
    claim.parentElement.appendChild(b);
    return b;
}

// Bottom of the stack: below the store comment, claim alert and recycle bubble.
function _positionVarianceAlert() {
    const b = document.getElementById('varianceAlertBubble');
    if (!b) return;
    let top = 116;
    ['dailyMessageBubble', 'claimAlertBubble', 'recycleAlertBubble'].forEach(id => {
        const el = document.getElementById(id);
        if (el && getComputedStyle(el).display !== 'none' && el.offsetHeight > 0) {
            top = Math.max(top, el.getBoundingClientRect().bottom + 12);
        }
    });
    b.style.top = top + 'px';
    // The aging-inventory bubble sits below this one — re-flow it when this moves.
    if (typeof _positionAgingAlert === 'function') _positionAgingAlert();
}

function closeVarianceAlertBubble() {
    const b = document.getElementById('varianceAlertBubble');
    if (b) b.style.display = 'none';
}

function _vrRenderBubble(icon, title, bodyText, summary, stores) {
    const b = _vrBubbleEl();
    if (!b) return;
    const iconEl = document.getElementById('varianceAlertBubbleIcon');
    const textEl = document.getElementById('varianceAlertBubbleText');
    // Feed one-liner — without it the Action Menu scrapes the bubble and repeats
    // its title (already the feed row's own title). The body/summary is the point.
    if (textEl) {
        textEl.dataset.summary = String(summary || bodyText).replace(/\s+/g, ' ').trim();
        // Stores this alert covers → the feed uses it to route an MSM single-store
        // click to that store (see _samGatherReminders).
        if (stores && stores.length) textEl.dataset.stores = [...new Set(stores)].join(',');
        else delete textEl.dataset.stores;
    }
    if (iconEl) iconEl.textContent = icon;
    textEl.style.display = 'flex';
    textEl.style.flexDirection = 'column';
    textEl.style.gap = '7px';
    textEl.innerHTML = `
        <div style="line-height:1.4;"><strong>${escapeHtml(title)}</strong></div>
        <div style="line-height:1.4; opacity:0.96;">${escapeHtml(bodyText)}</div>
        <button onclick="closeVarianceAlertBubble(); window.location.href='workspace.html#vreplies';"
            style="align-self:flex-start; background:rgba(255,255,255,0.18); border:1px solid rgba(255,255,255,0.5); color:#fff; font-weight:800; font-size:12px; border-radius:8px; padding:6px 12px; cursor:pointer;"
            onmouseover="this.style.background='rgba(255,255,255,0.3)';" onmouseout="this.style.background='rgba(255,255,255,0.18)';">Open Variance Replies</button>`;
    b.style.display = 'flex';
    _positionVarianceAlert();
    // Re-stack shortly after: the store comment fades in on its own 1.5s timer
    // and the claim/recycle bubbles may land on later checks.
    setTimeout(_positionVarianceAlert, 2200);
    b.animate([
        { transform: 'scale(0.95) translateX(10px)', opacity: 0 },
        { transform: 'scale(1) translateX(0)', opacity: 1 }
    ], { duration: 400, easing: 'cubic-bezier(0.4, 0, 0.2, 1)' });
}

// ============================================================
// AGING INVENTORY (workspace tab)
// ============================================================
// Each week the DM hand-picks the most valuable 30-day-plus items from the POS
// and adds them here with an opening note (fix the listing / answer a question).
// The store (manager or ASM) has one week to reply; every DM follow-up restarts
// that clock. Notes are an unlimited alternating thread per item — replacing
// the per-store aging spreadsheet. Row colors match the old sheet: purple = new
// item awaiting the store's first reply, yellow = DM follow-up awaiting a reply,
// white = ball in the DM's court, green = sold (closed), red = recycled (closed).

const _AG_STORE_ROLES = new Set(['manager', 'owner (manager)', 'owner manager', 'assistant manager']);

function _agRole() { return (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim(); }
// A manager can be delegated the DM side (Feature Access → Delegation →
// "Aging Inventory (DM)") — same pattern as cap-variance-dm: they wear the DM
// hat exclusively (all-store dropdown, add form, close buttons, DM popups).
function _agHasDmDelegation() {
    if (typeof _featureOverrideFor !== 'function') return false;
    const roleClass = 'role-' + _agRole().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, '-');
    const name = sessionStorage.getItem('speeksUserName') || '';
    return _featureOverrideFor('cap-aging-dm', roleClass, name) === true;
}
function _agIsDM() { return _agRole() === 'district manager' || _agHasDmDelegation(); }
function _agIsStoreUser() { return _AG_STORE_ROLES.has(_agRole()) && !_agHasDmDelegation(); }

// The store user's own store(s) — an MSM sees both, stacked in one list.
function _agMyStores() {
    if (typeof isMultiStoreManager === 'function' && isMultiStoreManager()) {
        return [...MULTISTORE_MANAGER_STORES];
    }
    const s = (sessionStorage.getItem('speeksUserStore') || '').toUpperCase();
    return (s && s !== 'ALL' && s !== 'CORP') ? [s] : [];
}

let _agItems = [];        // everything the GET returned (all my stores / all 5 for DM)
let _agAddOpen = false;   // DM add-item panel
let _agEditItem = null;   // item id whose info fields are being edited (DM typo fix)
let _agDrafts = {};       // "itemId|side" → unsaved reply text, survives re-renders
let _agJustAdded = '';    // "✓ Added …" chip in the add panel after an add
let _agStoreEdit = null;  // note id the store user is re-editing (their latest reply)
let _agClosedOpen = {};   // store → whether its "Closed Items" section is expanded (kept across re-renders)

const _agMoney = v => (v == null || v === '') ? '—'
    : '$' + Number(v).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
// The "Date listed" field is typed by hand as DD/MM/YYYY (Ethan's preference —
// hunting through a picker for a months-old date is slow). Lenient parse:
// -, . or / separators, 2-digit years, and a US-style month-first entry is
// auto-swapped when the day slot can only be a month (e.g. 16/03 vs 03/16).
function _agParseDMY(s) {
    const m = String(s || '').trim().match(/^(\d{1,2})[\/\-.](\d{1,2})[\/\-.](\d{2,4})$/);
    if (!m) return null;
    let d = +m[1], mo = +m[2], y = +m[3];
    if (y < 100) y += 2000;
    if (mo > 12 && d <= 12) { const t = d; d = mo; mo = t; }
    if (d < 1 || d > 31 || mo < 1 || mo > 12 || y < 2000 || y > 2100) return null;
    const dt = new Date(Date.UTC(y, mo - 1, d));
    if (dt.getUTCMonth() !== mo - 1 || dt.getUTCDate() !== d) return null;
    return `${y}-${String(mo).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
}
function _agFmtDMY(iso) {
    if (!iso) return '';
    const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})/);
    return m ? `${m[3]}/${m[2]}/${m[1]}` : '';
}
// Shared oninput mask for the DD/MM/YYYY fields: digits only, the slashes are
// inserted automatically, capped at ##/##/####.
const _AG_DATE_MASK = "const d=this.value.replace(/\\D/g,'').slice(0,8); this.value=d.length>4?d.slice(0,2)+'/'+d.slice(2,4)+'/'+d.slice(4):(d.length>2?d.slice(0,2)+'/'+d.slice(2):d);";
const _agFmtDate = d => { const x = new Date(d); return isNaN(x.getTime()) ? '' : x.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }); };
const _agFmtDue = d => { const x = new Date(d); return isNaN(x.getTime()) ? '' : x.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }); };

// Where an open item sits in the cycle, from its note thread:
//   purple  — the store has never replied (brand-new DM pick)
//   yellow  — the DM followed up and is waiting on the store again
//   dm      — the store replied last; the DM reviews next
function _agState(it) {
    if (it.status !== 'open') return it.status; // 'sold' | 'recycled'
    const notes = it.notes || [];
    // No DM note yet → the DM posted the line but hasn't written the note telling
    // the store what to do, so it's NOT the store's turn and no nudge fires. (A DM
    // always leaves a note; this just holds the alert until they do.)
    if (!notes.some(n => n.author_side === 'dm')) return 'new';
    const last = notes[notes.length - 1];
    if (last.author_side === 'dm') {
        return notes.some(n => n.author_side === 'store') ? 'yellow' : 'purple';
    }
    return 'dm';
}
// 'new' (no DM note) is deliberately excluded — the store isn't nagged until the
// DM has actually left their note.
const _agAwaitingStore = it => ['purple', 'yellow'].includes(_agState(it));
const _agOverdue = it => _agAwaitingStore(it) && it.due_at && Date.now() > new Date(it.due_at).getTime();

// Row-edit mode enter/leave — in-progress note-edit drafts don't outlive it.
function _agClearNeDrafts() {
    Object.keys(_agDrafts).forEach(k => { if (k.startsWith('ne|')) delete _agDrafts[k]; });
}
function agStartItemEdit(id) { _agEditItem = id; _agClearNeDrafts(); renderAgingInventory(); }
function agCancelItemEdit() { _agEditItem = null; _agClearNeDrafts(); renderAgingInventory(); }

// ---- load & render -----------------------------------------------------------
async function loadAgingInventory() {
    const body = document.getElementById('ag-body');
    if (!body) return;
    body.innerHTML = '<div class="status-message">Loading aging inventory…</div>';
    const stores = _agIsDM() ? ['OVL', 'LEE', 'WSP', 'MPL', 'BAL'] : _agMyStores();
    if (!stores.length) {
        body.innerHTML = '<div class="status-message">No store assigned to your account.</div>';
        return;
    }
    try {
        const res = await fetch(`${AGING_INV_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json.success) throw new Error(json.error);
        _agItems = json.data || [];
        // Keep the reminder cache in step so the dots clear the moment a reply
        // is visible here (instead of waiting for the next 10-minute poll).
        if (_agIsStoreUser()) {
            _agMyItemsCache = _agItems.filter(it => it.status === 'open');
            if (typeof applyKpiReminder === 'function') applyKpiReminder();
        }
        // NOTE: don't touch ag-store-select's display here — applyRoleBasedUI
        // owns it (dynamic-module-block + role-district-manager); clearing the
        // inline style it set would re-hide the dropdown.
        renderAgingInventory();
    } catch (e) {
        body.innerHTML = '<div class="status-message" style="color:var(--red-alert);">Failed to load the aging inventory report.</div>';
    }
}

function agOnStoreChange() {
    _agAddOpen = false; _agEditItem = null; _agDrafts = {}; _agJustAdded = ''; _agStoreEdit = null;
    renderAgingInventory(); // all stores are already loaded — just re-filter
}

// The stores the current render shows (the DM flips with the dropdown; a store
// user gets their own store(s), an MSM both at once).
let _agViewStore = null; // MSM aging view store, resolved once per tab-open (see switchWorkspaceTab)
function _agVisibleStores() {
    if (_agIsDM()) return [((document.getElementById('ag-store-select') || {}).value || 'OVL').toUpperCase()];
    // MSM: show one store's items (switch dashboards for the other) instead of
    // stacking both. _agViewStore is resolved at tab-open — a single-store alert
    // override if one was pending, else the active dashboard store. The reminder
    // still covers every managed store via _agMyStores(), and _agItems is fetched
    // for all of them — this only scopes the on-screen view. Single-store managers
    // are unaffected.
    const def = _agViewStore || _msmDefaultStore();
    return def ? [def] : _agMyStores();
}

function _agSubtitleText() {
    const open = _agItems.filter(it => it.status === 'open');
    if (_agIsDM()) {
        const waiting = open.filter(it => _agState(it) === 'dm').length;
        return waiting ? `${waiting} repl${waiting > 1 ? 'ies' : 'y'} waiting on your review` : '';
    }
    const mine = open.filter(_agAwaitingStore);
    if (!mine.length) return '';
    const overdue = mine.filter(_agOverdue).length;
    return `${mine.length} item${mine.length > 1 ? 's' : ''} need${mine.length > 1 ? '' : 's'} your reply${overdue ? ` · ${overdue} overdue` : ''}`;
}

function renderAgingInventory() {
    const body = document.getElementById('ag-body');
    if (!body) return;
    // Stash any typed replies / in-progress note edits so no re-render can
    // delete them.
    body.querySelectorAll('textarea[data-ag-reply]').forEach(ta => { _agDrafts[ta.dataset.agReply] = ta.value; });
    body.querySelectorAll('textarea[data-ag-noteedit]').forEach(ta => { _agDrafts['ne|' + ta.dataset.agNoteedit] = ta.value; });
    body.querySelectorAll('textarea[data-ag-storeedit]').forEach(ta => { _agDrafts['se|' + ta.dataset.agStoreedit] = ta.value; });
    // Remember which "Closed Items" sections are expanded so a re-render (e.g.
    // deleting one closed item) doesn't collapse them mid-cleanup.
    body.querySelectorAll('details[data-ag-closed]').forEach(d => { _agClosedOpen[d.dataset.agClosed] = d.open; });

    const canDm = _agIsDM();
    const addBtn = document.getElementById('ag-add-btn');
    const addCancelBtn = document.getElementById('ag-add-cancel-btn');
    if (addBtn && canDm) addBtn.style.display = 'inline-flex';
    if (addCancelBtn) addCancelBtn.style.display = (canDm && _agAddOpen) ? 'inline-flex' : 'none';

    let html = '';
    if (canDm && _agAddOpen) html += _agAddPanelHtml();

    const stores = _agVisibleStores();
    const multi = stores.length > 1;
    stores.forEach(store => {
        const storeItems = _agItems.filter(it => it.store === store);
        if (multi) html += `<div style="font-size:13px; font-weight:800; color:var(--slate-charcoal); text-transform:uppercase; letter-spacing:.5px; margin:18px 14px 6px;">🏬 ${escapeHtml(store)}</div>`;
        html += _agStoreSectionHtml(store, storeItems, canDm);
    });
    if (!stores.length) html += `<div style="padding:36px 20px; text-align:center; color:#94a3b8; font-weight:600;">No store assigned to your account.</div>`;
    body.innerHTML = html;

    const sub = document.getElementById('ag-subtitle');
    if (sub) sub.textContent = _agSubtitleText();
}

function _agStoreSectionHtml(store, storeItems, canDm) {
    const active = storeItems.filter(it => it.status === 'open');
    const closed = storeItems.filter(it => it.status !== 'open');
    // Items waiting on the store float to the top (overdue first, then by
    // deadline); items waiting on the DM sit below them.
    const stateRank = { purple: 0, yellow: 0, dm: 1 };
    active.sort((a, b) => {
        const r = stateRank[_agState(a)] - stateRank[_agState(b)];
        if (r) return r;
        const od = (_agOverdue(b) ? 1 : 0) - (_agOverdue(a) ? 1 : 0);
        if (od) return od;
        return new Date(a.due_at || a.created_at) - new Date(b.due_at || b.created_at);
    });
    closed.sort((a, b) => new Date(b.closed_at || 0) - new Date(a.closed_at || 0));

    let html = '';
    if (!active.length) {
        html += `<div style="padding:28px 20px; text-align:center; color:#94a3b8; font-weight:600;">${canDm ? 'No open aging items for this store — add the week’s picks with ＋ Add Item.' : 'No open aging items for your store right now. 🎉'}</div>`;
    } else {
        html += _agTableHtml(active, canDm);
    }
    if (closed.length) {
        html += `<details data-ag-closed="${store}"${_agClosedOpen[store] ? ' open' : ''} style="margin:14px 14px 6px;">
            <summary style="cursor:pointer; font-size:12px; font-weight:800; color:#64748b;">Closed Items — Sold or Recycled (${closed.length})</summary>
            <div style="margin-top:10px;">${_agTableHtml(closed, canDm)}</div>
        </details>`;
    }
    return html;
}

// Row tints matching the old spreadsheet's color key.
const _AG_ROW_BG = { purple: '#f3e8ff', yellow: '#fef9c3', dm: '#ffffff', sold: '#dcfce7', recycled: '#fee2e2' };

function _agStatusChip(it) {
    const s = _agState(it);
    const chip = (txt, fg, bg, bd) => `<span style="display:inline-block; font-size:9.5px; font-weight:800; color:${fg}; background:${bg}; border:1px solid ${bd}; border-radius:20px; padding:2px 8px; white-space:nowrap;">${txt}</span>`;
    if (s === 'sold') return chip('✓ Sold', '#166534', '#dcfce7', '#a7f3d0');
    if (s === 'recycled') return chip('♻ Recycled', '#b91c1c', '#fee2e2', '#fca5a5');
    const due = it.due_at ? ` · by ${_agFmtDue(it.due_at)}` : '';
    const overdue = _agOverdue(it) ? `<div style="margin-top:5px;">${chip('⚠ Overdue', '#b91c1c', '#fee2e2', '#fca5a5')}</div>` : '';
    // DM posted the line but hasn't left their note yet — not the store's turn.
    if (s === 'new') return chip('🆕 New — Awaiting DM note', '#6d28d9', '#ede9fe', '#c4b5fd');
    if (s === 'purple') return chip(`📩 Reply Needed${due}`, '#6d28d9', '#ede9fe', '#c4b5fd') + overdue;
    if (s === 'yellow') return chip(`↩ Follow-Up — Reply Needed${due}`, '#a16207', '#fef9c3', '#fde047') + overdue;
    return chip('⏳ Waiting on the DM', '#475569', '#f1f5f9', '#e2e8f0');
}

function _agTableHtml(items, canDm) {
    const th = t => `<th style="text-align:left; font-size:9.5px; font-weight:800; text-transform:uppercase; letter-spacing:.4px; color:#94a3b8; padding:8px 14px; border-bottom:1px solid #e2e8f0; white-space:nowrap;">${t}</th>`;
    let html = `<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; min-width:${canDm ? 1020 : 940}px;">
        <thead><tr>${th('Status')}${th('SKU')}${th('Item')}${th('Listed')}${th('Est. Value')}${th('Cost')}${th('Notes & Replies')}${canDm ? th('') : ''}</tr></thead><tbody>`;
    items.forEach(it => { html += _agRowHtml(it, canDm); });
    return html + `</tbody></table></div>`;
}

function _agRowHtml(it, canDm) {
    const bg = _AG_ROW_BG[_agState(it)] || '#ffffff';
    const td = (c, extra = '') => `<td style="padding:10px 14px; border-bottom:1px solid #f1f5f9; vertical-align:top; font-size:12px; background:${bg}; ${extra}">${c}</td>`;
    const days = it.date_created ? Math.max(0, Math.floor((Date.now() - new Date(it.date_created).getTime()) / 86400000)) : null;
    if (_agEditItem === it.id) {
        const inp = (f, v, type = 'text', w = '110px', extra = '') => `<input type="${type}" data-ag-edit="${f}" value="${escapeHtml(v == null ? '' : String(v))}" class="vr-up-input" style="width:${w}; font-size:12px;"${extra}>`;
        return `<tr data-ag-item-row="${it.id}">
            ${td(_agStatusChip(it))}
            ${td(inp('sku', it.sku, 'text', '140px'))}
            ${td(inp('title', it.title, 'text', '240px'))}
            ${td(inp('date_created', _agFmtDMY(it.date_created), 'text', '105px', ` placeholder="DD/MM/YYYY" maxlength="10" oninput="${_AG_DATE_MASK}"`))}
            ${td(inp('est_value', it.est_value, 'number', '90px'))}
            ${td(inp('cost', it.cost, 'number', '90px'))}
            ${td(_agThreadHtml(it, canDm, true))}
            ${td(`<div style="display:flex; flex-direction:column; gap:5px;">
                <button class="btn-primary" style="font-size:11px; padding:4px 10px;" onclick="agSaveItemEdit(this, '${it.id}')">Save</button>
                <button class="btn-secondary" style="font-size:11px; padding:4px 10px;" onclick="agCancelItemEdit()">Cancel</button>
            </div>`, 'white-space:nowrap;')}
        </tr>`;
    }
    const actions = !canDm ? '' : td(`<div style="display:flex; flex-direction:column; gap:5px; align-items:stretch;">${
        it.status === 'open'
            ? `<button title="Item sold — close it (green)" style="font-size:11px; font-weight:800; color:#166534; background:#dcfce7; border:1px solid #a7f3d0; border-radius:7px; padding:4px 10px; cursor:pointer; white-space:nowrap;" onclick="agSetStatus('${it.id}', 'sold')">✓ Sold</button>
               <button title="Item recycled out of inventory — close it (red)" style="font-size:11px; font-weight:800; color:#b91c1c; background:#fee2e2; border:1px solid #fca5a5; border-radius:7px; padding:4px 10px; cursor:pointer; white-space:nowrap;" onclick="agSetStatus('${it.id}', 'recycled')">♻ Recycled</button>
               <button title="Edit the item details and your notes" style="font-size:11px; font-weight:700; color:#475569; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:7px; padding:4px 10px; cursor:pointer; white-space:nowrap;" onclick="agStartItemEdit('${it.id}')">✎ Edit</button>`
            : `<button title="Put this item back on the open list" style="font-size:11px; font-weight:700; color:#475569; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:7px; padding:4px 10px; cursor:pointer; white-space:nowrap;" onclick="agSetStatus('${it.id}', 'open')">↩ Reopen</button>`
        }<button title="Delete this item and its whole thread" style="font-size:11px; font-weight:700; color:#475569; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:7px; padding:4px 10px; cursor:pointer; white-space:nowrap;" onclick="agDeleteItem('${it.id}')">🗑 Delete</button>
    </div>`, 'white-space:nowrap;');
    return `<tr>
        ${td(_agStatusChip(it), 'min-width:150px;')}
        ${td(`<span style="font-weight:700; white-space:nowrap; color:#64748b;">${escapeHtml(it.sku || '—')}</span>`)}
        ${td(`<span style="color:var(--slate-charcoal); font-weight:600;">${escapeHtml(it.title || '—')}</span>`, 'min-width:200px;')}
        ${td(it.date_created ? `<span style="white-space:nowrap;">${_agFmtDMY(it.date_created)}${days != null ? ` <span style="color:#94a3b8; font-weight:700;">· ${days}d</span>` : ''}</span>` : '—')}
        ${td(`<span style="font-weight:800; white-space:nowrap;">${_agMoney(it.est_value)}</span>`)}
        ${td(`<span style="white-space:nowrap; color:#64748b;">${_agMoney(it.cost)}</span>`)}
        ${td(_agThreadHtml(it, canDm), 'min-width:300px; width:38%;')}
        ${actions}
    </tr>`;
}

// The alternating DM ↔ store note thread, plus a reply box for whichever side
// the viewer is on (open items only) — strictly turn-based:
//   - The store's reply box only shows while the DM's note is the last word;
//     once they post, the reply locks, with an "✎ Edit your reply" button on
//     it until the deadline passes (any store user can edit it — a manager
//     can fix up or add to an ASM's reply and vice versa).
//   - The DM only gets the box when the store spoke last (or the thread is
//     empty and the opening note still needs writing).
//   - In DM row-edit mode (`editing`) the DM's notes become editable
//     textareas, but ONLY the ones the store hasn't answered yet — history
//     the conversation moved past is locked.
function _agThreadHtml(it, canDm, editing) {
    const notes = it.notes || [];
    const last = notes[notes.length - 1];
    const lastStoreIdx = notes.map(n => n.author_side).lastIndexOf('store');
    const isStore = !canDm && _agIsStoreUser();
    const beforeDue = !it.due_at || Date.now() < new Date(it.due_at).getTime();
    let html = `<div style="display:flex; flex-direction:column; gap:6px;">`;
    notes.forEach((n, idx) => {
        const dm = n.author_side === 'dm';
        const cap = `<div style="font-size:10px; font-weight:800; color:${dm ? '#6d28d9' : '#475569'};">${dm ? 'DM' : 'Store'}${n.author_name ? ' · ' + escapeHtml(n.author_name) : ''} · ${_agFmtDate(n.created_at)}</div>`;
        if (editing && canDm && dm && idx > lastStoreIdx) {
            const neDraft = _agDrafts['ne|' + n.id];
            html += `<div style="border-left:3px solid #8b5cf6; background:rgba(139,92,246,0.08); border-radius:0 8px 8px 0; padding:6px 10px;">
                ${cap}
                <textarea rows="2" data-ag-noteedit="${n.id}"
                    style="width:100%; box-sizing:border-box; margin-top:4px; padding:6px 8px; border:1.5px solid #cbd5e1; border-radius:7px; font-size:12px; font-weight:500; font-family:inherit; line-height:1.4; resize:vertical; background:#fff;">${escapeHtml(neDraft !== undefined ? neDraft : n.body)}</textarea>
            </div>`;
            return;
        }
        if (isStore && _agStoreEdit === n.id) {
            const seDraft = _agDrafts['se|' + n.id];
            html += `<div style="border-left:3px solid #94a3b8; background:rgba(148,163,184,0.10); border-radius:0 8px 8px 0; padding:6px 10px;">
                ${cap}
                <textarea rows="2" data-ag-storeedit="${n.id}"
                    style="width:100%; box-sizing:border-box; margin-top:4px; padding:6px 8px; border:1.5px solid #cbd5e1; border-radius:7px; font-size:12px; font-weight:500; font-family:inherit; line-height:1.4; resize:vertical; background:#fff;">${escapeHtml(seDraft !== undefined ? seDraft : n.body)}</textarea>
                <div style="display:flex; gap:6px; margin-top:6px;">
                    <button class="btn-primary" style="font-size:11px; padding:5px 13px;" onclick="agSaveStoreEdit(this, '${it.id}', '${n.id}')">Save</button>
                    <button class="btn-secondary" style="font-size:11px; padding:5px 13px;" onclick="agCancelStoreEdit()">Cancel</button>
                </div>
            </div>`;
            return;
        }
        // Show who last edited a note when it wasn't the original author — e.g.
        // a manager tidying up an ASM's reply (or vice versa).
        const editedTag = (n.edited_by && n.edited_by !== n.author_name)
            ? `<div style="font-size:9.5px; font-style:italic; color:#94a3b8; margin-top:3px;">~ edited by ${escapeHtml(n.edited_by)}${n.edited_at ? ' · ' + _agFmtDate(n.edited_at) : ''}</div>`
            : '';
        html += `<div style="border-left:3px solid ${dm ? '#8b5cf6' : '#94a3b8'}; background:${dm ? 'rgba(139,92,246,0.08)' : 'rgba(148,163,184,0.10)'}; border-radius:0 8px 8px 0; padding:6px 10px;">
            ${cap}
            <div style="font-size:12px; color:#334155; line-height:1.45; white-space:pre-wrap;">${escapeHtml(n.body)}</div>
            ${editedTag}
        </div>`;
        // The store's latest reply stays editable until the deadline passes
        // (or the DM moves the conversation on).
        if (isStore && it.status === 'open' && !dm && idx === notes.length - 1 && !_agStoreEdit && beforeDue) {
            html += `<div><button style="font-size:11px; font-weight:700; color:#475569; background:#f1f5f9; border:1px solid #e2e8f0; border-radius:7px; padding:4px 10px; cursor:pointer;" onclick="agStartStoreEdit('${n.id}')">✎ Edit Your Reply</button></div>`;
        }
    });
    if (it.status === 'open' && !editing) {
        let side = canDm ? 'dm' : (isStore ? 'store' : null);
        // Not the DM's turn while their own note is the one awaiting a reply;
        // not the store's turn unless a DM note is the last word.
        if (side === 'dm' && last && last.author_side === 'dm') side = null;
        if (side === 'store' && (!last || last.author_side !== 'dm')) side = null;
        if (side) {
            const key = `${it.id}|${side}`;
            const draft = _agDrafts[key] || '';
            const ph = side === 'dm'
                ? (notes.length
                    ? 'Follow-up question or instruction… (restarts their 1-week clock)'
                    : 'Your note to the store — what to fix, or your question…')
                : 'Reply to the DM — answer the question, or confirm it’s fixed…';
            html += `<div style="display:flex; gap:6px; align-items:flex-end; margin-top:2px;">
                <textarea rows="2" placeholder="${escapeHtml(ph)}" data-ag-reply="${key}"
                    style="flex:1; box-sizing:border-box; padding:7px 9px; border:1.5px solid #cbd5e1; border-radius:7px; font-size:12px; font-weight:500; font-family:inherit; line-height:1.4; resize:vertical; background:#fff;">${escapeHtml(draft)}</textarea>
                <button class="btn-primary" style="font-size:11.5px; padding:7px 13px; white-space:nowrap;" onclick="agPostNote(this, '${it.id}', '${side}')">Post</button>
            </div>`;
        }
    }
    return html + `</div>`;
}

// ---- store-side "edit your reply" (until the deadline) ------------------------
function agStartStoreEdit(noteId) { _agStoreEdit = noteId; renderAgingInventory(); }
function agCancelStoreEdit() {
    if (_agStoreEdit) delete _agDrafts['se|' + _agStoreEdit];
    _agStoreEdit = null;
    renderAgingInventory();
}
async function agSaveStoreEdit(btn, itemId, noteId) {
    const ta = document.querySelector(`#ag-body textarea[data-ag-storeedit="${noteId}"]`);
    const text = ta ? ta.value.trim() : '';
    if (!text) { if (ta) ta.focus(); return; }
    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Saving…';
    const by = sessionStorage.getItem('speeksUserName') || null;
    try {
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'update_note', note_id: noteId, body: text, by }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
        const it = _agItems.find(i => i.id === itemId);
        const note = it && (it.notes || []).find(n => n.id === noteId);
        if (note) { note.body = text; note.edited_by = by; note.edited_at = json.edited_at || new Date().toISOString(); }
        if (ta) ta.value = '';
        delete _agDrafts['se|' + noteId];
        _agStoreEdit = null;
        renderAgingInventory();
    } catch (e) {
        alert('Could not save the reply: ' + e.message);
        btn.disabled = false; btn.innerText = old;
    }
}

// ---- actions -----------------------------------------------------------------
async function agPostNote(btn, itemId, side) {
    const ta = document.querySelector(`#ag-body textarea[data-ag-reply="${itemId}|${side}"]`);
    const text = ta ? ta.value.trim() : '';
    if (!text) { if (ta) ta.focus(); return; }
    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Posting…';
    try {
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'add_note', item_id: itemId, side, body: text,
                by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Post failed');
        const it = _agItems.find(i => i.id === itemId);
        if (it) {
            (it.notes = it.notes || []).push({
                id: json.note_id, item_id: itemId, author_side: side,
                author_name: sessionStorage.getItem('speeksUserName') || null,
                body: text, created_at: new Date().toISOString(),
            });
            if (side === 'dm') it.due_at = new Date(Date.now() + 7 * 86400000).toISOString();
        }
        // blank the box BEFORE the re-render — the draft stash reads the live
        // DOM, so a still-filled textarea would resurrect the posted text as a
        // draft the next time the box appears
        if (ta) ta.value = '';
        delete _agDrafts[`${itemId}|${side}`];
        if (_agIsStoreUser()) {
            _agMyItemsCache = _agItems.filter(i => i.status === 'open');
            if (typeof applyKpiReminder === 'function') applyKpiReminder();
        }
        renderAgingInventory();
        // The reply/note that just posted may have cleared or narrowed the work the
        // aging bubble is nagging about. Update it live instead of leaving it stale
        // until the next sign-in: the store side re-renders (dropping a finished
        // store, hiding when nothing's left); the DM side hides once review is done.
        _agRefreshStorePopup();
        _agRetractBubbleIfDone();
        if (typeof renderActionFeed === 'function') renderActionFeed();
    } catch (e) {
        alert('Could not post the note: ' + e.message);
        btn.disabled = false; btn.innerText = old;
    }
}

// DM side only (the store side is handled live by _agRefreshStorePopup): once a
// DM reply clears the last item sitting in the 'dm' review state, hide the nag.
function _agRetractBubbleIfDone() {
    if (_agCurrentAckKey !== 'speeksAGAckDm') return;
    const b = document.getElementById('agingAlertBubble');
    if (!b || b.style.display === 'none') return;
    if (_agItems.some(it => it.status === 'open' && _agState(it) === 'dm')) return;
    b.style.display = 'none';
    _agPopShownThisSession = false;
    _agCurrentAckKey = null;
    _agCurrentAckMembers = null;
}

async function agSetStatus(itemId, status) {
    const q = { sold: 'Mark this item as SOLD and close it out (green)?',
                recycled: 'Mark this item as RECYCLED out of inventory and close it (red)?',
                open: 'Reopen this item and put it back on the report?' }[status];
    if (!confirm(q)) return;
    try {
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'set_status', item_id: itemId, status, by: sessionStorage.getItem('speeksUserName') || null }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        const it = _agItems.find(i => i.id === itemId);
        if (it) {
            it.status = status;
            it.closed_at = status === 'open' ? null : new Date().toISOString();
        }
        renderAgingInventory();
        // Closing an item (sold/recycled) clears its nag; reopening may bring one
        // back. Keep the live alert + feed in step, same as posting a reply does.
        if (_agIsStoreUser()) {
            _agMyItemsCache = _agItems.filter(i => i.status === 'open');
            if (typeof applyKpiReminder === 'function') applyKpiReminder();
        }
        _agRefreshStorePopup();
        _agRetractBubbleIfDone();
        if (typeof renderActionFeed === 'function') renderActionFeed();
    } catch (e) {
        alert('Could not update the status: ' + e.message);
    }
}

async function agDeleteItem(itemId) {
    if (!confirm('Delete this item and its entire note thread? (Use ✓ Sold or ♻ Recycled to close items normally — delete is for mistakes.)')) return;
    try {
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'delete_item', item_id: itemId }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Failed');
        _agItems = _agItems.filter(i => i.id !== itemId);
        renderAgingInventory();
    } catch (e) {
        alert('Could not delete: ' + e.message);
    }
}

// Saves the item info fields plus any of the DM's own notes edited in the row
// (the thread renders them as textareas in edit mode — store notes never).
async function agSaveItemEdit(btn, itemId) {
    const row = document.querySelector(`#ag-body tr[data-ag-item-row="${itemId}"]`);
    const it = _agItems.find(i => i.id === itemId);
    if (!row || !it) return;
    const get = f => { const el = row.querySelector(`input[data-ag-edit="${f}"]`); return el ? el.value.trim() : ''; };
    const dateRaw = get('date_created');
    let dateIso = '';
    if (dateRaw) {
        dateIso = _agParseDMY(dateRaw);
        if (!dateIso) { alert('Enter the listed date as DD/MM/YYYY (e.g. 16/03/2026).'); return; }
    }
    // Changed DM notes (an emptied box means "no change" — notes are edited,
    // not deleted, from here).
    const noteEdits = [];
    row.querySelectorAll('textarea[data-ag-noteedit]').forEach(ta => {
        const note = (it.notes || []).find(n => n.id === ta.dataset.agNoteedit);
        const text = ta.value.trim();
        if (note && text && text !== note.body) noteEdits.push({ note, text });
    });
    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Saving…';
    try {
        const patch = { sku: get('sku'), title: get('title'), date_created: dateIso, est_value: get('est_value'), cost: get('cost') };
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'update_item', item_id: itemId, ...patch }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Save failed');
        const editor = sessionStorage.getItem('speeksUserName') || null;
        await Promise.all(noteEdits.map(async ne => {
            const r = await fetch(AGING_INV_URL, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'update_note', note_id: ne.note.id, body: ne.text, by: editor }),
            });
            const j = await r.json().catch(() => ({}));
            if (!r.ok || j.success === false) throw new Error(j.error || 'Note save failed');
            ne.note.body = ne.text; ne.note.edited_by = editor; ne.note.edited_at = j.edited_at || new Date().toISOString();
        }));
        it.sku = patch.sku || null; it.title = patch.title || null;
        it.date_created = patch.date_created || null;
        it.est_value = patch.est_value === '' ? null : Number(patch.est_value);
        it.cost = patch.cost === '' ? null : Number(patch.cost);
        _agEditItem = null;
        _agClearNeDrafts();
        renderAgingInventory();
    } catch (e) {
        alert('Could not save: ' + e.message);
        btn.disabled = false; btn.innerText = old;
    }
}

// ---- DM add-item panel --------------------------------------------------------
function agToggleAdd() {
    // If the panel is already open with something typed, the top button submits the
    // item (people reach for "Add Item" expecting it to add) rather than toggling
    // the panel shut — which looked like the entry just vanished.
    if (_agAddOpen) {
        const hasData = ['ag-add-sku', 'ag-add-title'].some(id => {
            const el = document.getElementById(id); return el && el.value.trim();
        });
        if (hasData) { document.getElementById('ag-confirm-btn')?.click(); return; }
    }
    _agAddOpen = !_agAddOpen;
    _agJustAdded = '';
    renderAgingInventory();
}
function agCancelAdd() {
    _agAddOpen = false;
    _agJustAdded = '';
    renderAgingInventory();
}

function _agAddPanelHtml() {
    const store = (document.getElementById('ag-store-select') || {}).value || 'OVL';
    const lbl = t => `<label class="vr-up-label">${t}</label>`;
    const keep = id => { const el = document.getElementById(id); return el ? escapeHtml(el.value) : ''; };
    return `<div style="background:#f8fafc; border:1.5px solid #e2e8f0; border-radius:12px; padding:14px 16px; margin-bottom:16px;">
        <div style="font-weight:800; font-size:13px; color:var(--slate-charcoal); margin-bottom:10px;">Add an aging item for <b>${escapeHtml(store)}</b> <span style="font-weight:600; color:#94a3b8;">(store is picked in the dropdown above)</span></div>
        <div style="display:flex; gap:12px; flex-wrap:wrap; align-items:flex-end;">
            <div class="vr-up-field">${lbl('SKU')}<input type="text" id="ag-add-sku" class="vr-up-input" style="width:160px;" placeholder="KS01-…" value="${keep('ag-add-sku')}"></div>
            <div class="vr-up-field">${lbl('Item title')}<input type="text" id="ag-add-title" class="vr-up-input" style="width:280px;" placeholder="What is it?" value="${keep('ag-add-title')}"></div>
            <div class="vr-up-field">${lbl('Date listed')}<input type="text" id="ag-add-date" class="vr-up-input" style="width:120px;" placeholder="DD/MM/YYYY" maxlength="10" oninput="${_AG_DATE_MASK}" value="${keep('ag-add-date')}"></div>
            <div class="vr-up-field">${lbl('Estimated value ($)')}<input type="number" step="0.01" id="ag-add-value" class="vr-up-input" style="width:120px;" value="${keep('ag-add-value')}"></div>
            <div class="vr-up-field">${lbl('Cost ($)')}<input type="number" step="0.01" id="ag-add-cost" class="vr-up-input" style="width:110px;" value="${keep('ag-add-cost')}"></div>
        </div>
        <div class="vr-up-field" style="margin-top:10px;">${lbl('Your note to the store (optional — you can post it in the item’s thread anytime)')}
            <textarea id="ag-add-note" rows="2" placeholder="e.g. Pictures need to be better and the price looks high — is $1,499 still right for this market?"
                style="width:100%; box-sizing:border-box; padding:8px 10px; border:1.5px solid #cbd5e1; border-radius:8px; font-size:12.5px; font-family:inherit; line-height:1.4; resize:vertical; background:#fff;">${keep('ag-add-note')}</textarea>
        </div>
        <div style="margin-top:10px; display:flex; align-items:center; gap:10px; flex-wrap:wrap;">
            <button id="ag-confirm-btn" class="btn-primary" style="font-size:12px; padding:8px 18px;" onclick="agConfirmAdd(this)">Add to the ${escapeHtml(store)} report →</button>
            ${_agJustAdded ? `<span style="font-size:12px; font-weight:800; color:#166534;">✓ Added ${escapeHtml(_agJustAdded)}</span>` : ''}
        </div>
    </div>`;
}

// Adding always rolls straight into the next entry: post the item, clear the
// form, keep the panel open (header Cancel closes it after the last one) —
// Ethan enters the week's items back-to-back first and posts the notes into
// each thread afterwards, which is also why the note is optional.
async function agConfirmAdd(btn) {
    const val = id => { const el = document.getElementById(id); return el ? el.value.trim() : ''; };
    const store = (document.getElementById('ag-store-select') || {}).value || '';
    const sku = val('ag-add-sku'), title = val('ag-add-title'), note = val('ag-add-note');
    if (!sku && !title) { alert('Give the item at least a SKU or a title.'); return; }
    const dateRaw = val('ag-add-date');
    let dateIso = null;
    if (dateRaw) {
        dateIso = _agParseDMY(dateRaw);
        if (!dateIso) { alert('Enter the listed date as DD/MM/YYYY (e.g. 16/03/2026).'); return; }
    }
    const old = btn.innerText;
    btn.disabled = true; btn.innerText = 'Adding…';
    try {
        const res = await fetch(AGING_INV_URL, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'add_item', store, sku, title, note,
                date_created: dateIso,
                est_value: val('ag-add-value') || null,
                cost: val('ag-add-cost') || null,
                by: sessionStorage.getItem('speeksUserName') || null,
            }),
        });
        const json = await res.json().catch(() => ({}));
        if (!res.ok || json.success === false) throw new Error(json.error || 'Add failed');
        // blank the live inputs BEFORE the re-render — the rebuilt panel
        // carries current DOM values over, so this is what clears the form
        ['ag-add-sku', 'ag-add-title', 'ag-add-date', 'ag-add-value', 'ag-add-cost', 'ag-add-note'].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.value = '';
        });
        _agJustAdded = sku || title;
        await loadAgingInventory();
        document.getElementById('ag-add-sku')?.focus();
    } catch (e) {
        alert('Could not add the item: ' + e.message);
        btn.disabled = false; btn.innerText = old;
    }
}

// ---- reminders: pulsing dots + purple bubble ----------------------------------
// Store side: a dot on the workspace nav-link + tab while any item awaits their
// reply, plus one generic purple bubble. DM side: the same bubble when a store
// has replied and it's the DM's turn. ("Inv" in the names keeps these clear of
// checkAgingClaims, which is the CLAIMS aging alert.)
//
// The bubble NAGS UNTIL ACKNOWLEDGED, then STAYS dismissed: while work is
// pending it re-appears on every sign-in until the user dismisses it (the ✕ or
// the Open button — both route through closeAgingAlertBubble). Once dismissed it
// does NOT return on sign-out/in or the next day — only genuinely NEW activity
// brings it back: a new item, or a new DM follow-up on an item. This works by
// remembering, per item, the exact pending state that was acknowledged
// (`itemId:lastRelevantNoteId`); the popup fires only when some currently
// pending item wasn't in the acknowledged set. `_agPopShownThisSession`
// (in-memory, resets on a fresh page load) stops the 10-min poll from
// re-animating a bubble already up this session.
let _agRemindersStarted = false;
let _agDmRemindersStarted = false;
let _agMyItemsCache = [];
let _agPopShownThisSession = false; // a popup is already up this session (poll guard)
let _agCurrentAckKey = null;        // localStorage key to update when the current bubble is acknowledged
let _agCurrentAckMembers = null;    // pending-state members the current bubble represents

// The pending "members" the popup is about: one token per item that still
// needs the given side's attention, stamped with the last note from the OTHER
// side so a fresh follow-up (new note id) counts as new, unacknowledged work.
//   side 'store' → items awaiting the store, stamped with the last DM note
//   side 'dm'    → items the store replied to, stamped with the last store note
// Urgency tier of a store-awaiting item — folded into the member id so an
// ESCALATION (needs-replies → due-soon → overdue) counts as new work and gives
// one fresh nudge even after the earlier tier was acknowledged. Within a tier it
// stays quiet across sign-ins/days.
function _agTier(it) {
    if (_agOverdue(it)) return 'over';
    if (it.due_at) {
        const d = new Date(it.due_at).getTime();
        if (Date.now() < d && d - Date.now() < 24 * 3600 * 1000) return 'soon';
    }
    return 'new';
}
// Is this item past its opening exchange for the given side? The FIRST prompt
// each side gets is descriptive ("review your replies" / "reply needed"); once
// a thread is a back-and-forth, further notes are just a simple "new reply".
//   side 'store' (manager waiting) → they've replied at least once already, so a
//                                    new DM note is a follow-up in the chain
//   side 'dm' (DM waiting)         → the DM has already followed up once, so a
//                                    new store reply is a subsequent one
function _agIsFollowUp(it, side) {
    const notes = it.notes || [];
    const dmCount = notes.filter(n => n.author_side === 'dm').length;
    const storeCount = notes.filter(n => n.author_side === 'store').length;
    return side === 'store' ? storeCount >= 1 : dmCount >= 2;
}
function _agPendingMembers(items, side) {
    const rel = side === 'store'
        ? (items || []).filter(_agAwaitingStore)
        : (items || []).filter(it => it.status === 'open' && _agState(it) === 'dm');
    const wantSide = side === 'store' ? 'dm' : 'store';
    return rel.map(it => {
        const notes = it.notes || [];
        let lastId = 'new';
        for (let i = notes.length - 1; i >= 0; i--) { if (notes[i].author_side === wantSide) { lastId = notes[i].id; break; } }
        // store side stamps the urgency tier so escalations re-nag; the DM side
        // only fires once the window closes, so it needs no tier.
        return it.id + ':' + lastId + (side === 'store' ? ':' + _agTier(it) : '');
    });
}
function _agAckedSet(key) {
    try { return new Set(JSON.parse(localStorage.getItem(key) || '[]')); }
    catch (e) { return new Set(); }
}

function _agDotNeeded() {
    return _agMyItemsCache.some(_agAwaitingStore);
}

async function checkAgingInvReminders() {
    if (!_agIsStoreUser()) return;
    const stores = _agMyStores();
    if (!stores.length) return;
    if (!_agRemindersStarted) {
        _agRemindersStarted = true;
        setInterval(checkAgingInvReminders, 10 * 60 * 1000);
    }
    try {
        const res = await fetch(`${AGING_INV_URL}?stores=${encodeURIComponent(stores.join(','))}&v=${Date.now()}`);
        const json = await res.json();
        if (!json || json.success === false) return;
        _agMyItemsCache = (json.data || []).filter(it => it.status === 'open');
        applyKpiReminder();
        _agMaybePopup();
    } catch (e) { /* next poll retries */ }
}

// The store-side tiers, most urgent first. A store's tier is the worst of its
// awaiting items: overdue > follow-up (DM re-noted) > due within 24h > plain.
const _AG_TIER_RANK = { over: 3, followup: 2, soon: 1, plain: 0 };
const _AG_TIER_HEAD = {
    over:     ['🚨', 'Aging Inventory Replies Overdue'],
    followup: ['📬', 'New Reply in Aging Inventory'],
    soon:     ['⏰', 'Aging Inventory Replies Due Soon'],
    plain:    ['📦', 'Aging Inventory Needs Replies'],
};
// Full single-store sentence (kept for single-store managers).
const _AG_TIER_BODY = {
    over:     'The reply deadline has passed on the aging report — get your replies submitted as soon as possible.',
    followup: 'The DM added a new note on the aging report — take a look and reply.',
    soon:     'Aging report replies are due within the next day — make sure they’re submitted in time.',
    plain:    'The aging report has items waiting on a reply from your store.',
};
// Short per-store phrase (used in the multi-store breakdown).
const _AG_TIER_PHRASE = {
    over: 'reply overdue', followup: 'new DM note to answer', soon: 'due within a day', plain: 'needs your reply',
};
function _agStoreTierOf(items) {
    const now = Date.now();
    const dueSoon = it => it.due_at && (() => { const d = new Date(it.due_at).getTime(); return now < d && d - now < 24 * 3600 * 1000; })();
    if (items.some(_agOverdue)) return 'over';
    if (items.some(it => _agIsFollowUp(it, 'store'))) return 'followup';
    if (items.some(dueSoon)) return 'soon';
    return 'plain';
}

// Render the store-side aging bubble for the given awaiting items. A single-store
// manager gets the tier's full sentence; a multi-store manager gets a per-store
// breakdown ("BAL: due within a day • MPL: new DM note to answer") so both stores'
// progress is visible at once, and finishing one store drops it (see
// _agRefreshStorePopup). Stamps the covered stores for MSM click-routing. No
// guards here — callers own the session/ack gates.
function _agBuildStoreBubble(mine) {
    const byStore = {};
    mine.forEach(it => { const s = (it.store || '').toUpperCase(); (byStore[s] = byStore[s] || []).push(it); });
    const stores = Object.keys(byStore);
    const multi = _agMyStores().length > 1;
    // Overall tier = worst across every pending store → drives the title/icon.
    let top = 'plain';
    stores.forEach(s => { const t = _agStoreTierOf(byStore[s]); if (_AG_TIER_RANK[t] > _AG_TIER_RANK[top]) top = t; });
    const [icon, title] = _AG_TIER_HEAD[top];
    let body;
    if (multi && stores.length > 1) {
        const ordered = stores.slice().sort((a, b) => _AG_TIER_RANK[_agStoreTierOf(byStore[b])] - _AG_TIER_RANK[_agStoreTierOf(byStore[a])]);
        body = ordered.map(s => `${s}: ${_AG_TIER_PHRASE[_agStoreTierOf(byStore[s])]}`).join('  •  ');
    } else if (multi && stores.length === 1) {
        body = `${stores[0]}: ${_AG_TIER_BODY[top]}`;
    } else {
        body = _AG_TIER_BODY[top];
    }
    _agRenderBubble(icon, title, body);
    const agTextEl = document.getElementById('agingAlertBubbleText');
    if (agTextEl) {
        // Clean one-liner for the feed (else it scrapes title+body together).
        agTextEl.dataset.summary = body;
        const ss = [...new Set(stores.filter(Boolean))];
        if (ss.length) agTextEl.dataset.stores = ss.join(','); else delete agTextEl.dataset.stores;
    }
}

// Store-side popup: shows on every sign-in until acknowledged. Single-store users
// see the most-urgent tier's message; a multi-store manager sees a per-store
// breakdown (see _agBuildStoreBubble).
function _agMaybePopup() {
    const mine = _agMyItemsCache.filter(_agAwaitingStore);
    if (!mine.length) return;
    const members = _agPendingMembers(_agMyItemsCache, 'store');
    const acked = _agAckedSet('speeksAGAckStore');
    if (members.every(m => acked.has(m))) return; // all pending work already acknowledged
    if (_agPopShownThisSession) return;            // already up this session (poll guard)
    _agPopShownThisSession = true;
    _agCurrentAckKey = 'speeksAGAckStore';
    _agCurrentAckMembers = members;
    _agBuildStoreBubble(mine);
}

// After a store posts a reply, keep the live store bubble in step: drop a store
// that just finished (so an MSM who clears BAL still gets nagged for MPL), and
// hide the bubble once nothing is left awaiting. Only touches a store bubble that
// is currently up — an acked/hidden one is not resurrected.
function _agRefreshStorePopup() {
    if (!_agIsStoreUser()) return;
    const b = document.getElementById('agingAlertBubble');
    if (!b || b.style.display === 'none' || _agCurrentAckKey !== 'speeksAGAckStore') return;
    const mine = _agMyItemsCache.filter(_agAwaitingStore);
    if (!mine.length) {
        b.style.display = 'none';
        _agPopShownThisSession = false;
        _agCurrentAckKey = null;
        _agCurrentAckMembers = null;
        return;
    }
    _agBuildStoreBubble(mine); // re-render with the remaining store(s)
    _agCurrentAckMembers = _agPendingMembers(_agMyItemsCache, 'store');
}

// DM side: same treatment — nags until acknowledged while any store reply sits
// waiting on the DM's review. Kept off the store users' cache so their nav dot
// logic is untouched.
async function checkAgingInvDmReminders() {
    if (!_agIsDM()) return;
    if (!_agDmRemindersStarted) {
        _agDmRemindersStarted = true;
        setInterval(checkAgingInvDmReminders, 10 * 60 * 1000);
    }
    try {
        const res = await fetch(`${AGING_INV_URL}?stores=OVL,LEE,WSP,MPL,BAL&v=${Date.now()}`);
        const json = await res.json();
        if (!json || json.success === false) return;
        // Hold the DM's "review" nudge until the store's reply window (due_at)
        // has actually closed — give the store the full deadline to submit, then
        // remind the DM to review whatever came in. A store reply that lands
        // early won't ping the DM until the deadline passes.
        const reviewable = (json.data || []).filter(it => {
            if (it.status !== 'open' || _agState(it) !== 'dm') return false;
            // Ongoing back-and-forth: ping the DM as soon as the store replies —
            // the deadline gate is only for the store's initial reply window.
            if (_agIsFollowUp(it, 'dm')) return true;
            // First review of the batch: hold until the reply deadline passes.
            return it.due_at && new Date(it.due_at).getTime() <= Date.now();
        });
        const members = _agPendingMembers(reviewable, 'dm');
        if (!members.length) return;
        const acked = _agAckedSet('speeksAGAckDm');
        if (members.every(m => acked.has(m))) return; // all replies already reviewed/acknowledged
        if (_agPopShownThisSession) return;            // already up this session (poll guard)
        _agPopShownThisSession = true;
        _agCurrentAckKey = 'speeksAGAckDm';
        _agCurrentAckMembers = members;
        // First batch review after the deadline gets the descriptive prompt; a
        // later reply in an ongoing thread is just a simple "new reply".
        if (reviewable.some(it => !_agIsFollowUp(it, 'dm'))) {
            _agRenderBubble('📬', 'Aging Inventory Replies To Review',
                'Stores have replied on the aging report — review the replies and follow up or close the items out.');
        } else {
            _agRenderBubble('📬', 'New Reply in Aging Inventory',
                'A store added a new reply on the aging report — take a look.');
        }
        // Stores whose replies need review → route a DM click to the first one.
        // Ordered longest-waiting-first (oldest closed window) so the click lands
        // on the store that's been sitting the longest. Mirrors variance DM routing.
        const agTextEl = document.getElementById('agingAlertBubbleText');
        if (agTextEl) {
            const ordered = reviewable.slice().sort((a, b) => {
                const da = a.due_at ? new Date(a.due_at).getTime() : Infinity;
                const db = b.due_at ? new Date(b.due_at).getTime() : Infinity;
                return da - db;
            });
            const ss = [...new Set(ordered.map(it => (it.store || '').toUpperCase()).filter(Boolean))];
            if (ss.length) agTextEl.dataset.stores = ss.join(','); else delete agTextEl.dataset.stores;
        }
    } catch (e) { /* next poll retries */ }
}

// Aging Inventory's own PURPLE bubble — created on demand next to the shared
// claim bubble (same header stacking context) and positioned at the very
// bottom of the stack: store comment → claims → recycle → variance → aging.
function _agBubbleEl() {
    let b = document.getElementById('agingAlertBubble');
    if (b) return b;
    const claim = document.getElementById('claimAlertBubble');
    if (!claim || !claim.parentElement) return null;
    b = document.createElement('div');
    b.id = 'agingAlertBubble';
    b.style.cssText = 'display:none; position:fixed; top:116px; right:24px; background:linear-gradient(135deg, #7c3aed, #4c1d95); color:white; padding:11px 14px 11px 16px; border-radius:14px; align-items:flex-start; gap:8px; font-size:13px; box-shadow:0 10px 28px rgba(76, 29, 149, 0.38); max-width:min(380px, calc(100vw - 48px)); z-index:998;';
    b.innerHTML = `<span id="agingAlertBubbleIcon" style="font-size:16px; flex-shrink:0; margin-top:2px;">⏳</span>
        <span id="agingAlertBubbleText" style="white-space:normal; overflow-y:auto; max-height:220px;"></span>
        <button onclick="closeAgingAlertBubble()" class="daily-bubble-close" title="Dismiss">
            <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
        </button>`;
    claim.parentElement.appendChild(b);
    return b;
}

function _positionAgingAlert() {
    const b = document.getElementById('agingAlertBubble');
    if (!b) return;
    let top = 116;
    ['dailyMessageBubble', 'claimAlertBubble', 'recycleAlertBubble', 'varianceAlertBubble'].forEach(id => {
        const el = document.getElementById(id);
        if (el && getComputedStyle(el).display !== 'none' && el.offsetHeight > 0) {
            top = Math.max(top, el.getBoundingClientRect().bottom + 12);
        }
    });
    b.style.top = top + 'px';
}

function closeAgingAlertBubble() {
    const b = document.getElementById('agingAlertBubble');
    if (b) b.style.display = 'none';
    // Acknowledged (the ✕ OR the "Open Aging Inventory" button both route here):
    // record every pending item this bubble covered so it won't return on
    // sign-out/in or the next day. It comes back only for NEW work (a new item
    // or a new DM follow-up produces a member not in this set). If it's never
    // acknowledged, a fresh page load resets _agPopShownThisSession and it nags
    // again next sign-in.
    if (_agCurrentAckKey && _agCurrentAckMembers) {
        const acked = _agAckedSet(_agCurrentAckKey);
        _agCurrentAckMembers.forEach(m => acked.add(m));
        localStorage.setItem(_agCurrentAckKey, JSON.stringify([...acked].slice(-500)));
        _agCurrentAckKey = null;
        _agCurrentAckMembers = null;
    }
    _agPopShownThisSession = false;
}

function _agRenderBubble(icon, title, bodyText) {
    const b = _agBubbleEl();
    if (!b) return;
    const iconEl = document.getElementById('agingAlertBubbleIcon');
    const textEl = document.getElementById('agingAlertBubbleText');
    if (iconEl) iconEl.textContent = icon;
    textEl.style.display = 'flex';
    textEl.style.flexDirection = 'column';
    textEl.style.gap = '7px';
    textEl.innerHTML = `
        <div style="line-height:1.4;"><strong>${escapeHtml(title)}</strong></div>
        <div style="line-height:1.4; opacity:0.96;">${escapeHtml(bodyText)}</div>
        <button onclick="closeAgingAlertBubble(); window.location.href='workspace.html#aging';"
            style="align-self:flex-start; background:rgba(255,255,255,0.18); border:1px solid rgba(255,255,255,0.5); color:#fff; font-weight:800; font-size:12px; border-radius:8px; padding:6px 12px; cursor:pointer;"
            onmouseover="this.style.background='rgba(255,255,255,0.3)';" onmouseout="this.style.background='rgba(255,255,255,0.18)';">Open Aging Inventory</button>`;
    b.style.display = 'flex';
    _positionAgingAlert();
    // Re-stack shortly after: the other bubbles land on their own timers.
    setTimeout(_positionAgingAlert, 2200);
    b.animate([
        { transform: 'scale(0.95) translateX(10px)', opacity: 0 },
        { transform: 'scale(1) translateX(0)', opacity: 1 }
    ], { duration: 400, easing: 'cubic-bezier(0.4, 0, 0.2, 1)' });
}


/* =========================================================
   SPEEKS ACTION MENU  (Priority-Hero briefing deck)
   Renders the QuickPortal action deck: announcements + store
   notes feed, priority hero, and the Reminders & Due card.
   The action-item cards themselves trigger the existing
   panels/modals directly from the HTML (toggleChecklistPanel,
   toggleAuditPanel, toggleGoalsPanel, toggleNotifs). Progress
   numbers are pushed in from the existing chip updaters via
   samSetProgress(). Data sources are the same fetches the app
   already runs -- no extra network calls. Realtime is phase 3.
   ========================================================= */

function _samEsc(s) {
    return String(s == null ? '' : s).replace(/[&<>"]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
}

function _samFmtDate(d) {
    if (!d || isNaN(d.getTime())) return '';
    const now = new Date();
    if (d.toDateString() === now.toDateString()) {
        let h = d.getHours(), m = d.getMinutes();
        const ap = h >= 12 ? 'pm' : 'am';
        return `${h % 12 || 12}:${String(m).padStart(2, '0')}${ap}`;
    }
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

// Pull a clean title + snippet + priority flag out of an announcement's HTML body.
function _samParseAnn(item) {
    const tmp = document.createElement('div');
    tmp.innerHTML = item.text || '';
    let priority = !!item.high_priority || /HIGH PRIORITY|🚨/.test(item.text || '');
    // Drop the "🚨 HIGH PRIORITY" marker span BEFORE pulling the title out.
    // Leaving it in pushed the title off index 0, so the old "does the body
    // start with the title" test failed and the title got repeated at the head
    // of the snippet ("July 2026 Store GoalsJuly's here…") on priority posts.
    tmp.querySelectorAll('span').forEach(s => {
        if (/HIGH PRIORITY/i.test(s.textContent || '')) { priority = true; s.remove(); }
    });
    // Remove the title node itself so the body can never repeat it, rather than
    // relying on string matching (whitespace differences broke that too).
    const strong = tmp.querySelector('strong');
    let title = strong ? (strong.textContent || '').trim() : '';
    if (strong) strong.remove();
    let snippet = (tmp.textContent || '').replace(/\s+/g, ' ').trim();
    if (!title) {                       // no explicit title — borrow the opening words
        title = snippet.slice(0, 70);
        snippet = snippet.slice(title.length).trim();
    }
    const stripPr = s => s.replace(/^\s*🚨?\s*HIGH PRIORITY\s*/i, '').trim();
    return { title: stripPr(title) || 'Announcement', snippet: stripPr(snippet), priority };
}

function _samAnnRead(item) {
    const currentUser = sessionStorage.getItem('speeksUserName');
    const cleanUser = currentUser ? String(currentUser).trim().toLowerCase() : null;
    if (!cleanUser) return false;
    const localRead = new Set(JSON.parse(localStorage.getItem('speeksLocalRead_' + cleanUser) || '[]'));
    const inReadBy = !!(item.readBy && item.readBy.some(u => String(u).trim().toLowerCase() === cleanUser));
    return inReadBy || localRead.has(item.rowId);
}

function _samIsMSM() {
    try { return typeof _isMSMChecklist === 'function' && _isMSMChecklist(); } catch (_) { return false; }
}

// --- UNIFIED FEED (announcements + store notes + reminders/due dates) ---
// One "everything" feed. Announcements + store notes get a permanent read;
// reminders get a per-day dismiss (they re-surface tomorrow if still due). The
// header's Mark-all-read clears whatever is currently active.
function renderActionFeed() {
    const feed = document.getElementById('samFeed');
    if (!feed) return; // not a manager / menu not present

    const anns = (window._samAnnData || []).map(it => {
        const p = _samParseAnn(it);
        const d = it.date ? new Date(it.date) : null;
        return {
            type: 'ann', rowId: it.rowId, title: p.title, snippet: p.snippet, priority: p.priority,
            author: it.author || 'Announcement',
            dateObj: d, dateMs: (d && !isNaN(d.getTime())) ? d.getTime() : 0,
            read: _samAnnRead(it)
        };
    });

    const notes = (window._samStoreNotes || []).map(n => {
        // Prefer the real send time (created_at) — n.date is date-only, so it
        // rendered as 12:00am and sorted same-day notes by an identical value.
        const d = n.created_at ? new Date(n.created_at) : (n.date ? new Date(n.date) : null);
        const tmp = document.createElement('div'); tmp.innerHTML = n.text || '';
        return {
            type: 'note', title: 'Message from ' + (n.author || 'your team'),
            snippet: (tmp.textContent || '').replace(/\s+/g, ' ').trim(),
            store: String(n.store || '').toUpperCase(), id: n.id || null,
            dateObj: d, dateMs: (d && !isNaN(d.getTime())) ? d.getTime() : Date.now(), read: false
        };
    });

    const rems = _samGatherReminders();

    // Priority hero = newest unread high-priority announcement (kept above feed).
    // Whatever lands in the hero is REMOVED from the feed below — a high-priority
    // item shows in exactly one place, at the top, so it can't read as duplicated.
    // Only the hero item is excluded; a second unread priority announcement still
    // falls through to the feed rather than disappearing entirely.
    let heroRowId = null;
    const hero = document.getElementById('samHero');
    if (hero) {
        // Only ONE high-priority announcement is surfaced at a time, in the hero.
        // Pick the OLDEST unread priority so the one that's already been up there
        // stays put; a newer priority queues behind it (hidden — see the feed
        // filter below) and only takes the hero once the current one is read.
        const prio = anns.filter(a => a.priority && !a.read).sort((a, b) => a.dateMs - b.dateMs)[0];
        if (prio) {
            document.getElementById('samHeroTitle').textContent = prio.title;
            document.getElementById('samHeroSnip').textContent = prio.snippet;
            heroRowId = prio.rowId;
            hero.hidden = false;
            _samSyncHero(prio);          // must run after unhiding — hidden = 0 width
        } else {
            hero.hidden = true;
        }
    }

    // Read announcements leave the feed entirely (they live in the Archived tab of
    // the announcements modal). Everything else is ordered purely newest-first.
    // Grouping by type first used to bury a brand-new announcement under week-old
    // ones of a "higher" type, which reads as broken once there are a lot unread.
    // Reminders still surface at the top on their own merit — their dateMs is
    // Date.now(), so they're always the newest thing in the list.
    // Priority announcements never go in the feed list — the one active hero shows
    // up top, and any additional unread priority ones wait their turn for the hero
    // (rather than stacking in the feed). Non-priority announcements flow normally.
    const all = rems.concat(notes, anns.filter(a => !a.read && a.rowId !== heroRowId && !a.priority))
        .sort((a, b) => (b.dateMs || 0) - (a.dateMs || 0));
    const items = all.slice(0, 8);

    // Compact "new patch notes" row — patch notes collapse to one entry in the
    // main feed (the full notes live in the hub). Only when there are unseen ones.
    const _cu = sessionStorage.getItem('speeksUserName');
    const _clu = _cu ? String(_cu).trim().toLowerCase() : null;
    const patchUnseen = !!(_clu && localStorage.getItem('speeksUnseenPatchNotes_' + _clu) === 'true');
    const patchVer = (typeof _latestPatchKey === 'string' && _latestPatchKey) ? _latestPatchKey.split('|')[0] : '';
    // The patch title already carries its own "v" (e.g. "v2.2.2"), so blindly
    // prefixing another one rendered "vv2.2.2". Normalise to exactly one.
    const patchLabel = patchVer ? 'v' + patchVer.replace(/^\s*v/i, '').trim() : '';
    const patchRow = patchUnseen ? `<div class="sam-ann sam-patchrow" onclick="openHubToPatch()">
            <span class="sam-adot" style="background:#8b5cf6;box-shadow:0 0 0 4px #f1edfb"></span>
            <div class="sam-a-body"><div class="sam-a-top"><span class="sam-a-title">New Patch Notes</span><span class="sam-a-flag" style="color:#8b5cf6;background:#f1edfb">New</span></div><div class="sam-a-snip">${patchLabel ? _samEsc(patchLabel) + ' — click for what changed' : 'Click for details'}</div></div>
        </div>` : '';

    // "Active" = anything not a read announcement (drives the pip). No bulk
    // mark-all — each item must be read individually.
    const activeCount = rems.length + notes.length + anns.filter(a => !a.read).length + (patchUnseen ? 1 : 0);
    const pip = document.getElementById('samAnnPip');
    if (pip) { pip.textContent = activeCount; pip.style.display = activeCount > 0 ? 'inline-grid' : 'none'; }

    if (!items.length && !patchRow) {
        _samReconcileFeed(feed, [{ key: 'empty', html: '<div class="sam-empty">You\'re all caught up.</div>' }]);
        return;
    }

    const showStoreChip = _samIsMSM();
    // Each item gets an explicit "Mark read" button (no bulk skip) — a checkmark
    // + label so reading is a deliberate action, not a reflex ✕.
    const readBtn = onclick => `<button class="sam-markread-btn" onclick="${onclick}"><svg viewBox="0 0 24 24"><path d="M20 6 9 17l-5-5"/></svg>Mark read</button>`;
    // Reminders are live task-nags, so theirs is a "Snooze" (quiets today, returns
    // tomorrow if still outstanding, auto-clears for good once the work is done).
    const snoozeBtn = onclick => `<button class="sam-markread-btn sam-snooze-btn" data-tip="Snoozes for today — comes back tomorrow if it's still outstanding, and disappears for good once the work is done." onclick="${onclick}"><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M12 8v4l3 2"/></svg>Snooze</button>`;

    // Build a keyed list of cards, then reconcile in place (see
    // _samReconcileFeed). renderActionFeed used to blow away and rebuild the whole
    // list on every call — and it's called after every data fetch resolves AND on
    // a 5s interval — so cards flickered as data streamed in and churned forever.
    // Now unchanged cards are left untouched; only new/changed ones touch the DOM.
    const desired = [];
    if (patchRow) desired.push({ key: 'patch', html: patchRow });
    items.forEach(it => {
        if (it.type === 'rem') {
            const dotcls = it.dueCls === 'sam-due-red' ? 'urgent' : 'warn';
            const remClick = it.action ? ` onclick="${it.action}" style="cursor:pointer"` : '';
            desired.push({ key: 'rem:' + it.key, html: `<div class="sam-ann rem"${remClick}>
                <span class="sam-adot ${dotcls}"></span>
                <div class="sam-a-body">
                    <div class="sam-a-top"><span class="sam-a-title">${_samEsc(it.title)}</span><span class="sam-r-due ${it.dueCls}">${_samEsc(it.due)}</span></div>
                    <div class="sam-a-snip">${_samEsc(it.snippet)}</div>
                </div>
                ${snoozeBtn(`samDismissItem(event,'rem','${_samEsc(it.key)}')`)}
            </div>` });
            return;
        }
        if (it.type === 'note') {
            const chip = (showStoreChip && it.store) ? `<span class="sam-schip">${_samEsc(it.store)}</span>` : '';
            desired.push({ key: 'note:' + (it.id || ('d' + it.dateMs)), html: `<div class="sam-ann note" data-hub-target="note-${_samEsc(String(it.id || ''))}" onclick="openHubTo('note-${_samEsc(String(it.id || ''))}','unread')">
                <span class="sam-adot"></span>
                <div class="sam-a-body">
                    <div class="sam-a-top"><span class="sam-a-title">${_samEsc(it.title)}</span>${chip}<span class="sam-a-flag gold">Store note</span></div>
                    <div class="sam-a-snip">${_samEsc(it.snippet)}</div>
                    <div class="sam-a-meta">${it.dateObj ? _samFmtDate(it.dateObj) : 'Store note'}</div>
                </div>
                ${readBtn(`samDismissItem(event,'note','${it.id ? _samEsc(it.id) : ''}')`)}
            </div>` });
            return;
        }
        const flag = it.priority ? '<span class="sam-a-flag">Priority</span>' : '';
        const tgt = 'ann-' + _samEsc(String(it.rowId || ''));
        desired.push({ key: 'ann:' + (it.rowId || ('d' + it.dateMs)), html: `<div class="sam-ann" data-hub-target="${tgt}" onclick="openHubTo('${tgt}','unread')">
            <span class="sam-adot"></span>
            <div class="sam-a-body">
                <div class="sam-a-top"><span class="sam-a-title">${_samEsc(it.title)}</span>${flag}</div>
                <div class="sam-a-snip">${_samEsc(it.snippet)}</div>
                <div class="sam-a-meta">${it.dateObj ? _samFmtDate(it.dateObj) + ' &middot; ' : ''}${_samEsc(it.author)}</div>
            </div>
            ${readBtn(`samDismissItem(event,'ann','${it.rowId ? _samEsc(it.rowId) : ''}')`)}
        </div>` });
    });

    _samReconcileFeed(feed, desired);
    _samAddReadFull();
}

// Keyed, in-place reconcile of the action feed. Cards are matched by a stable key
// (rem/note/ann + id) and a content signature; an unchanged card is left exactly
// where it is, a changed one is swapped silently, and a genuinely new one fades
// in via .sam-enter. This is what stops the feed flickering as data streams in on
// login and on every 5s refresh — the old code rebuilt every card each time.
function _samMakeSamCard(d) {
    const tmp = document.createElement('div');
    tmp.innerHTML = d.html.trim();
    const el = tmp.firstElementChild;
    el.dataset.samKey = d.key;
    el._samSig = d.html;
    return el;
}
function _samPlaceCard(feed, el, prev) {
    if (prev) { if (prev.nextElementSibling !== el) prev.after(el); }
    else if (feed.firstElementChild !== el) feed.prepend(el);
}
function _samReconcileFeed(feed, desired) {
    const wantSet = new Set(desired.map(d => d.key));
    // Drop cards no longer present (including the "all caught up" placeholder).
    Array.from(feed.children).forEach(el => {
        if (!el.dataset || !wantSet.has(el.dataset.samKey)) el.remove();
    });
    let prev = null;
    desired.forEach(d => {
        let el = null;
        for (let i = 0; i < feed.children.length; i++) {
            if (feed.children[i].dataset.samKey === d.key) { el = feed.children[i]; break; }
        }
        if (!el) {
            el = _samMakeSamCard(d);
            el.classList.add('sam-enter');
            el.addEventListener('animationend', () => el.classList.remove('sam-enter'), { once: true });
            _samPlaceCard(feed, el, prev);
        } else if (el._samSig !== d.html) {
            const fresh = _samMakeSamCard(d); // content changed → swap silently, no flash
            el.replaceWith(fresh);
            el = fresh;
            _samPlaceCard(feed, el, prev);
        } else {
            _samPlaceCard(feed, el, prev); // unchanged → just keep it in order
        }
        prev = el;
    });
}

// ONE RULE, everywhere: you may only mark something read if you can actually read
// all of it. Snippets are clamped, so a message is either
//   fully visible  -> keep "Mark read"
//   clipped        -> swap it for "Read full", which opens the hub
// Truncation can't be known until after layout, so this measures post-render.
// Reminders are skipped: they snooze rather than read, and their row already
// carries its own open-the-tool action.
function _samAddReadFull() {
    document.querySelectorAll('#samFeed .sam-ann:not(.rem)').forEach(row => {
        if (row.querySelector('.sam-readfull')) return;       // already converted (reused card)
        const el = row.querySelector('.sam-a-snip');
        if (!el) return;
        if (el.scrollHeight - el.clientHeight <= 1) return;   // fits; nothing hidden
        // Clipped: the row's own "Mark read" would let someone clear a message
        // they've only seen the first line of, so it goes away entirely.
        const mr = row.querySelector('.sam-markread-btn');
        if (mr) mr.remove();
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'sam-readfull';
        btn.innerHTML = 'Read full <svg viewBox="0 0 24 24"><path d="M5 12h14M13 6l6 6-6 6"/></svg>';
        btn.onclick = ev => {
            ev.stopPropagation();   // don't double-fire the row's own handler
            openHubTo(row.dataset.hubTarget || '');
        };
        el.insertAdjacentElement('afterend', btn);
    });
}

// Open the hub and jump straight to one item. Landing at the top of a 29-item
// list and expecting someone to re-find the thing they just clicked is the whole
// problem this solves. Falls back to a plain open when the target isn't in view
// (e.g. an archived item while the filter is "All").
// Target we're trying to land on, and how long we'll keep re-anchoring to it.
// toggleNotifs() renders the hub synchronously and THEN fires loadPatchNotes(),
// whose fetch re-renders #hubFeed a few hundred ms later — mid smooth-scroll —
// inserting patch rows above the target and sliding it out from under the
// animation, so you landed on a neighbouring announcement. renderHubFeed() calls
// _hubScrollToPending() on every rebuild so the jump survives any late re-render.
let _hubPendingTarget = null;
let _hubPendingUntil = 0;

function openHubTo(targetId, filter) {
    const hub = document.getElementById('notifDropdown');
    if (!hub || !hub.classList.contains('show')) toggleNotifs();
    // Opening from a notification lands on a filter (announcements/comments open
    // "Unread") so reading one drops it off and the remaining unread items stay
    // in view — no exit-and-reopen to clear the next one.
    if (filter) {
        window._hubFilter = filter;
        const sel = document.getElementById('hubFilter');
        if (sel) sel.value = filter;
        if (typeof renderHubFeed === 'function') renderHubFeed();
    }
    if (!targetId) return;
    _hubPendingTarget = targetId;
    _hubPendingUntil = Date.now() + 2500; // long enough for the patch-notes fetch
    _hubScrollToPending();
}

function _hubScrollToPending() {
    const targetId = _hubPendingTarget;
    if (!targetId || Date.now() > _hubPendingUntil) return;
    // renderHubFeed() has already run synchronously inside toggleNotifs, but the
    // modal's open transition hasn't settled, so measure on the next frame.
    requestAnimationFrame(() => setTimeout(() => {
        if (_hubPendingTarget !== targetId) return; // superseded by a newer jump
        const card = document.querySelector(`#hubFeed [data-hub-id="${CSS.escape(targetId)}"]`);
        if (!card) return;
        // 'start', not 'center'. Centring a card taller than the viewport cuts off
        // BOTH ends — you land mid-announcement, with the footer (reactions, read
        // receipts and Mark as read) below the fold, so a long post looked like it
        // had no way to mark it read. Aligning the top also means you start reading
        // at the beginning, which is the point of jumping to it.
        card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        card.classList.remove('hub-jump');
        void card.offsetWidth;          // restart the highlight if it's re-clicked
        card.classList.add('hub-jump');
        setTimeout(() => card.classList.remove('hub-jump'), 2200);
    }, 60));
}

// Same rule for the priority hero: its snippet is a single ellipsised line, so
// "Mark read" only appears when the whole message actually fits. The two CTAs are
// mutually exclusive — clicking the bar anywhere already opens the hub, so once
// the text is fully readable "Read now" is just noise next to "Mark read".
function _samSyncHero(ann) {
    const btn = document.getElementById('samHeroRead');
    const snip = document.getElementById('samHeroSnip');
    const cta = document.getElementById('samHeroCta');
    if (!btn || !snip) return;
    const clipped = snip.scrollWidth - snip.clientWidth > 1;
    btn.hidden = clipped || !ann.rowId;
    if (cta) cta.hidden = !btn.hidden;   // exactly one of the two is ever visible
    // Assigning .onclick replaces the markup's inline toggleNotifs(), so the bar
    // deep-links to its own announcement like every other row.
    const heroEl = document.getElementById('samHero');
    if (heroEl) heroEl.onclick = () => openHubTo('ann-' + (ann.rowId || ''), 'unread');
    if (btn.hidden) return;
    btn.onclick = ev => {
        ev.stopPropagation();       // the hero itself opens the hub
        samDismissItem(ev, 'ann', ann.rowId);
    };
}

// Permanent read for one announcement (local set + server), no DOM animation.
function _samMarkAnnRead(rowId) {
    const user = sessionStorage.getItem('speeksUserName');
    if (!user || !rowId) return;
    const clean = String(user).trim().toLowerCase();
    const key = 'speeksLocalRead_' + clean;
    const set = new Set(JSON.parse(localStorage.getItem(key) || '[]'));
    set.add(rowId);
    localStorage.setItem(key, JSON.stringify([...set]));
    try { postWrite(CMS_URL, { type: 'mark_read', user, rowIds: [rowId] }).catch(() => {}); } catch (_) {}
    if (typeof updateMainBadge === 'function') updateMainBadge();
}

function samDismissItem(ev, kind, key) {
    if (ev) ev.stopPropagation();
    const row = ev && ev.target ? ev.target.closest('.sam-ann') : null;
    if (kind === 'rem') {
        // Record WHAT was snoozed, not just that it was — see _samGetDismissedRem.
        const cur = _samGatherReminders().find(r => r.key === key);
        const map = _samGetDismissedRem();
        map[key] = cur ? cur.sig : '';
        _samSetDismissedRem(map);
    } else if (kind === 'note') {
        // Record locally FIRST, so the read survives the next re-fetch even if the
        // POST below is slow, fails, or races a poll.
        _addLocalNoteRead(key);
        if (key && Array.isArray(window._samStoreNotes)) {
            window._samStoreNotes = window._samStoreNotes.filter(n => String(n.id) !== String(key));
        }
        // Mirror the read into the hub archive copy so it dims there immediately
        // (rather than waiting for the next 30s comment poll).
        if (key && Array.isArray(window._hubStoreNotes)) {
            window._hubStoreNotes.forEach(n => { if (String(n.id) === String(key)) n.read = true; });
            try { if (typeof renderHubFeed === 'function') renderHubFeed(); } catch (_) {}
        }
        if (key) { try { postWrite(STORE_COMMENT_URL, { type: 'mark_read', commentIds: [key], user: sessionStorage.getItem('speeksUserName') }).catch(() => {}); } catch (_) {} }
    } else if (kind === 'ann') {
        _samMarkAnnRead(key);
    }
    if (row) row.remove();
    renderActionFeed();
}

// Clear the whole feed: read every announcement, mark notes read, dismiss the
// day's reminders. Lets the user zero out their feed when caught up.
function samMarkAllRead() {
    const user = sessionStorage.getItem('speeksUserName');
    const unreadIds = (window._samAnnData || []).filter(a => !_samAnnRead(a)).map(a => a.rowId).filter(Boolean);
    if (unreadIds.length && user) {
        const clean = String(user).trim().toLowerCase();
        const kk = 'speeksLocalRead_' + clean;
        const set = new Set(JSON.parse(localStorage.getItem(kk) || '[]'));
        unreadIds.forEach(id => set.add(id));
        localStorage.setItem(kk, JSON.stringify([...set]));
        try { postWrite(CMS_URL, { type: 'mark_read', user, rowIds: unreadIds }).catch(() => {}); } catch (_) {}
    }
    const noteIds = (window._samStoreNotes || []).map(n => n.id).filter(Boolean);
    noteIds.forEach(_addLocalNoteRead);
    if (noteIds.length && user) { try { postWrite(STORE_COMMENT_URL, { type: 'mark_read', commentIds: noteIds, user }).catch(() => {}); } catch (_) {} }
    window._samStoreNotes = [];
    // Only dismiss reminders that are ON SCREEN right now. This used to blanket-add
    // every configured key, which silently pre-dismissed reminders that hadn't fired
    // yet: clearing the feed in the morning meant a claim that aged out at noon never
    // showed for the rest of the day. You can't "read" something that doesn't exist,
    // so use the same liveness test the feed itself uses (_samGatherReminders).
    const map = _samGetDismissedRem();
    _samGatherReminders().forEach(r => { map[r.key] = r.sig; });
    _samSetDismissedRem(map);
    if (typeof updateMainBadge === 'function') updateMainBadge();
    renderActionFeed();
}

// --- PROGRESS MIRRORS (called from the existing chip updaters) ---
function samSetProgress(kind, data) {
    const map = {
        cl: ['samClVal', 'samClFill', 'samClSub', 'Open your daily tasks'],
        audit: ['samAuditVal', 'samAuditFill', 'samAuditSub', "Open today's cleaning list"],
        list: ['samListVal', 'samListFill', 'samListSub', "This week's listing target"]
    }[kind];
    if (!map) return;
    const val = document.getElementById(map[0]), fill = document.getElementById(map[1]), sub = document.getElementById(map[2]);
    if (!val || !fill || !sub) return;

    if (data && data.stores) {
        const tot = data.stores.reduce((a, s) => a + s.total, 0);
        const dn = data.stores.reduce((a, s) => a + s.done, 0);
        val.textContent = '';
        fill.style.width = (tot ? dn / tot * 100 : 0) + '%';
        sub.innerHTML = '<span class="sam-storestats">' + data.stores.map(s =>
            `<span class="sam-storestat"><span class="sam-schip">${_samEsc(s.store)}</span> ${s.done}/${s.total}</span>`).join('') + '</span>';
        return;
    }
    const done = (data && data.done) || 0, total = (data && data.total) || 0;
    if (!total) { val.textContent = ''; fill.style.width = '0%'; sub.textContent = map[3]; return; }
    val.textContent = `${done}/${total}`;
    fill.style.width = (done / total * 100) + '%';
    sub.textContent = done >= total ? 'All done for today' : `${total - done} left today`;
}

// --- LISTING GOALS (mirror the widget's headline) ---
// Mirror the Listing Goals modal's weekly numbers onto the rail card.
//
// This used to scrape #goals-store-target for a "done/target" pair, but that
// element only ever reads "Goal: 190 Listings" — no slash — so the match always
// failed and the bar and value silently stayed blank. Read the same elements the
// modal itself fills instead: #goals-total-actual is the week's summed goals, and
// the weekly target comes from targetFor(). MSM stacks two stores, so its totals
// live in per-store elements and both sides get summed.
function samRefreshListing() {
    const val = document.getElementById('samListVal'), fill = document.getElementById('samListFill'), sub = document.getElementById('samListSub');
    if (!val || !fill || !sub) return;

    const num = el => {
        const n = parseInt(String((el && el.textContent) || '').replace(/[^\d-]/g, ''), 10);
        return isNaN(n) ? 0 : n;
    };
    const targetOf = s => { try { return targetFor(s) || 0; } catch (_) { return 0; } };

    let done = 0, target = 0, label = '';

    if (_samIsMSM()) {
        MULTISTORE_MANAGER_STORES.forEach(s => {
            done += num(document.getElementById(`goals-total-actual-${s}`));
            target += targetOf(s);
        });
        label = MULTISTORE_MANAGER_STORES.map(s => `${s} ${targetOf(s)}`).join(' · ');
    } else {
        done = num(document.getElementById('goals-total-actual'));
        target = (typeof _weekTargetTotal === 'number' && _weekTargetTotal)
            ? _weekTargetTotal
            : targetOf(sessionStorage.getItem('speeksUserStore'));
        label = target ? `Goal: ${target} listings this week` : '';
    }

    // Nothing loaded yet — leave the card's default subtitle rather than flashing 0/0.
    if (!target) return;

    val.textContent = `${done}/${target}`;
    fill.style.width = Math.max(0, Math.min(100, done / target * 100)) + '%';
    sub.textContent = label;
}

// Strip the leading emoji from hotbar chips at runtime (keeps the source markup
// untouched and avoids editing every link / risking encoding mojibake).
function samCleanHotbar() {
    document.querySelectorAll('.hotbar-btn').forEach(a => {
        if (a.dataset.samCleaned) return;
        const cleaned = (a.textContent || '').replace(/^[^\w(]+/, '').trim();
        if (cleaned) a.textContent = cleaned;
        a.dataset.samCleaned = '1';
    });
    // Flatten visible role/store wrappers into the one chip row. applyRoleBasedUI
    // stamps their display inline (flex/none), so CSS can't; override the visible
    // ones to `contents` here (runs right after applyRoleBasedUI). Hidden wrappers
    // keep their inline `none`.
    document.querySelectorAll('.hotbars-stack .hotbar-wrapper').forEach(w => {
        if (window.getComputedStyle(w).display !== 'none') {
            w.style.setProperty('display', 'contents', 'important');
        }
    });
}

// --- REMINDERS & DUE (aggregate the existing alert bubbles, into the feed) ---
// Each reminder backs a live outstanding task, read out of the alert bubble the
// app already computes. Dismissing hides it for TODAY only; if it's still due
// tomorrow the bubble is still showing and it re-appears.
// One row per built-out deadline/reminder tool. `action` is the same "open the
// tool" logic the old alert bubble ran on click — the hub + dashboard cards now
// carry it so clicking a reminder jumps straight to its tool.
function _samReminderCfg() {
    return [
        { key: 'variance', id: 'varianceAlertBubble', text: 'varianceAlertBubbleText', title: 'Variance Replies Due', urgency: 2, due: 'Due', cls: 'sam-due-red', action: "window.location.href='workspace.html#vreplies'" },
        // A DM has no store-scoped claims tool — send them to the all-stores
        // oversight view instead, which is where they can actually act.
        { key: 'claims', id: 'claimAlertBubble', text: 'claimAlertBubbleText', title: 'Insurance Claims Aging', urgency: 2, due: 'Aging', cls: 'sam-due-red',
          action: (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim() === 'district manager'
              ? "openClaimsOversight()"
              : "openClaimsModal(); switchClaimsTab('view')" },
        { key: 'recycle', id: 'recycleAlertBubble', text: 'recycleAlertBubbleText', title: 'Recycle Review', urgency: 1, due: 'Review', cls: 'sam-due-amber', action: "toggleRecycleInventory(); switchRecycleTab('view')" },
        { key: 'aging', id: 'agingAlertBubble', text: 'agingAlertBubbleText', title: 'Aging Inventory Review', urgency: 1, due: 'Review', cls: 'sam-due-amber', action: "window.location.href='workspace.html#aging'" }
    ];
}

function _samDismKey() {
    const u = (sessionStorage.getItem('speeksUserName') || 'anon').trim().toLowerCase();
    const day = new Date().toLocaleDateString('en-US', { timeZone: 'America/Chicago' });
    return 'samRemDismissed_' + u + '_' + day;
}
// Dismissals are stored as { key: snippetAtSnoozeTime }, NOT a bare list of keys.
// A snooze must quiet the reminder AS IT READ WHEN SNOOZED — with a plain key list
// it also swallowed every later update that same day, so a DM could send a fresh
// claim reminder and the manager's feed would silently drop it until tomorrow.
// Comparing against the snippet means new content (new count, new sender) resurfaces.
function _samGetDismissedRem() {
    try {
        const raw = JSON.parse(localStorage.getItem(_samDismKey()) || '{}');
        // Legacy array format carried no signature, so it can only mean "hide all
        // day" — the exact bug above. Drop it rather than honouring it.
        return (raw && typeof raw === 'object' && !Array.isArray(raw)) ? raw : {};
    } catch (_) { return {}; }
}
function _samSetDismissedRem(map) { try { localStorage.setItem(_samDismKey(), JSON.stringify(map || {})); } catch (_) {} }

function _samGatherReminders() {
    const dismissed = _samGetDismissedRem();
    const out = [];
    _samReminderCfg().forEach(c => {
        const el = document.getElementById(c.id);
        if (!el) return;
        // The alert elements are position:fixed, and offsetParent is ALWAYS null
        // for fixed elements — the old `offsetParent !== null` test could never
        // pass, so no reminder ever reached the feed. Computed display is the
        // real signal: the check functions flip it to flex when a reminder is
        // live and back to none when it clears.
        if (window.getComputedStyle(el).display === 'none') return;
        const t = document.getElementById(c.text);
        let sub = '';
        if (t) {
            // A bubble can author its own one-line feed summary via data-summary.
            // Preferred, because scraping the bubble is lossy: the bubble repeats its
            // title (already the row title here), and long instructional text gets
            // truncated to nothing useful. The bubble keeps the full copy for the
            // place the user actually acts.
            if (t.dataset && t.dataset.summary) {
                sub = t.dataset.summary.replace(/\s+/g, ' ').trim();
            } else {
                // Fallback scrape. Drop the "Open …" CTA button, and join block
                // children with a space — textContent runs them together, which
                // produced "…review them.That includes…".
                const clone = t.cloneNode(true);
                clone.querySelectorAll('button').forEach(b => b.remove());
                const blocks = Array.from(clone.children)
                    .map(el => (el.textContent || '').trim())
                    .filter(Boolean);
                sub = (blocks.length ? blocks.join(' ') : (clone.textContent || ''))
                    .replace(/\s+/g, ' ').trim();
            }
        }
        if (sub.length > 160) sub = sub.slice(0, 158) + '…'; // 3-line clamp in CSS shows the rest
        // Snoozed — but only while it's still the SAME reminder. A bubble may supply
        // an explicit identity via data-sig (see _renderClaimBubble); otherwise the
        // displayed text is the identity, so any change in wording — a moved count,
        // a new sender — counts as new information and breaks through the snooze
        // rather than staying buried until tomorrow.
        const sig = (t && t.dataset && t.dataset.sig) ? t.dataset.sig : sub;
        if (Object.prototype.hasOwnProperty.call(dismissed, c.key) && dismissed[c.key] === sig) return;
        // For an MSM: if this alert covers exactly ONE store (the bubble stamps the
        // covered stores on data-stores), clicking it opens that store's tool even
        // while he's on the other store's dashboard — without switching dashboards.
        // A both-store alert stamps two, so nothing is set and the tool opens on the
        // active dashboard store (the user's chosen rule).
        let action = c.action || '';
        if (action && t && t.dataset && t.dataset.stores) {
            const stores = t.dataset.stores.split(',').map(s => s.trim().toUpperCase()).filter(Boolean);
            const roleLc = (sessionStorage.getItem('speeksUserRole') || '').toLowerCase().trim();
            let target = '';
            // MSM: only route a single-store alert; a both-store one opens the active
            // dashboard store. DM: land on the first store that needs review (the
            // bubble lists them attention-first).
            if (isMultiStoreManager()) { if (stores.length === 1) target = stores[0]; }
            else if (roleLc === 'district manager' && stores.length) target = stores[0];
            if (target) action = `sessionStorage.setItem('speeksMsmToolStore','${target}');` + action;
        }
        out.push({
            type: 'rem', key: c.key, sig, title: c.title, snippet: sub || 'Needs your attention',
            due: c.due, dueCls: c.cls, urgency: c.urgency, read: false, dateMs: Date.now() + c.urgency,
            action
        });
    });
    return out;
}

// --- INIT ---
/* =========================================================
   REALTIME NOTIFICATIONS  (broadcast-as-ping)
   The notification tables are RLS-locked with no policies, so
   postgres_changes would deliver nothing to the anon client
   (and adding SELECT policies would expose the tables — the app
   deliberately routes every read through the edge fns). Instead
   each tool's edge fn broadcasts a tiny "changed" ping after a
   successful write; we re-run that tool's existing check*()
   function, which re-fetches through the trusted fn. No table
   data ever travels over realtime. The 10-min polls stay as a
   safety net (to be slowed once every tool broadcasts).
   ========================================================= */
const _RT_CHANNEL = 'speeks-notify';
let _rtClient = null, _rtChannel = null, _rtLoading = null, _rtStarted = false;
let _rtLastStatus = 'not started', _rtLastPing = null, _rtPingCount = 0, _rtEverConnected = false;
const _rtDebounce = {}; // tool -> timer, so a burst of pings collapses to one re-check
// Console check: _rtDebug() → is the socket subscribed, and what was the last ping?
window._rtDebug = () => ({ started: _rtStarted, clientLoaded: !!_rtClient, status: _rtLastStatus, pings: _rtPingCount, lastPing: _rtLastPing });

// Registry: ping name → the check/loader function(s) to re-run for that tool,
// in order. THIS is the single place to wire a notification into realtime — add
// a line here and have that tool's edge fn broadcast the same name (see
// broadcastChange in the edge fns). Subscribe, debounce, reconnect-sweep and the
// feed repaint are all automatic, so a future notification is a one-line add.
// Functions are looked up on window (top-level declarations) and may be absent
// on a given page — missing/failing ones are skipped.
const _RT_TOOL_CHECKS = {
    aging:         ['checkAgingInvReminders', 'checkAgingInvDmReminders', '_agRefreshStorePopup'],
    claims:        ['checkClaimReminders', 'checkAgingClaims', 'checkAgingClaimsDM'],
    recycle:       ['checkRecycleReminders'],
    variance:      ['checkVarianceReminders', 'checkVarianceDmReminders'],
    comments:      ['fetchAndDisplayStoreComment'],
    announcements: ['loadCMS'],
    patch:         ['loadPatchNotes'],
};

// Re-run a tool's checks (sequentially, so any UI-refresh step runs after its
// fetch), then repaint the feed. Wrapped so nothing can kill the channel.
async function _rtRunCheck(tool) {
    try {
        const fns = _RT_TOOL_CHECKS[tool] || [];
        for (const name of fns) {
            try { if (typeof window[name] === 'function') await window[name](); }
            catch (_) { /* skip this one, keep going */ }
        }
        if (typeof renderActionFeed === 'function') renderActionFeed();
    } catch (e) { /* keep the channel alive */ }
}
// Re-check every tool on RECONNECT so a change made while the socket was down
// still surfaces. (The first connect is skipped — the login sweep already ran.)
function _rtSweepAll() { Object.keys(_RT_TOOL_CHECKS).forEach(_rtRunCheck); }

function _rtHandlePing(payload) {
    const tool = payload && payload.tool;
    if (!tool) return;
    _rtLastPing = payload; _rtPingCount++;
    clearTimeout(_rtDebounce[tool]);
    _rtDebounce[tool] = setTimeout(() => _rtRunCheck(tool), 400);
}

// Lazy-load supabase-js from CDN (mirrors the XLSX loader), then make one client.
function _rtEnsureClient() {
    if (_rtClient) return Promise.resolve(_rtClient);
    if (_rtLoading) return _rtLoading;
    const ready = () => (window.supabase && typeof window.supabase.createClient === 'function');
    const srcs = [
        'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2',
        'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.js',
        'https://unpkg.com/@supabase/supabase-js@2',
    ];
    _rtLoading = new Promise((resolve, reject) => {
        if (ready()) return resolve(window.supabase);
        const tryNext = i => {
            if (i >= srcs.length) { _rtLoading = null; return reject(new Error('supabase-js unavailable')); }
            const s = document.createElement('script');
            s.src = srcs[i];
            s.onload = () => ready() ? resolve(window.supabase) : tryNext(i + 1);
            s.onerror = () => { s.remove(); tryNext(i + 1); };
            document.head.appendChild(s);
        };
        tryNext(0);
    }).then(sb => {
        // NOTE: don't reassign window.supabase — it holds the library namespace.
        _rtClient = sb.createClient(_SUPABASE_URL, _SUPABASE_ANON_KEY);
        return _rtClient;
    });
    return _rtLoading;
}

// Subscribe once per page load (feed users only — samInit gates it). On failure
// we fall back to the polls, which are still running.
function initRealtimeNotifications() {
    if (_rtStarted) return;
    _rtStarted = true;
    _rtEnsureClient().then(client => {
        _rtChannel = client.channel(_RT_CHANNEL);
        _rtChannel.on('broadcast', { event: 'changed' }, msg => _rtHandlePing(msg && msg.payload));
        _rtChannel.subscribe(status => {
            _rtLastStatus = status;
            if (status === 'SUBSCRIBED') {
                if (_rtEverConnected) _rtSweepAll(); // reconnect → catch up on missed changes
                _rtEverConnected = true;             // first connect: the login sweep already ran
            }
        });
    }).catch(() => {
        _rtStarted = false; // let a later samInit retry; polling covers us meanwhile
    });
}

function samInit() {
    const menu = document.getElementById('speeksActionMenu');
    if (!menu) return;
    // Only users who actually see the deck lose the old ticker + bell (they're
    // re-homed here). Everyone else — employees, other pages — keeps them.
    const visible = window.getComputedStyle(menu).display !== 'none';
    document.body.classList.toggle('sam-active', visible);
    if (typeof _syncLayout === 'function') _syncLayout();
    if (!visible) return;
    // Roles with none of the action items (CEO / TOM) would get an empty rail
    // card — drop the rail and let the feed run full width instead.
    const rail = menu.querySelector('.sam-rail');
    if (rail) {
        const anyItem = Array.from(rail.querySelectorAll('.sam-mini'))
            .some(b => window.getComputedStyle(b).display !== 'none');
        menu.classList.toggle('sam-norail', !anyItem);
    }
    renderActionFeed();
    samRefreshListing();
    samCleanHotbar();
    if (window._samInited) return;
    window._samInited = true;
    // The alert bubbles and listing widget populate asynchronously and from many
    // code paths; a light interval keeps the deck in sync without wiring every
    // one. Cheap DOM reads only.
    setInterval(() => { renderActionFeed(); samRefreshListing(); }, 5000);
    // Realtime: push notifications the moment a write lands, instead of waiting
    // for the tool's 10-min poll. Feed users only (we're past the visible gate).
    initRealtimeNotifications();
}


/* =========================================================
   SPEEKS FEED HUB  (#notifDropdown) — unified filterable reader.
   Announcements are pre-built in loadCMS (window._hubAnnItems) with
   their reactions / receipts / docs preserved; store notes, deadlines
   and patch notes are built here. renderHubFeed() merges + filters.
   ========================================================= */

// Pull a clean title + formatted body + priority flag out of an announcement.
// item.text = optional "HIGH PRIORITY" span + <strong>title</strong> + body html.
function _hubParseAnn(item) {
    const tmp = document.createElement('div');
    tmp.innerHTML = item.text || '';
    let priority = !!item.high_priority;
    tmp.querySelectorAll('span').forEach(s => { if (/HIGH PRIORITY/i.test(s.textContent || '')) { priority = true; s.remove(); } });
    let title = '';
    const strong = tmp.querySelector('strong');
    if (strong) { title = (strong.textContent || '').trim(); strong.remove(); }
    let bodyHtml = tmp.innerHTML.replace(/^(\s*<br\s*\/?>\s*)+/i, '').trim();
    if (!title) title = ((tmp.textContent || '').trim().slice(0, 80)) || 'Announcement';
    return { title, bodyHtml, priority };
}

function _hubNoteItem(n) {
    const d = n.date ? new Date(n.date) : null;
    const dateMs = (d && !isNaN(d.getTime())) ? d.getTime() : Date.now();
    const tmp = document.createElement('div'); tmp.innerHTML = n.text || '';
    const body = (tmp.textContent || '').replace(/\s+/g, ' ').trim();
    const store = String(n.store || '').toUpperCase();
    const metaR = (d && !isNaN(d.getTime())) ? _samFmtDate(d) : '';
    const isRead = !!n.read;   // read store notes stay in the hub, just dimmed
    const kindLabel = isRead ? 'Read · Store note' : 'Store note';
    // Store comments live in the hub permanently now (they no longer expire off the
    // dashboard), so an unread one needs a way to be cleared FROM the hub — without
    // this, old comments piled up in the Unread filter with no affordance.
    const markReadBtn = (!isRead && n.id)
        ? `<div class="hub-foot"><button class="hub-markread" onclick="hubMarkNoteRead('${escapeHtml(String(n.id))}')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 6 9 17l-5-5"></path></svg>Mark as read</button></div>`
        : '';
    const html = `
        <div class="hub-item t-note${isRead ? ' read' : ''}" data-t="note" data-hub-id="note-${escapeHtml(String(n.id || ''))}">
            <div class="hub-row">
                <span class="hub-tico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg></span>
                <div class="hub-col">
                    <div class="hub-item-top"><span class="hub-item-title">Message from ${escapeHtml(n.author || 'your team')}</span><span class="hub-meta-r">${metaR}</span></div>
                    <div class="hub-kind-meta"><span class="hub-kind">${kindLabel}</span>${store ? ' · ' + escapeHtml(store) : ''}</div>
                    <div class="hub-item-body">${escapeHtml(body)}</div>
                    ${markReadBtn}
                </div>
            </div>
        </div>`;
    return { kind: 'note', archived: false, read: isRead, priority: false, dateMs, html };
}

// Mark a store comment read from the hub (the dashboard feed's ✕ does the same via
// samDismissItem). Local read first so it survives a re-fetch, mirror both feeds,
// then persist server-side so it stays read across devices/sign-outs.
function hubMarkNoteRead(id) {
    if (!id) return;
    const key = String(id);
    _addLocalNoteRead(key);
    if (Array.isArray(window._hubStoreNotes)) window._hubStoreNotes.forEach(n => { if (String(n.id) === key) n.read = true; });
    if (Array.isArray(window._samStoreNotes)) window._samStoreNotes = window._samStoreNotes.filter(n => String(n.id) !== key);
    try { postWrite(STORE_COMMENT_URL, { type: 'mark_read', commentIds: [key], user: sessionStorage.getItem('speeksUserName') }).catch(() => {}); } catch (_) {}
    try { if (typeof renderHubFeed === 'function') renderHubFeed(); } catch (_) {}
    try { if (typeof renderActionFeed === 'function') renderActionFeed(); } catch (_) {}
    if (typeof updateMainBadge === 'function') updateMainBadge();
}

function _hubDueItem(r) {
    const amber = r.dueCls === 'sam-due-amber';
    // Clicking the card closes the hub and runs the tool's own open-action.
    const clickAttr = r.action ? ` onclick="closeAllModals(); ${r.action}" style="cursor:pointer"` : '';
    const openHint = r.action ? '<span class="hub-open-hint">Open →</span>' : '';
    const html = `
        <div class="hub-item t-due${amber ? ' amber' : ''}" data-t="due"${clickAttr}>
            <div class="hub-row">
                <span class="hub-tico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="9"></circle><path d="M12 7v5l3 2"></path></svg></span>
                <div class="hub-col">
                    <div class="hub-item-top"><span class="hub-item-title">${escapeHtml(r.title)}</span><span class="hub-due-badge ${amber ? 'hub-due-amber' : 'hub-due-red'}">${escapeHtml(r.due)}</span></div>
                    <div class="hub-kind-meta"><span class="hub-kind">Deadline</span> · ${escapeHtml(r.snippet)}${openHint}</div>
                </div>
            </div>
        </div>`;
    return { kind: 'due', archived: false, priority: false, dateMs: Date.now() + (r.urgency || 0), html };
}

function _hubPatchItems() {
    const data = window._hubPatchData;
    if (!data || !data.entries || !data.entries.length) return [];
    const groups = buildPatchGroups(data.entries);
    const catOrder = ['New Features', 'Improvements', 'Bug Fixes'];
    const catDot = { 'New Features': 'pd-feat', 'Improvements': 'pd-imp', 'Bug Fixes': 'pd-fix' };
    const toLis = summary => (summary || '').split('\n').map(l => l.replace(/^[-•]\s*/, '').trim()).filter(Boolean).map(l => `<li>${escapeHtml(l)}</li>`).join('');
    // Only the newest group counts as unread, and only while the user's unseen
    // flag is set — otherwise every historical version would sit in "Unread".
    const _pu = sessionStorage.getItem('speeksUserName');
    const _pcu = _pu ? String(_pu).trim().toLowerCase() : null;
    const patchUnseen = !!(_pcu && localStorage.getItem('speeksUnseenPatchNotes_' + _pcu) === 'true');
    return groups.map((g, i) => {
        const sections = catOrder.map(cat => {
            const items = g.items.filter(it => it.category === cat);
            if (!items.length) return '';
            return `<div class="hub-patch-sec"><div class="hub-psec-title"><span class="hub-pdot ${catDot[cat]}"></span>${cat}</div><ul>${items.map(it => toLis(it.summary)).join('')}</ul></div>`;
        }).join('');
        const d = (typeof parsePatchDate === 'function') ? parsePatchDate(g.date) : null;
        const dateMs = (d && !isNaN(d.getTime())) ? d.getTime() : (Date.now() - i);
        // Only the newest unread version gets the button — older groups are history.
        const isUnread = patchUnseen && i === 0;
        const markReadBtn = isUnread
            ? `<div class="hub-foot"><button class="hub-markread" onclick="hubMarkPatchRead()"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 6 9 17l-5-5"></path></svg>Mark as read</button></div>`
            : '';
        const html = `
            <div class="hub-item t-patch hub-patch${isUnread ? '' : ' read'}" data-t="patch" data-hub-id="patch-${escapeHtml(g.title)}">
                <div class="hub-row">
                    <span class="hub-tico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2 2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path></svg></span>
                    <div class="hub-col">
                        <div class="hub-patch-head"><span class="hub-kind">Patch Notes</span><span class="hub-patch-ver">${escapeHtml(g.title)}</span>${i === 0 ? '<span class="hub-latest">Latest</span>' : ''}<span class="hub-meta-r">${formatPatchDate(g.date)}</span></div>
                        ${sections}
                        ${markReadBtn}
                    </div>
                </div>
            </div>`;
        return { kind: 'patch', archived: false, priority: false, read: !(patchUnseen && i === 0), dateMs, html };
    });
}

function renderHubFeed() {
    const feed = document.getElementById('hubFeed');
    if (!feed) return;
    const filter = window._hubFilter || 'all';

    let items = [];
    (window._hubAnnItems || []).forEach(a => items.push(a));
    // Hub keeps the full store-comment history (they no longer expire at midnight);
    // the dashboard feed still uses the today-only _samStoreNotes briefing.
    (window._hubStoreNotes || window._samStoreNotes || []).forEach(n => { try { items.push(_hubNoteItem(n)); } catch (_) {} });
    try { (typeof _samGatherReminders === 'function' ? _samGatherReminders() : []).forEach(r => items.push(_hubDueItem(r))); } catch (_) {}
    try { _hubPatchItems().forEach(p => items.push(p)); } catch (_) {}

    // "All" shows everything readable — unread AND read announcements — hiding only
    // onboarding-cutoff/stale items. "Archived" is the history view (read + hidden).
    // Reading an announcement dims it in the hub but does NOT drop it from "All".
    // "Unread" = still needs your attention: unread announcements and comments,
    // plus outstanding deadlines (which are unread by nature). Patch note groups
    // carry their own read flag, so only genuinely-new ones qualify.
    const shown = items.filter(it =>
        filter === 'all' ? (!it.hidden && it.kind !== 'due')
        : filter === 'unread' ? (!it.read && !it.hidden)
        : filter === 'arch' ? (it.read || it.hidden)
        : it.kind === filter
    ).sort((a, b) => (b.dateMs || 0) - (a.dateMs || 0));

    const labels = { all: 'updates', unread: 'unread', ann: 'announcements', note: 'comments', due: 'deadlines', patch: 'patch notes', arch: 'archived' };
    const countEl = document.getElementById('hubCount');
    if (countEl) countEl.textContent = `${shown.length} ${labels[filter] || 'updates'}`;

    feed.innerHTML = shown.length ? shown.map(it => it.html).join('') : '<div class="hub-empty">Nothing here right now.</div>';
    // A rebuild throws away the card a pending jump was scrolling to (and can add
    // rows above it), so re-anchor. No-ops unless a jump is actually in flight.
    _hubScrollToPending();
}

function setHubFilter(v) { window._hubFilter = v; renderHubFeed(); }

// Mark one announcement read from the hub, then rebuild (loadCMS re-derives read
// state + re-renders the hub and the Action Menu feed).
function hubMarkRead(rowId) {
    if (typeof _samMarkAnnRead === 'function') _samMarkAnnRead(rowId);
    if (typeof loadCMS === 'function') loadCMS();
}

// Open the hub straight to the patch-notes filter (from the main feed's row).
function openHubToPatch() {
    window._hubFilter = 'patch';
    const sel = document.getElementById('hubFilter'); if (sel) sel.value = 'patch';
    const modal = document.getElementById('notifDropdown');
    if (modal && !modal.classList.contains('show')) toggleModal('notifDropdown', 'notifBadge');
    renderHubFeed();
    if (typeof loadPatchNotes === 'function') loadPatchNotes();
}

// Record the latest patch version as seen (clears the "new patch" row + badge).

